import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Header } from '@/components/ui/custom/Header';
import { BottomNav } from '@/components/ui/custom/BottomNav';
import { HomeView } from '@/views/customer/HomeView';
import { CartView } from '@/views/customer/CartView';
import { ProductView } from '@/views/customer/ProductView';
import { CheckoutView } from '@/views/customer/CheckoutView';
import { NotificationsView } from './views/customer/NotificationsView';
import { OrderSuccessView } from './views/customer/OrderSuccessView';
import { ProfileView } from '@/views/customer/ProfileView';
import { AdminDashboardView as AdminDashboard } from '@/views/admin/AdminDashboardView';
import { AdminProductsView as AdminProducts } from '@/views/admin/AdminProductsView';
import { AdminProductFormView as AdminProductForm } from '@/views/admin/AdminProductFormView';
import { AdminOrdersView as AdminOrders } from '@/views/admin/AdminOrdersView';
import { AdminCouponsView as AdminCoupons } from '@/views/admin/AdminCouponsView';
import { cn } from '@/lib/utils';
import { AdminBannersView as AdminBanners } from '@/views/admin/AdminBannersView';
import { AdminSettingsView as AdminSettings } from '@/views/admin/AdminSettingsView';
import { AdminReviewsView as AdminReviews } from '@/views/admin/AdminReviewsView';
import { AdminQAView as AdminQA } from '@/views/admin/AdminQAView';
import { AdminAnalyticsView as AdminAnalytics } from '@/views/admin/AdminAnalyticsView';
import { AdminCustomersView as AdminCustomers } from '@/views/admin/AdminCustomersView';
import { AdminUserDetailView as AdminUserDetail } from '@/views/admin/AdminUserDetailView';
import { AdminPushView as AdminPush } from '@/views/admin/AdminPushView';
import { AuthView } from '@/views/shared/AuthView';
import { AdminLoginView as AdminLogin } from '@/views/admin/AdminLoginView';
import { AccountSettingsView as AccountSettings } from '@/views/customer/AccountSettingsView';
import { OrdersView } from '@/views/customer/OrdersView';
import { OrderDetailsView } from '@/views/customer/OrderDetailsView';
import { SearchView } from '@/views/customer/SearchView';
import { RecentlyViewedView } from '@/views/customer/RecentlyViewedView';
import { CompareView } from '@/views/customer/CompareView';
import { ReferralView } from '@/views/customer/ReferralView';
import { FavoritesView } from '@/views/customer/FavoritesView';
import { AdminLayout } from '@/components/layouts/AdminLayout';

declare global {
  interface Window {
    removeSilentGuardianLoader?: () => void;
  }
}

import { DebugPanel } from '@/components/debug/DebugPanel';
import { useAuth } from '@/contexts/AuthContext';
import { useProducts } from '@/hooks/useProducts';

import { useFavorites } from '@/hooks/useFavorites';
import { useRecentlyViewed } from '@/hooks/useRecentlyViewed';
import { useAppBadge } from '@/hooks/useAppBadge';
import { NotificationProvider } from '@/contexts/NotificationContext';
import { useRealtimeUpdate } from '@/hooks/useRealtimeUpdate';
import { StoreProvider } from '@/contexts/StoreContext';
import { CartProvider } from '@/contexts/CartContext';
import { useCart } from '@/hooks/useCart';
import { HelmetProvider } from 'react-helmet-async';
import { haptic } from '@/utils/haptic';
import type { View, Product } from '@/types';

export default function App() {
  // Global check for session-based splash skip
  useEffect(() => {
    if (typeof window !== 'undefined' && sessionStorage.getItem('splash_shown')) {
      const loader = document.getElementById('silent-guardian-loader');
      if (loader) loader.remove();
    }
  }, []);

  return (
    <HelmetProvider>
      <StoreProvider>
        <NotificationProvider>
          <CartProvider>
            <AppContent />
          </CartProvider>
        </NotificationProvider>
      </StoreProvider>
    </HelmetProvider>
  );
}

const getProductById = (products: Product[], id: string) => products.find(p => p.id === id);

const AppContent = () => {
  const { isAdmin, loading: authLoading } = useAuth();
  const { products, loading: productsLoading } = useProducts();
  const { cart, addToCart, getCartCount, getCartTotal, clearCart, updateQuantity, removeFromCart } = useCart();
  const { favorites, toggleFavorite } = useFavorites();
  const { addToRecentlyViewed, getRecentlyViewedProducts } = useRecentlyViewed();
  const recentlyViewedProducts = getRecentlyViewedProducts(products);

  const [currentView, setCurrentView] = useState<View>('home');
  const [selectedProductId, setSelectedProductId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // Experimental Hooks (Disabled for cart bug isolation - Round 2)
  /*
  useTemporalFold(cart);
  useNeuralInjection();
  */

  const { setBadge, clearBadge } = useAppBadge();

  // Scroll tracking for animations
  const [scrollProgress, setScrollProgress] = useState(0);
  useEffect(() => {
    const handleScroll = () => {
      const progress = window.scrollY / (document.documentElement.scrollHeight - window.innerHeight);
      setScrollProgress(progress);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Sync view with URL on initial load and back/forward bottons
  useEffect(() => {
    const syncWithUrl = () => {
      const path = window.location.pathname.slice(1) || 'home';
      // Basic validation of view name
      const validViews: View[] = [
        'home', 'cart', 'product-detail', 'checkout', 'profile', 'admin', 'search', 'auth', 'login', 'favorites',
        'notifications', 'order-success', 'orders', 'order-details', 'recently-viewed', 'compare', 'referral', 'account-settings',
        'admin-dashboard', 'admin-products', 'admin-product-form', 'admin-orders', 'admin-coupons', 'admin-banners',
        'admin-settings', 'admin-reviews', 'admin-qa', 'admin-analytics', 'admin-customers', 'admin-user-detail', 'admin-push'
      ];
      if (validViews.includes(path as View)) {
        setCurrentView(path as View);
      }
    };

    syncWithUrl();
    window.addEventListener('popstate', syncWithUrl);
    return () => window.removeEventListener('popstate', syncWithUrl);
  }, []);


  // Sync PWA Badge with cart count
  useEffect(() => {
    const count = getCartCount();
    if (count > 0) {
      setBadge(count);
    } else {
      clearBadge();
    }
  }, [cart, getCartCount, setBadge, clearBadge]);

  // Real-time updates for deployment
  const handleUpdate = useCallback(() => {
    // Force version re-check
    console.log('[RealtimeUpdate] Update detected. Auto-loading service worker update.');
    window.location.reload();
  }, []);

  useRealtimeUpdate(handleUpdate);

  // Force loader removal once data is ready
  // Force loader removal once data is ready or after a safe timeout
  useEffect(() => {
    const removeLoader = () => {
      if (window.removeSilentGuardianLoader) {
        window.removeSilentGuardianLoader();
      }
      // Fallback: manually find and remove if the global function fails
      const loader = document.getElementById('silent-guardian-loader');
      if (loader) loader.remove();
    };

    if (!authLoading && !productsLoading) {
      removeLoader();
      // Mark splash as shown for the session to prevent it on every nav
      if (typeof window !== 'undefined') {
        sessionStorage.setItem('splash_shown', 'true');
      }
    }

    // Absolute safety fallback (2s max loading for better UX)
    const safetyTimer = setTimeout(removeLoader, 2000);
    return () => clearTimeout(safetyTimer);
  }, [authLoading, productsLoading]);

  const handleProductClick = (productId: string) => {
    setSelectedProductId(productId);
    setCurrentView('product-detail');
    addToRecentlyViewed(productId);
    haptic.light();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleNavigate = (view: View, id?: string) => {
    if (id) setSelectedProductId(id);
    setCurrentView(view);

    // Sync URL without full reload
    const path = view === 'home' ? '/' : `/${view}`;
    if (window.location.pathname !== path) {
      window.history.pushState({ view, id }, '', path);
    }

    window.scrollTo(0, 0);
  };

  const handleBack = () => {
    haptic.light();
    // If we're on a sub-view, go back to a logical parent or home
    if (currentView === 'product-detail' || currentView === 'search' || currentView === 'favorites') {
      handleNavigate('home');
      return;
    }

    if (currentView === 'order-details') {
      handleNavigate('orders');
      return;
    }

    if (currentView === 'referral') {
      handleNavigate('profile');
      return;
    }

    // Default to browser back, but fallback to home if it tries to leave the site
    if (window.history.length > 1) {
      window.history.back();
    } else {
      handleNavigate('home');
    }
  };

  const handleToggleFavorite = (product: Product) => {
    toggleFavorite(product);
  };

  const handleAddToCart = (product: Product, quantity: number = 1, variantId?: string) => {
    addToCart(product, quantity, variantId);
    haptic.success();
  };

  const handleQuickBuy = (product: Product, variantId?: string) => {
    addToCart(product, 1, variantId);
    // Force sync with URL and state
    setCurrentView('checkout');
    const path = '/checkout';
    if (window.location.pathname !== path) {
      window.history.pushState({ view: 'checkout' }, '', path);
    }
    haptic.success();
  };

  const renderView = () => {
    if (authLoading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-zinc-900 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-muted-foreground animate-pulse font-medium">Carregando marketplace...</p>
        </div>
      );
    }

    switch (currentView) {
      case 'home':
        return (
          <HomeView
            products={products}
            favorites={favorites.map(p => p.id)}
            recentlyViewedProducts={recentlyViewedProducts}
            onToggleFavorite={handleToggleFavorite}
            onProductClick={handleProductClick}
            onNavigate={handleNavigate}
            searchQuery={searchQuery}
            onAddToCart={handleAddToCart}
            onQuickBuy={handleQuickBuy}
          />
        );
      case 'cart':
        return (
          <CartView
            cart={cart}
            onUpdateQuantity={updateQuantity}
            onRemove={removeFromCart}
            onNavigate={handleNavigate}
          />
        );
      case 'favorites':
        return (
          <FavoritesView
            favorites={favorites}
            onToggleFavorite={handleToggleFavorite}
            onNavigate={handleNavigate}
            onProductClick={handleProductClick}
          />
        );
      case 'product-detail': {
        const product = selectedProductId ? getProductById(products, selectedProductId) : null;
        if (!product) {
          setCurrentView('home');
          return null;
        }
        return (
          <ProductView
            product={product}
            isFavorite={favorites.some(f => f.id === product.id)}
            onToggleFavorite={() => handleToggleFavorite(product)}
            onBack={() => setCurrentView('home')}
            onAddToCart={(q, vId) => handleAddToCart(product as Product, q, vId)}
          />
        );
      }
      case 'checkout':
        return (
          <CheckoutView
            cart={cart}
            subtotal={getCartTotal()}
            shipping={0}
            total={getCartTotal()}
            onClearCart={clearCart}
            onNavigate={handleNavigate}
          />
        );
      case 'profile':
        return (
          <ProfileView
            onNavigate={handleNavigate}
            onProductClick={handleProductClick}
          />
        );
      case 'notifications':
        return (
          <NotificationsView
            onBack={() => setCurrentView('home')}
          />
        );
      case 'order-success':
        return (
          <OrderSuccessView
            onNavigate={handleNavigate}
          />
        );
      case 'login':
      case 'auth':
        return (
          <AuthView
            onNavigate={handleNavigate}
            onSuccess={() => handleNavigate('profile')}
          />
        );
      case 'admin':
      case 'admin-dashboard':
      case 'admin-products':
      case 'admin-product-form':
      case 'admin-orders':
      case 'admin-coupons':
      case 'admin-banners':
      case 'admin-settings':
      case 'admin-reviews':
      case 'admin-qa':
      case 'admin-analytics':
      case 'admin-customers':
      case 'admin-user-detail':
      case 'admin-push':
        if (authLoading) return <AdminRouteLoading />;
        if (!isAdmin) return <AdminAccessDenied onNavigate={handleNavigate} />;

        return (
          <AdminLayout currentView={currentView} onNavigate={handleNavigate}>
            {currentView === 'admin-dashboard' || currentView === 'admin' ? (
              <AdminDashboard onNavigate={handleNavigate} />
            ) : currentView === 'admin-products' ? (
              <AdminProducts onNavigate={handleNavigate} />
            ) : currentView === 'admin-product-form' ? (
              <AdminProductForm onNavigate={handleNavigate} />
            ) : currentView === 'admin-orders' ? (
              <AdminOrders onNavigate={handleNavigate} />
            ) : currentView === 'admin-coupons' ? (
              <AdminCoupons onNavigate={handleNavigate} />
            ) : currentView === 'admin-banners' ? (
              <AdminBanners onNavigate={handleNavigate} />
            ) : currentView === 'admin-settings' ? (
              <AdminSettings onNavigate={handleNavigate} />
            ) : currentView === 'admin-reviews' ? (
              <AdminReviews onNavigate={handleNavigate} />
            ) : currentView === 'admin-qa' ? (
              <AdminQA onNavigate={handleNavigate} />
            ) : currentView === 'admin-analytics' ? (
              <AdminAnalytics onNavigate={handleNavigate} />
            ) : currentView === 'admin-customers' ? (
              <AdminCustomers onNavigate={handleNavigate} />
            ) : currentView === 'admin-user-detail' ? (
              <AdminUserDetail
                userId={selectedProductId || ''}
                onBack={() => handleNavigate('admin-customers')}
                onNavigate={handleNavigate}
              />
            ) : (
              <AdminPush onNavigate={handleNavigate} />
            )}
          </AdminLayout>
        );

      case 'admin-login':
        return (
          <AdminLogin
            onLogin={() => handleNavigate('admin')}
            onNavigate={handleNavigate}
          />
        );

      case 'account-settings':
        return <AccountSettings onNavigate={handleNavigate} />;

      case 'orders':
        return <OrdersView onNavigate={handleNavigate} />;

      case 'order-details':
        return (
          <OrderDetailsView
            orderId={selectedProductId || ''}
            onBack={() => handleNavigate('orders')}
            onNavigate={handleNavigate}
          />
        );

      case 'favorites':
        return (
          <FavoritesView
            favorites={favorites}
            onToggleFavorite={handleToggleFavorite}
            onProductClick={handleProductClick}
            onNavigate={handleNavigate}
          />
        );

      case 'recently-viewed':
        return (
          <RecentlyViewedView
            products={recentlyViewedProducts}
            favorites={favorites.map(f => f.id)}
            onToggleFavorite={handleToggleFavorite}
            onProductClick={handleProductClick}
            onNavigate={handleNavigate}
            onClear={() => { }} // To be implemented if needed
          />
        );

      case 'compare':
        return (
          <CompareView
            products={[]} // To be implemented with comparison hook
            onNavigate={handleNavigate}
            onRemoveProduct={() => { }}
            onClearAll={() => { }}
            onProductClick={handleProductClick}
          />
        );

      case 'search':
        return (
          <SearchView
            onNavigate={handleNavigate}
            initialQuery={searchQuery}
            onBack={() => handleNavigate('home')}
          />
        );

      case 'referral':
        return (
          <ReferralView
            onBack={() => handleNavigate('profile')}
          />
        );

      default:
        return (
          <HomeView
            products={products}
            favorites={favorites.map(p => p.id)}
            recentlyViewedProducts={recentlyViewedProducts}
            onToggleFavorite={handleToggleFavorite}
            onProductClick={handleProductClick}
            onNavigate={handleNavigate}
            searchQuery={searchQuery}
            onAddToCart={handleAddToCart}
            onQuickBuy={handleQuickBuy}
          />
        );
    }
  };

  return (
    <div className="min-h-screen pb-32 bg-gray-50/30">
      {!currentView.startsWith('admin') && (
        <Header
          onNavigate={handleNavigate}
          showBackButton={currentView !== 'home'}
          onBack={handleBack}
          onOpenNotifications={() => handleNavigate('notifications')}
          hideSearch={false}
          externalScrollProgress={scrollProgress}
          searchQuery={searchQuery}
          onSearch={setSearchQuery}
          cartCount={getCartCount()}
        />
      )}

      <main className={cn(
        "pt-2 pb-32",
        currentView.startsWith('admin') && "pt-0 pb-0"
      )}>
        <AnimatePresence mode="wait">
          {!currentView.startsWith('admin') ? (
            <motion.div
              key={currentView}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.2 }}
            >
              {renderView()}
            </motion.div>
          ) : (
            <div key={currentView}>
              {renderView()}
            </div>
          )}
        </AnimatePresence>
      </main>

      {!currentView.startsWith('admin') && currentView !== 'checkout' && currentView !== 'order-success' && (
        <BottomNav
          currentView={currentView}
          onNavigate={handleNavigate}
          cartCount={getCartCount()}
        />
      )}

      <DebugPanel
        isOpen={isDebugOpen}
        onClose={() => setIsDebugOpen(false)}
      />
    </div>
  );
};

const AdminRouteLoading = () => (
  <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
    <div className="w-12 h-12 border-4 border-zinc-900 border-t-transparent rounded-full animate-spin"></div>
    <p className="text-muted-foreground animate-pulse font-medium">Verificando permissões...</p>
  </div>
);

const AdminAccessDenied = ({ onNavigate }: { onNavigate: (view: View) => void }) => {
  const { isAdmin, loading } = useAuth();
  useEffect(() => {
    if (!loading && !isAdmin) {
      console.warn('[App] Access denied to admin view. Redirecting to home.');
      import('sonner').then(({ toast }) => {
        toast.error('Acesso restrito a administradores.');
      });
      onNavigate('home');
    }
  }, [onNavigate, isAdmin, loading]);
  return null;
};

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, RefreshCw, Trash2, Wifi, WifiOff, ShieldAlert } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useStore } from '@/contexts/StoreContext';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

declare const __APP_VERSION__: string;

interface DebugPanelProps {
    isOpen: boolean;
    onClose: () => void;
}

export function DebugPanel({ isOpen, onClose }: DebugPanelProps) {
    const { config } = useStore();
    const { user } = useAuth();
    const [swStatus, setSwStatus] = useState<string>('unknown');
    const [networkStatus, setNetworkStatus] = useState<string>('online');
    const [lastCheck, setLastCheck] = useState<string>('-');
    const [remoteVersion, setRemoteVersion] = useState<string>('checking...');

    const checkEverything = useCallback(async () => {
        // 1. Check Network
        setNetworkStatus(navigator.onLine ? 'online' : 'offline');

        // 2. Check SW
        if ('serviceWorker' in navigator) {
            const reg = await navigator.serviceWorker.getRegistration();
            if (reg) {
                setSwStatus(reg.active ? 'active' : reg.waiting ? 'waiting' : 'installing');
            } else {
                setSwStatus('not_registered');
            }
        } else {
            setSwStatus('unsupported');
        }

        // 3. Check Remote Version
        try {
            const ts = Date.now();
            const res = await fetch(`/version.json?t=${ts}`, { cache: 'no-store' });
            if (res.ok) {
                const data = await res.json();
                setRemoteVersion(data.version);
            } else {
                setRemoteVersion('error_fetching');
            }
        } catch (e) {
            setRemoteVersion('network_error');
        }

        setLastCheck(new Date().toLocaleTimeString());
    }, []);

    useEffect(() => {
        if (isOpen) {
            const timer = setTimeout(() => {
                checkEverything();
            }, 0);
            return () => clearTimeout(timer);
        }
    }, [isOpen, checkEverything]);

    const forceNuclearReset = async () => {
        if (!confirm('ISSO VAI RESETAR TUDO E RECARREGAR. TEM CERTEZA?')) return;

        toast.info('Iniciando protocolo nuclear...');

        try {
            // 1. Unregister SW
            if ('serviceWorker' in navigator) {
                const regs = await navigator.serviceWorker.getRegistrations();
                for (const r of regs) await r.unregister();
            }

            // 2. Clear Caches
            if ('caches' in window) {
                const keys = await caches.keys();
                for (const k of keys) await caches.delete(k);
            }

            // 3. Clear LocalStorage (Warning: clears auth too if not careful, but maybe necessary for "nuclear")
            // We will keep 'sb-' keys (Supabase) to try and save auth, but clear others
            Object.keys(localStorage).forEach(key => {
                if (!key.startsWith('sb-')) localStorage.removeItem(key);
            });

            // 4. Force Reload with Timestamp to bust cache
            window.location.href = window.location.origin + '?nuclear=' + Date.now();

        } catch (e: any) {
            toast.error('Falha no reset: ' + e.message);
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[99999] flex items-center justify-center p-4">
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-black/80 backdrop-blur-sm"
                    />

                    <motion.div
                        initial={{ scale: 0.9, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        exit={{ scale: 0.9, opacity: 0 }}
                        className="relative w-full max-w-md bg-zinc-950 border border-zinc-800 rounded-2xl p-6 shadow-2xl overflow-hidden"
                    >
                        <div className="flex items-center justify-between mb-6">
                            <div className="flex items-center gap-2">
                                <ShieldAlert className="w-5 h-5 text-red-500" />
                                <h2 className="font-mono text-lg font-bold text-white">SYSTEM DIAGNOSTICS</h2>
                            </div>
                            <Button size="icon" variant="ghost" onClick={onClose} className="h-8 w-8 text-zinc-400">
                                <X className="w-4 h-4" />
                            </Button>
                        </div>

                        <div className="space-y-4 font-mono text-xs">

                            {/* STATUS GRID */}
                            <div className="grid grid-cols-2 gap-3">
                                <div className="p-3 bg-zinc-900 rounded-lg border border-zinc-800">
                                    <div className="text-zinc-500 mb-1">APP VERSION</div>
                                    <div className="text-emerald-400 font-bold">{__APP_VERSION__}</div>
                                </div>
                                <div className="p-3 bg-zinc-900 rounded-lg border border-zinc-800">
                                    <div className="text-zinc-500 mb-1">REMOTE VER</div>
                                    <div className={remoteVersion === __APP_VERSION__ ? "text-emerald-400 font-bold" : "text-amber-400 font-bold"}>
                                        {remoteVersion}
                                    </div>
                                </div>
                                <div className="p-3 bg-zinc-900 rounded-lg border border-zinc-800">
                                    <div className="text-zinc-500 mb-1">SW STATUS</div>
                                    <div className="text-blue-400 font-bold">{swStatus}</div>
                                </div>
                                <div className="p-3 bg-zinc-900 rounded-lg border border-zinc-800">
                                    <div className="text-zinc-500 mb-1">NETWORK</div>
                                    <div className="flex items-center gap-2">
                                        {networkStatus === 'online' ? <Wifi className="w-3 h-3 text-emerald-500" /> : <WifiOff className="w-3 h-3 text-red-500" />}
                                        <span className="text-white">{networkStatus}</span>
                                    </div>
                                </div>
                            </div>

                            {/* STORE CONFIG */}
                            <div className="p-3 bg-zinc-900 rounded-lg border border-zinc-800">
                                <div className="text-zinc-500 mb-1 flex justify-between">
                                    <span>STORE ID</span>
                                    <span className="text-[10px] text-zinc-600">MinAppVer: {config?.minAppVersion || 'N/A'}</span>
                                </div>
                                <div className="text-white truncate">{config?.minAppVersion ? 'CONFIG LOADED' : 'NO CONFIG'}</div>
                                <div className="text-zinc-600 mt-1 truncate">User: {user?.id || 'ANONYMOUS'}</div>
                            </div>

                            {/* ACTIONS */}
                            <div className="grid grid-cols-2 gap-3 mt-6">
                                <Button
                                    variant="outline"
                                    onClick={checkEverything}
                                    className="h-12 bg-zinc-900 border-zinc-800 hover:bg-zinc-800 text-zinc-300"
                                >
                                    <RefreshCw className="w-4 h-4 mr-2" />
                                    Refresh Stats
                                </Button>

                                <Button
                                    variant="destructive"
                                    onClick={forceNuclearReset}
                                    className="h-12 bg-red-900/20 border-red-900/50 hover:bg-red-900/40 text-red-400"
                                >
                                    <Trash2 className="w-4 h-4 mr-2" />
                                    NUCLEAR RESET
                                </Button>
                            </div>

                            <div className="text-center text-zinc-700 mt-4 text-[10px]">
                                Last check: {lastCheck}
                            </div>

                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
}

