import { motion, AnimatePresence } from 'framer-motion';
import { Rocket, X, ShieldAlert, ArrowRight, RefreshCw } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { useState, useEffect } from 'react';

interface UpdateNotificationProps {
    show: boolean;
    onUpdate: () => void;
    onClose?: () => void;
    isMandatory?: boolean;
    currentVersion?: string;
    newVersion?: string | null;
}

declare const __APP_VERSION__: string;

const SHORT_VERSION = (v: string) => v.slice(-6);

export function UpdateNotification({
    show,
    onUpdate,
    onClose,
    isMandatory = false,
    currentVersion,
    newVersion,
}: UpdateNotificationProps) {
    const [isUpdating, setIsUpdating] = useState(false);
    const [progress, setProgress] = useState(0);
    const [countdown, setCountdown] = useState<number | null>(null);

    const fromVer = SHORT_VERSION(currentVersion || __APP_VERSION__);
    const toVer = newVersion ? SHORT_VERSION(newVersion) : null;

    // Animated progress bar during update
    useEffect(() => {
        if (!isUpdating) return;
        setProgress(0);
        const steps = [15, 35, 55, 75, 90, 100];
        const timers: ReturnType<typeof setTimeout>[] = [];
        steps.forEach((p, i) => {
            timers.push(setTimeout(() => setProgress(p), i * 250));
        });
        return () => timers.forEach(clearTimeout);
    }, [isUpdating]);

    const handleUpdate = () => {
        setIsUpdating(true);
        setTimeout(() => onUpdate(), 1200);
    };

    // Mandatory countdown
    useEffect(() => {
        if (!isMandatory || !show) return;
        setCountdown(5);
        const interval = setInterval(() => {
            setCountdown(prev => {
                if (prev === null || prev <= 1) {
                    clearInterval(interval);
                    handleUpdate();
                    return null;
                }
                return prev - 1;
            });
        }, 1000);
        return () => clearInterval(interval);
    }, [isMandatory, show]); // eslint-disable-line react-hooks/exhaustive-deps

    return (
        <AnimatePresence>
            {show && (
                <div className="fixed inset-0 z-[10000] pointer-events-none flex items-start justify-center pt-safe">
                    {/* Mandatory backdrop */}
                    {isMandatory && (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 bg-black/50 backdrop-blur-sm pointer-events-auto"
                        />
                    )}

                    {/* Notification Card */}
                    <motion.div
                        initial={isMandatory
                            ? { scale: 0.85, opacity: 0, y: 80 }
                            : { y: -80, opacity: 0, scale: 0.95 }}
                        animate={isMandatory
                            ? { scale: 1, opacity: 1, y: 120 }
                            : { y: 16, opacity: 1, scale: 1 }}
                        exit={isMandatory
                            ? { scale: 0.85, opacity: 0, y: 80 }
                            : { y: -80, opacity: 0, scale: 0.95 }}
                        transition={{ type: 'spring', stiffness: 320, damping: 28 }}
                        className={cn(
                            'relative pointer-events-auto mx-4 overflow-hidden',
                            'backdrop-blur-2xl border shadow-2xl',
                            isMandatory
