import { useState } from 'react';
import type { Address } from '@/types';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Checkbox } from '@/components/ui/checkbox';
import { Loader2, Search } from 'lucide-react';
import { toast } from 'sonner';

interface AddressFormProps {
    initialData?: Address;
    onSubmit: (address: Omit<Address, 'id' | 'user_id'>) => Promise<any>;
    onCancel: () => void;
}

export function AddressForm({ initialData, onSubmit, onCancel }: AddressFormProps) {
    const [loading, setLoading] = useState(false);
    const [cepLoading, setCepLoading] = useState(false);

    const [formData, setFormData] = useState({
        name: initialData?.name || 'Casa',
        recipient_name: initialData?.recipient_name || '',
        cep: initialData?.cep || '',
        street: initialData?.street || '',
        number: initialData?.number || '',
        complement: initialData?.complement || '',
        neighborhood: initialData?.neighborhood || '',
        city: initialData?.city || '',
        state: initialData?.state || '',
        reference: initialData?.reference || '',
        is_default: initialData?.is_default || false,
    });

    const formatCep = (value: string) => {
        return value.replace(/\D/g, '').replace(/^(\d{5})(\d)/, '$1-$2').slice(0, 9);
    };

    const handleCepBlur = async () => {
        const cleanCep = formData.cep.replace(/\D/g, '');
        if (cleanCep.length !== 8) return;

        setCepLoading(true);
        try {
            const response = await fetch(`https://viacep.com.br/ws/${cleanCep}/json/`);
            const data = await response.json();

            if (data.erro) {
                toast.error('CEP não encontrado');
                return;
            }

            setFormData(prev => ({
                ...prev,
                street: data.logradouro,
                neighborhood: data.bairro,
                city: data.localidade,
                state: data.uf
            }));
        } catch (error) {
            console.error('Error fetching CEP:', error);
            toast.error('Erro ao buscar CEP');
        } finally {
            setCepLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await onSubmit(formData);
            // Form should be closed by parent, but we can verify success here if needed
        } catch (error) {
            console.error('Submit error:', error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                    <Label htmlFor="name">Apelido do Endereço *</Label>
                    <Input
                        id="name"
                        value={formData.name}
                        onChange={(e) => setFormData(p => ({ ...p, name: e.target.value }))}
                        placeholder="Ex: Casa, Trabalho"
                        required
                        disabled={loading}
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="recipient_name">Quem vai receber? *</Label>
                    <Input
                        id="recipient_name"
                        value={formData.recipient_name}
                        onChange={(e) => setFormData(p => ({ ...p, recipient_name: e.target.value }))}
                        placeholder="Nome do recebedor"
                        required
                        disabled={loading}
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="cep">CEP *</Label>
                    <div className="relative">
                        <Input
                            id="cep"
                            value={formData.cep}
                            onChange={(e) => setFormData(p => ({ ...p, cep: formatCep(e.target.value) }))}
                            onBlur={handleCepBlur}
                            placeholder="00000-000"
                            required
                            disabled={loading || cepLoading}
                        />
                        {cepLoading && (
                            <div className="absolute right-3 top-1/2 -translate-y-1/2">
                                <Loader2 className="h-4 w-4 animate-spin text-gray-500" />
                            </div>
                        )}
                        {!cepLoading && !formData.street && formData.cep.length === 9 && (
                            <button
                                type="button"
                                onClick={handleCepBlur}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                            >
                                <Search className="h-4 w-4" />
                            </button>
                        )}
                    </div>
                </div>

                <div className="space-y-2">
                    <Label htmlFor="street">Rua / Avenida *</Label>
                    <Input
                        id="street"
                        value={formData.street}
                        onChange={(e) => setFormData(p => ({ ...p, street: e.target.value }))}
                        required
                        disabled={loading}
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="number">Número *</Label>
                    <Input
                        id="number"
                        value={formData.number}
                        onChange={(e) => setFormData(p => ({ ...p, number: e.target.value }))}
                        required
                        disabled={loading}
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="complement">Complemento</Label>
                    <Input
                        id="complement"
                        value={formData.complement}
                        onChange={(e) => setFormData(p => ({ ...p, complement: e.target.value }))}
                        placeholder="Apto, Bloco, etc"
                        disabled={loading}
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="neighborhood">Bairro *</Label>
                    <Input
                        id="neighborhood"
                        value={formData.neighborhood}
                        onChange={(e) => setFormData(p => ({ ...p, neighborhood: e.target.value }))}
                        required
                        disabled={loading}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                        <Label htmlFor="city">Cidade *</Label>
                        <Input
                            id="city"
                            value={formData.city}
                            onChange={(e) => setFormData(p => ({ ...p, city: e.target.value }))}
                            required
                            disabled={loading}
                        />
                    </div>
                    <div className="space-y-2">
                        <Label htmlFor="state">Estado *</Label>
                        <Input
                            id="state"
                            value={formData.state}
                            onChange={(e) => setFormData(p => ({ ...p, state: e.target.value }))}
                            required
                            maxLength={2}
                            disabled={loading}
                        />
                    </div>
                </div>

                <div className="col-span-1 md:col-span-2 space-y-2">
                    <Label htmlFor="reference">Ponto de Referência</Label>
                    <Input
                        id="reference"
                        value={formData.reference}
                        onChange={(e) => setFormData(p => ({ ...p, reference: e.target.value }))}
                        disabled={loading}
                    />
                </div>

                <div className="col-span-1 md:col-span-2 flex items-center space-x-2 pt-2">
                    <Checkbox
                        id="is_default"
                        checked={formData.is_default}
                        onCheckedChange={(checked) => setFormData(p => ({ ...p, is_default: checked as boolean }))}
                        disabled={loading}
                    />
                    <Label htmlFor="is_default" className="cursor-pointer font-normal">
                        Definir como endereço padrão
                    </Label>
                </div>
            </div>

            <div className="flex justify-end gap-3 pt-4">
                <Button
                    type="button"
                    variant="outline"
                    onClick={onCancel}
                    disabled={loading}
                >
                    Cancelar
                </Button>
                <Button
                    type="submit"
                    disabled={loading}
                >
                    {loading ? (
                        <>
                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            Salvando...
                        </>
                    ) : (
                        'Salvar Endereço'
                    )}
                </Button>
            </div>
        </form>
    );
}

