import { ShoppingCart, ChevronRight } from 'lucide-react';
import { useState, useEffect } from 'react';
import { useCart } from '@/hooks/useCart';

interface CartReminderProps {
    onAction: () => void;
}

export function CartReminder({ onAction }: CartReminderProps) {
    const { cart: items, getCartCount } = useCart();
    const [isVisible, setIsVisible] = useState(false);
    const [isDismissed, setIsDismissed] = useState(false);

    useEffect(() => {
        // Show reminder if cart has items and it's not dismissed
        if (items.length > 0 && !isDismissed) {
            const showTimer = setTimeout(() => setIsVisible(true), 1500);
            return () => clearTimeout(showTimer);
        } else {
            setIsVisible(false);
        }
    }, [items.length, isDismissed]);

    useEffect(() => {
        if (isVisible) {
            const hideTimer = setTimeout(() => {
                setIsVisible(false);
                setIsDismissed(true);
            }, 3000);
            return () => clearTimeout(hideTimer);
        }
    }, [isVisible]);

    if (!isVisible) return null;

    const itemCount = getCartCount();

    return (
        <div className="fixed bottom-28 left-4 right-4 z-40 animate-in slide-in-from-bottom-8 fade-in-0 duration-700">
            <div className="bg-zinc-900 border border-white/10 rounded-[2.5rem] p-4 shadow-[0_20px_50px_rgba(0,0,0,0.3)] flex items-center justify-between group">
                <div className="flex items-center gap-4 flex-1">
                    <div className="w-12 h-12 bg-amber-400 rounded-2xl flex items-center justify-center shadow-[0_0_20px_rgba(251,191,36,0.3)] animate-pulse">
