                    </div>
                    <div className="space-y-0.5">
                        <p className="text-[10px] font-black uppercase tracking-[0.2em] text-amber-400">Não esqueça!</p>
                        <h4 className="text-xs font-bold text-white uppercase tracking-tighter">
                            Você tem {itemCount} {itemCount === 1 ? 'item' : 'itens'} no carrinho
                        </h4>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <button
                        onClick={onAction}
                        className="h-10 px-5 bg-white text-zinc-900 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-zinc-100 transition-all active:scale-95 flex items-center gap-2"
                    >
                        Ver Carrinho
                        <ChevronRight className="w-3 h-3" />
                    </button>
                    <div className="relative w-10 h-10 flex items-center justify-center flex-shrink-0">
                        <svg className="w-8 h-8 -rotate-90" viewBox="0 0 32 32">
                            <circle
                                cx="16"
                                cy="16"
                                r="12"
                                stroke="currentColor"
                                strokeWidth="2.5"
                                fill="transparent"
                                className="text-white/10"
                            />
                            <circle
                                cx="16"
                                cy="16"
                                r="12"
                                stroke="currentColor"
                                strokeWidth="2.5"
                                fill="transparent"
