                        </svg>
                        <style>{`
                            @keyframes timer {
                                from { stroke-dashoffset: 75.4; }
                                to { stroke-dashoffset: 0; }
                            }
                        `}</style>
                    </div>
                </div>
            </div>
        </div>
    );
