import { createContext, useEffect, useState, useMemo, useRef, type ReactNode } from 'react';
import { supabase } from '@/lib/supabase';
import type { Session, User } from '@supabase/supabase-js';
import { toast } from 'sonner';

interface AuthContextType {
    session: Session | null;
    user: User | null;
    loading: boolean;
    isAdmin: boolean;
    login: (email: string, senha: string) => Promise<boolean>;
    signUp: (email: string, senha: string) => Promise<boolean>;
    logout: () => Promise<void>;
}

// eslint-disable-next-line react-refresh/only-export-components
export const AuthContext = createContext<AuthContextType>({} as AuthContextType);

// Shared semaphore and state for all Auth instances (prevents redundant parallel checks)
let checkingLock: Promise<void> | null = null;
let lastVisibilityChange = Date.now();

if (typeof window !== 'undefined') {
    window.addEventListener('visibilitychange', () => {
        lastVisibilityChange = Date.now();
    });
}

export const AuthProvider = ({ children }: { children: ReactNode }) => {
    const [session, setSession] = useState<Session | null>(null);
    const [user, setUser] = useState<User | null>(null);
    const [loading, setLoading] = useState(true);
    const [isAdmin, setIsAdmin] = useState<boolean>(() => {
        // Optimistic initialization from cache to prevent UI flicker/disconnects
        if (typeof window !== 'undefined') {
            const lastUser = localStorage.getItem('supabase.auth.token'); // Crude way to check if someone was logged in
            if (lastUser) {
                return localStorage.getItem('app.is_admin') === 'true';
            }
        }
        return false;
    });

    const checkAdmin = async (u: User | null | undefined, force: boolean = false) => {
        if (!u) {
            setIsAdmin(false);
            if (typeof window !== 'undefined') localStorage.removeItem('app.is_admin');
            return;
        }

        // If a check is already in progress, wait for it instead of starting a new one
        if (checkingLock) {
            console.log('[Auth] Check already in progress, waiting...');
            await checkingLock;
            return;
        }

        const runCheck = async () => {
            // REDUCED JITTER: 1s delay instead of 3s for faster initial response
            const timeSinceResume = Date.now() - lastVisibilityChange;
            if (timeSinceResume < 1000) {
                console.log(`[Auth] Resume detected (${timeSinceResume}ms ago), jittering check for 1s...`);
                await new Promise(resolve => setTimeout(resolve, 1000));
            }

            // REDUCED COOLDOWN for forced checks (like login)
            const now = Date.now();
            const COOLDOWN_MS = force ? 0 : 30000;
            const lastCheck = (window as any)._lastAdminCheck || 0;
            const timeSinceLastCheck = now - lastCheck;

            if (timeSinceLastCheck < COOLDOWN_MS) {
                console.log(`[Auth] Throttling check (last check was ${Math.round(timeSinceLastCheck / 1000)}s ago)`);
                return;
            }

            try {
                console.log('[Auth] Executing admin check for:', u.id);
                // Non-blocking RPC check
                const adminPromise = supabase.rpc('is_admin');
                const timeoutPromise = new Promise((resolve) => setTimeout(() => resolve('timeout'), 10000));

                const result: any = await Promise.race([adminPromise, timeoutPromise]);

                if (result === 'timeout' || result?.error) {
                    console.warn(`[Auth] Admin RPC failed or timed out. result:`, result);

                    // Fallback to profiles table
                    const { data: profile, error: profileError } = await supabase
                        .from('profiles')
                        .select('role')
                        .eq('id', u.id)
                        .single();

                    if (!profileError && profile) {
                        const isAdminRole = profile.role === 'admin';
                        console.log(`[Auth] Fallback check success. isAdmin: ${isAdminRole}`);
                        setIsAdmin(isAdminRole);
                        if (typeof window !== 'undefined') localStorage.setItem('app.is_admin', String(isAdminRole));
                    }
                } else {
                    const isAdminVal = !!result.data;
                    console.log(`[Auth] Admin check result:`, isAdminVal);
                    setIsAdmin(isAdminVal);
                    if (typeof window !== 'undefined') localStorage.setItem('app.is_admin', String(isAdminVal));
                }

                if (typeof window !== 'undefined') {
                    (window as any)._lastAdminCheck = Date.now();
                }
            } catch (error) {
                console.error('[Auth] Unexpected check error:', error);
            }
        };

        // Execute with lock
        checkingLock = runCheck();
        try {
            await checkingLock;
        } finally {
            checkingLock = null;
        }
    };

    useEffect(() => {
        // standalone fail-safe timer (v11.x extended to 15s for mobile stability)
        const safetyTimeout = setTimeout(() => {
            setLoading(current => {
                if (current) {
                    console.log('[Auth] Safety timeout (15s) reached. Unblocking UI.');
                    return false;
                }
                return current;
            });
        }, 15000);
        return () => clearTimeout(safetyTimeout);
    }, []);

    const hasInited = useRef(false);
    useEffect(() => {
        // Immediate session resolution with internal timeout guard
        const initAuth = async () => {
            if (hasInited.current) return;
            hasInited.current = true;
            console.log('[Auth] initAuth started');
            try {
                // Racing getSession against a timeout to prevent absolute hangs on mobile
                const sessionPromise = supabase.auth.getSession();
                const timeoutPromise = new Promise((resolve) => setTimeout(() => resolve('timeout'), 8000));

                const sessionRes: any = await Promise.race([sessionPromise, timeoutPromise]);

                if (sessionRes === 'timeout') {
                    console.warn('[Auth] getSession timed out. Moving to listener.');
                    return;
                }

                const initSes = sessionRes.data?.session;
                console.log('[Auth] getSession result:', !!initSes);
                if (initSes) {
                    setSession(initSes);
                    setUser(initSes.user);
                    // Non-blocking admin check
                    checkAdmin(initSes.user);
                }
            } catch (err) {
                console.error('[Auth] initAuth error:', err);
            } finally {
                // FALLBACK: Ensure loading is false even if we couldn't get session
                console.log('[Auth] initAuth finished - forcing loading false');
                setLoading(false);
            }
        };
        initAuth();

        // Consolidated session listener for subsequent changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
            console.log('[Auth] State change event:', event, !!session);

            setSession(prev => {
                // If we already have a session from initAuth, and this is INITIAL_SESSION with null,
                // we suspicious it might be a race condition. 
                // However, Supabase usually knows best. But we'll guard.
                if (event === 'INITIAL_SESSION' && !session && prev) {
                    console.warn('[Auth] Guarded: INITIAL_SESSION tried to clear a restored session.');
                    return prev;
                }

                if (event === 'INITIAL_SESSION' && prev?.user?.id === session?.user?.id) return prev;
                return session;
            });

            setUser(prev => {
                if (event === 'INITIAL_SESSION' && !session && prev) return prev;
                if (event === 'INITIAL_SESSION' && prev?.id === session?.user?.id) return prev;
                return session?.user ?? null;
            });

            if (session?.user) {
                checkAdmin(session.user);
            } else {
                setIsAdmin(false);
                if (typeof window !== 'undefined') localStorage.removeItem('app.is_admin');
            }

            setLoading(false);
        });

        return () => {
            subscription.unsubscribe();
        };
    }, []);



    const signUp = async (email: string, senha: string): Promise<boolean> => {
        const { error } = await supabase.auth.signUp({
            email,
            password: senha,
            options: {
                emailRedirectTo: window.location.origin
            }
        });
        if (error) {
            toast.error('Erro ao cadastrar: ' + error.message);
            return false;
        }
        return true;
    };

    const login = async (email: string, senha: string): Promise<boolean> => {
        const { error } = await supabase.auth.signInWithPassword({
            email,
            password: senha,
        });
        if (error) {
            toast.error('Erro ao entrar: ' + error.message);
            return false;
        }
        return true;
    };

    const logout = async () => {
        const { error } = await supabase.auth.signOut();
        if (error) {
            toast.error('Erro ao sair: ' + error.message);
        } else {
            setSession(null);
            setUser(null);
            setIsAdmin(false);
        }
    };

    const value = useMemo(() => ({
        session,
        user,
        loading,
        isAdmin,
        login,
        signUp,
        logout
    }), [session, user, loading, isAdmin]);

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
};

import { useState, useCallback } from 'react';
import { supabase } from '@/lib/supabase';

export function useAnalytics() {
    const [loading, setLoading] = useState(false);

    const fetchInventoryHealth = useCallback(async () => {
        try {
            setLoading(true);
            const { data, error } = await (supabase.rpc as any)('get_inventory_health');
            if (error) throw error;
            return data || [];
        } catch (err) {
            console.error('Error fetching inventory health:', err);
            return [];
        } finally {
            setLoading(false);
        }
    }, []);

    const fetchCategoryAnalytics = useCallback(async (startDate: string, endDate: string) => {
        try {
            setLoading(true);
            const { data, error } = await (supabase.rpc as any)('get_category_analytics', {
                p_start_date: startDate,
                p_end_date: endDate
            });
            if (error) throw error;
            return data || [];
        } catch (err) {
            console.error('Error fetching category analytics:', err);
            return [];
        } finally {
            setLoading(false);
        }
    }, []);

    const fetchCustomerIntelligence = useCallback(async () => {
        try {
            setLoading(true);
            const { data, error } = await (supabase.rpc as any)('get_customer_intelligence');
            if (error) throw error;
            return data || [];
        } catch (err) {
            console.error('Error fetching customer intelligence:', err);
            return [];
        } finally {
            setLoading(false);
        }
    }, []);

    const fetchExecutiveSummary = useCallback(async () => {
        try {
            setLoading(true);
            const { data, error } = await (supabase.rpc as any)('get_admin_analytics_v2');
            if (error) throw error;
            return data;
        } catch (err) {
            console.error('Error fetching executive summary:', err);
            return null;
        } finally {
            setLoading(false);
        }
    }, []);

    const fetchRetentionAnalytics = useCallback(async (days: number = 90) => {
        try {
            setLoading(true);
            // Add a small delay to ensure auth session is fully propagated to PostgREST
            await new Promise(resolve => setTimeout(resolve, 300));

            // Try get_retention_analytics first, fallback to get_retention_rate
            const { data, error } = await (supabase.rpc as any)('get_retention_analytics', { p_days: days });

            if (error) {
                // If it's the specific UUID error, we know the RPC needs updating, but we log it clearly
                if (error.code === '22P02') {
                    console.error('[Analytics] Critical: get_retention_analytics UUID cast error. DATABASE MIGRATION REQUIRED.', error);
                } else {
                    console.warn('[Analytics] get_retention_analytics failed, trying get_retention_rate fallback:', error);
                }

                const { data: fallbackData, error: fallbackError } = await (supabase.rpc as any)('get_retention_rate');
                if (fallbackError) throw fallbackError;
                return fallbackData ?? 0;
            }
            return data ?? 0;
        } catch (err) {
            console.error('[Analytics] Error in fetchRetentionAnalytics:', err);
            return 0;
        } finally {
            setLoading(false);
        }
    }, []);

    return {
        loading,
        fetchInventoryHealth,
        fetchCustomerIntelligence,
        fetchExecutiveSummary,
        fetchRetentionAnalytics,
        fetchCategoryAnalytics
    };
}

import { useCallback } from 'react';
import { logForensic } from '@/lib/forensicsDB';

/**
 * useBackgroundFetch v20.0
 * Background Fetch API — handles large downloads that continue even if browser closes.
 */
export function useBackgroundFetch() {
    const isSupported = 'backgroundFetch' in (navigator.serviceWorker.controller || {});

    const startBackgroundSync = useCallback(async (id: string, urls: string[], title: string) => {
        if (!('serviceWorker' in navigator)) return;

        try {
            const reg = await navigator.serviceWorker.ready;
            const fetchReg = await (reg as any).backgroundFetch.fetch(id, urls, {
                title: title,
                icons: [{ src: '/icons/icon-192x192.png', sizes: '192x192', type: 'image/png' }],
                downloadTotal: 0, // optional, sum of content-lengths
            });

            void logForensic({
                t: new Date().toISOString(),
                m: `Background Fetch Started: ${id}`,
                d: { urlsCount: urls.length, title },
                level: 'info',
                source: 'sw',
            });

            return fetchReg;
        } catch (err) {
            console.error('[BackgroundFetch] Failed to start:', err);
            return null;
        }
    }, []);

    return { startBackgroundSync, isSupported };
}

import { useState, useEffect, useCallback } from 'react';
import type { Banner } from '@/types';
import { supabase } from '@/lib/supabase';

// Module-level cache to persist banners across component remounts
let cachedBanners: Banner[] = [];
let isInitialLoadDone = false;
let globalFetchPromise: Promise<void> | null = null;

export function useBanners() {
  const [banners, setBanners] = useState<Banner[]>(cachedBanners);
  const [isLoaded, setIsLoaded] = useState(isInitialLoadDone);

  const fetchBanners = useCallback(async (onlyActive = true, forceRefresh = false) => {
    // If already fetching, wait for the same promise
    if (globalFetchPromise && !forceRefresh) return globalFetchPromise;

    // If already loaded and not forcing refresh, skip
    if (isInitialLoadDone && !forceRefresh) return;

    const fetchAction = async () => {
      try {
        console.log('[Banners] Fetching banners...');
        let query = supabase
          .from('banners')
          .select('*');

        if (onlyActive) {
          query = query.eq('active', true);
        }

        const { data, error } = await query.order('order', { ascending: true });

        if (error) {
          console.error('[Banners] Supabase error:', error);
          throw error;
        }

        console.log(`[Banners] Found ${data?.length || 0} banners`);

        if (data) {
          const mappedBanners: Banner[] = data.map((b: any) => ({
            id: b.id,
            imageUrl: b.image_url || b.imagem_url,
            title: b.title || '',
            link: b.link || undefined,
            position: b.position as "home_top" | "home_middle" | "home_bottom",
            active: b.active ?? b.ativo ?? true,
            order: b.order || 0
          }));

          cachedBanners = mappedBanners;
          setBanners(mappedBanners);
        }
        isInitialLoadDone = true;
      } catch (error: any) {
        console.error('[Banners] Error fetching banners:', error.message);
      } finally {
        setIsLoaded(true);
        globalFetchPromise = null;
      }
    };

    globalFetchPromise = fetchAction();
    return globalFetchPromise;
  }, []);

  useEffect(() => {
    if (!isInitialLoadDone) {
      fetchBanners();
    }
  }, [fetchBanners]);

  const getBannersByPosition = useCallback((position: Banner['position']) => {
    return banners
      .filter(b => b.position === position) // Filter by activity happened in fetchBanners
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
  }, [banners]);

  const uploadBannerImage = async (file: File): Promise<string> => {
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
      const filePath = `${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('banners')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage
        .from('banners')
        .getPublicUrl(filePath);

      return data.publicUrl;
    } catch (error) {
      console.error('Error uploading banner:', error);
      throw error;
    }
  };

  const addBanner = async (banner: Omit<Banner, 'id'>) => {
    try {
      const { data, error } = await supabase
        .from('banners')
        .insert([{
          image_url: banner.imageUrl,
          title: banner.title,
          link: banner.link,
          position: banner.position,
          active: banner.active,
          order: banner.order
        }])
        .select()
        .single();

      if (error) throw error;

      isInitialLoadDone = false; // Force re-fetch to update cache correctly
      return data;
    } catch (error) {
      console.error('Error adding banner:', error);
      throw error;
    }
  };

  const updateBanner = async (id: string, updates: Partial<Banner>) => {
    try {
      const dbUpdates: any = {};
      if (updates.imageUrl !== undefined) dbUpdates.image_url = updates.imageUrl;
      if (updates.title !== undefined) dbUpdates.title = updates.title;
      if (updates.link !== undefined) dbUpdates.link = updates.link;
      if (updates.position !== undefined) dbUpdates.position = updates.position;
      if (updates.active !== undefined) dbUpdates.active = updates.active;
      if (updates.order !== undefined) dbUpdates.order = updates.order;

      const { error } = await supabase
        .from('banners')
        .update(dbUpdates)
        .eq('id', id);

      if (error) throw error;
      isInitialLoadDone = false;
    } catch (error) {
      console.error('Error updating banner:', error);
      throw error;
    }
  };

  const reorderBanners = async (activeBannerId: string, overBannerId: string) => {
    // 1. Optimistic Update
    const previousBanners = [...banners];
    const newBanners = [...banners];
    const activeIndex = newBanners.findIndex(b => b.id === activeBannerId);
    const overIndex = newBanners.findIndex(b => b.id === overBannerId);

    if (activeIndex !== -1 && overIndex !== -1) {
      const activeBanner = { ...newBanners[activeIndex] };
      const overBanner = { ...newBanners[overIndex] };

      // Swap the 'order' values
      const tempOrder = activeBanner.order;
      activeBanner.order = overBanner.order;
      overBanner.order = tempOrder;

      newBanners[activeIndex] = overBanner;
      newBanners[overIndex] = activeBanner;

      // Sort by order
      newBanners.sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
      setBanners(newBanners);
    }

    try {
      // 2. Atomic Swap via RPC
      const { error } = await (supabase.rpc as any)('swap_banner_order', {
        banner_id_1: activeBannerId,
        banner_id_2: overBannerId
      });

      if (error) throw error;
      isInitialLoadDone = false;
    } catch (error) {
      setBanners(previousBanners);
      console.error('Error reordering banners:', error);
    }
  };

  const deleteBanner = async (id: string, imageUrl?: string) => {
    try {
      const { error } = await supabase
        .from('banners')
        .delete()
        .eq('id', id);

      if (error) throw error;

      if (imageUrl) {
        try {
          const url = new URL(imageUrl);
          const fileName = url.pathname.split('/').pop();
          if (fileName && !fileName.includes('placeholder')) {
            await supabase.storage.from('banners').remove([fileName]);
          }
        } catch (e) {
          const fileName = imageUrl.split('/').pop();
          if (fileName) {
            await supabase.storage.from('banners').remove([fileName]);
          }
        }
      }
      cachedBanners = cachedBanners.filter(b => b.id !== id);
      setBanners(prev => prev.filter(b => b.id !== id));
    } catch (error) {
      console.error('Error deleting banner:', error);
      throw error;
    }
  };

  return {
    banners,
    isLoaded,
    getBannersByPosition,
    uploadBannerImage,
    addBanner,
    updateBanner,
    deleteBanner,
    reorderBanners,
    refreshBanners: fetchBanners
  };
}

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';
import type { Category } from '@/types';

export function useCategories() {
    const [categories, setCategories] = useState<Category[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchCategories = useCallback(async () => {
        try {
            setIsLoading(true);
            const { data, error } = await supabase
                .from('categorias')
                .select('*')
                .order('nome');

            if (error) throw error;

            const adaptedCategories: Category[] = (data || []).map((item) => ({
                id: item.id,
                name: item.nome,
                slug: item.slug || '',
                description: item.descricao || '',
                isActive: item.ativo ?? true,
                createdAt: item.created_at
            }));

            setCategories(adaptedCategories);
        } catch (error) {
            console.error('Error fetching categories:', error);
            toast.error('Erro ao carregar categorias');
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchCategories();
    }, [fetchCategories]);

    const generateSlug = (name: string) => {
        return name
            .toLowerCase()
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/(^-|-$)+/g, '');
    };

    const addCategory = useCallback(async (category: Omit<Category, 'id' | 'createdAt' | 'slug'>) => {
        const tempId = `temp-${Date.now()}`;
        const slug = generateSlug(category.name);
        const newCategory: Category = {
            id: tempId,
            name: category.name,
            slug,
            description: category.description,
            isActive: category.isActive,
            createdAt: new Date().toISOString()
        };

        setCategories(prev => [...prev, newCategory]);

        try {
            const { data, error } = await supabase
                .from('categorias')
                .insert({
                    nome: category.name,
                    slug,
                    descricao: category.description,
                    ativo: category.isActive
                })
                .select()
                .single();

            if (error) throw error;

            setCategories(prev => prev.map(c => c.id === tempId ? {
                id: data.id,
                name: data.nome,
                slug: data.slug || '',
                description: data.descricao || '',
                isActive: data.ativo ?? true,
                createdAt: data.created_at
            } : c));

            toast.success('Categoria criada com sucesso!');
            return data;
        } catch (error) {
            setCategories(prev => prev.filter(c => c.id !== tempId));
            console.error('Error adding category:', error);
            toast.error('Erro ao criar categoria');
            throw error;
        }
    }, []);

    const updateCategory = useCallback(async (id: string, updates: Partial<Omit<Category, 'id' | 'createdAt' | 'slug'>>) => {
        const previousCategories = [...categories];

        setCategories(prev => prev.map(c => {
            if (c.id === id) {
                const next = { ...c, ...updates };
                if (updates.name) next.slug = generateSlug(updates.name);
                return next;
            }
            return c;
        }));

        try {
            const updateData: any = {};
            if (updates.name) {
                updateData.nome = updates.name;
                updateData.slug = generateSlug(updates.name);
            }
            if (updates.description !== undefined) updateData.descricao = updates.description;
            if (updates.isActive !== undefined) updateData.ativo = updates.isActive;

            const { error } = await supabase
                .from('categorias')
                .update(updateData)
                .eq('id', id);

            if (error) throw error;
            toast.success('Categoria atualizada com sucesso!');
        } catch (error) {
            setCategories(previousCategories);
            console.error('Error updating category:', error);
            toast.error('Erro ao atualizar categoria');
            throw error;
        }
    }, [categories]);

    const deleteCategory = useCallback(async (id: string) => {
        const previousCategories = [...categories];
        setCategories(prev => prev.filter(c => c.id !== id));

        try {
            const { error } = await supabase
                .from('categorias')
                .delete()
                .eq('id', id);

            if (error) throw error;
            toast.success('Categoria removida com sucesso!');
        } catch (error) {
            setCategories(previousCategories);
            console.error('Error deleting category:', error);
            toast.error('Erro ao remover categoria');
            throw error;
        }
    }, [categories]);

    return {
        categories,
        isLoading,
        fetchCategories,
        addCategory,
        updateCategory,
        deleteCategory
    };
}

import { useState, useEffect, useCallback } from 'react';
import type { Coupon } from '@/types';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';

export function useCoupons() {
  const [coupons, setCoupons] = useState<Coupon[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchCoupons = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('coupons')
        .select('*')
        .eq('active', true);

      if (error) throw error;

      const formattedCoupons: Coupon[] = data?.map((c) => ({
        id: c.id,
        code: c.code,
        type: c.type as 'percentage' | 'fixed',
        value: c.value,
        minPurchase: c.min_purchase ?? undefined,
        usageLimit: c.usage_limit ?? undefined,
        usageCount: c.usage_count || 0,
        validUntil: c.valid_until ?? undefined,
        active: c.active ?? true
      })) || [];

      setCoupons(formattedCoupons);
    } catch (error) {
      console.error('Error fetching coupons:', error);
      toast.error('Erro ao carregar cupons');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCoupons();
  }, [fetchCoupons]);

  const validateCoupon = useCallback(async (code: string, subtotal: number): Promise<{ valid: boolean; discount: number; message?: string }> => {
    try {
      const { data, error } = await supabase.rpc('validate_coupon_secure' as any, {
        p_code: code,
        p_subtotal: subtotal
      } as any);

      if (error) throw error;

      const result = (data as any)?.[0];
      if (!result) return { valid: false, discount: 0, message: 'Erro ao validar cupom' };

      return {
        valid: result.is_valid,
        discount: Number(result.discount_value),
        message: result.error_message
      };
    } catch (error) {
      console.error('Error validating coupon:', error);
      return { valid: false, discount: 0, message: 'Erro na conexão com servidor' };
    }
  }, []);

  const applyCoupon = useCallback(async (code: string) => {
    try {
      const { error } = await (supabase.rpc('increment_coupon_usage' as any, {
        coupon_code: code
      } as any) as any);

      if (error) throw error;

      fetchCoupons();
      return { success: true };
    } catch (error) {
      console.error('Error applying coupon:', error);
      return { success: false, message: 'Erro ao aplicar uso do cupom' };
    }
  }, [fetchCoupons]);

  const addCoupon = async (coupon: Omit<Coupon, 'id' | 'usageCount'>) => {
    try {
      const { data, error } = await supabase
        .from('coupons')
        .insert([{
          code: coupon.code,
          type: coupon.type,
          value: coupon.value,
          min_purchase: coupon.minPurchase,
          usage_limit: coupon.usageLimit,
          valid_until: coupon.validUntil,
          active: coupon.active ?? true,
          usage_count: 0
        }])
        .select()
        .single();

      if (error) throw error;

      toast.success('Cupom criado com sucesso');
      fetchCoupons();
      return data;
    } catch (error) {
      console.error('Error adding coupon:', error);
      toast.error('Erro ao criar cupom');
      throw error;
    }
  };

  const updateCoupon = async (id: string, updates: Partial<Coupon>) => {
    try {
      const { error } = await supabase
        .from('coupons')
        .update({
          code: updates.code,
          type: updates.type,
          value: updates.value,
          min_purchase: updates.minPurchase,
          usage_limit: updates.usageLimit,
          valid_until: updates.validUntil,
          active: updates.active
        })
        .eq('id', id);

      if (error) throw error;

      toast.success('Cupom atualizado');
      fetchCoupons();
    } catch (error) {
      console.error('Error updating coupon:', error);
      toast.error('Erro ao atualizar cupom');
      throw error;
    }
  };

  const deleteCoupon = async (id: string) => {
    try {
      const { error } = await supabase
        .from('coupons')
        .delete()
        .eq('id', id);

      if (error) throw error;

      toast.success('Cupom removido');
      fetchCoupons();
    } catch (error) {
      console.error('Error deleting coupon:', error);
      toast.error('Erro ao remover cupom');
      throw error;
    }
  };

  const getCouponStats = useCallback(async () => {
    try {
      const { data, error } = await (supabase.rpc as any)('get_coupon_stats');
      if (error) throw error;
      return (data as any)?.[0] || null;
    } catch (error) {
      console.error('Error getting coupon stats:', error);
      return null;
    }
  }, []);

  return {
    coupons,
    loading,
    validateCoupon,
    applyCoupon,
    refreshCoupons: fetchCoupons,
    addCoupon,
    updateCoupon,
    deleteCoupon,
    getCouponStats
  };
}

