import { useState, useEffect } from 'react';
import { logForensic } from '@/lib/forensicsDB';

interface DeviceSpecs {
    memory?: number;     // approximate RAM in GB
    cpus?: number;       // hardware concurrency
    saveData?: boolean;  // network save data mode
}

/**
 * useDeviceAdaptation v20.0
 * Adapts application limits based on hardware capabilities.
 * Uses Device Memory API and Hardware Concurrency.
 * 
 * Logic:
 * - Low Memory (< 4GB): Reduce cache limits, disable heavy animations.
 * - High Memory (> 8GB): Extended cache, speculation rules eager.
 */
export function useDeviceAdaptation() {
    const [specs, setSpecs] = useState<DeviceSpecs>({
        memory: (navigator as any).deviceMemory,
        cpus: navigator.hardwareConcurrency,
    });

    useEffect(() => {
        const conn = (navigator as any).connection;
        if (conn) {
            setSpecs(prev => ({ ...prev, saveData: conn.saveData }));
        }

        void logForensic({
            t: new Date().toISOString(),
            m: 'Device Adaptation Profile Loaded',
            d: specs,
            level: 'info',
            source: 'app',
        });
    }, []);

    const isLowEnd = (specs.memory || 8) < 4 || (specs.cpus || 8) < 4;
    const isHighEnd = (specs.memory || 0) >= 8 && (specs.cpus || 0) >= 8;

    return {
        specs,
        isLowEnd,
        isHighEnd,
        // Dynamic limits
        maxForensicsEntries: isLowEnd ? 100 : 500,
        cacheTTLMultiplier: isLowEnd ? 0.5 : (isHighEnd ? 2 : 1)
    };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/contexts/AuthContext';
import { useLocalStorage } from './useLocalStorage';
import { useProducts } from './useProducts';
import type { Product } from '@/types';
import { toast } from 'sonner';

const FAVORITES_KEY = 'ikcous_favorites';

export function useFavorites() {
  const { user } = useAuth();
  const { products: allProducts } = useProducts();
  const [localFavorites, setLocalFavorites] = useLocalStorage<Product[]>(FAVORITES_KEY, []);
  const [dbFavoriteIds, setDbFavoriteIds] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  // 1. Sync Logic: When User logs in, merge Local -> DB
  useEffect(() => {
    if (!user) {
      if (dbFavoriteIds.length > 0) {
        setDbFavoriteIds([]);
      }
      return;
    }

    const syncFavorites = async () => {
      setLoading(true);

      try {
        // A. Push Local to DB (Merge)
        if (localFavorites.length > 0) {
          const promises = localFavorites.map(p =>
            supabase.from('favorites').upsert(
              { user_id: user.id, product_id: p.id },
              { onConflict: 'user_id, product_id', ignoreDuplicates: true }
            )
          );
          await Promise.all(promises);

          // Clear local after sync
          setLocalFavorites([]);
          toast.success('Seus favoritos locais foram sincronizados!');
        }

        // B. Fetch from DB
        const { data, error } = await supabase
          .from('favorites')
          .select('product_id');

        if (error) {
          console.error('Error fetching favorites', error);
        } else if (data) {
          const newIds = data.map(f => f.product_id);
          // Only update if different
          if (JSON.stringify(newIds) !== JSON.stringify(dbFavoriteIds)) {
            setDbFavoriteIds(newIds);
          }
        }
      } catch (err) {
        console.error('Sync failed', err);
      } finally {
        setLoading(false);
      }
    };

    syncFavorites();
  }, [user, localFavorites, setLocalFavorites, dbFavoriteIds.length]); // Improved dependencies

  // 2. Computed Favorites List
  const favorites = user
    ? allProducts.filter(p => dbFavoriteIds.includes(p.id))
    : localFavorites;

  // 3. Actions
  const addToFavorites = useCallback(async (product: Product) => {
    if (user) {
      // Optimistic
      setDbFavoriteIds(prev => [...prev, product.id]);
      const { error } = await supabase.from('favorites').insert({ user_id: user.id, product_id: product.id });

      if (error) {
        console.error(error);
        toast.error('Erro ao salvar favorito');
        setDbFavoriteIds(prev => prev.filter(id => id !== product.id));
      } else {
        toast.success('Adicionado aos favoritos');
      }
    } else {
      setLocalFavorites(prev => {
        if (prev.find(p => p.id === product.id)) return prev;
        return [...prev, product];
      });
      toast.success('Adicionado aos favoritos');
    }
  }, [user, setLocalFavorites]);

  const removeFromFavorites = useCallback(async (productId: string) => {
    if (user) {
      // Optimistic
      setDbFavoriteIds(prev => prev.filter(id => id !== productId));
      const { error } = await supabase.from('favorites').delete().eq('user_id', user.id).eq('product_id', productId);

      if (error) {
        console.error(error);
        toast.error('Erro ao remover favorito');
        setDbFavoriteIds(prev => [...prev, productId]);
      } else {
        toast.success('Removido dos favoritos');
      }
    } else {
      setLocalFavorites(prev => prev.filter(p => p.id !== productId));
      toast.success('Removido dos favoritos');
    }
  }, [user, setLocalFavorites]);

  const toggleFavorite = useCallback((product: Product) => {
    const isFav = user ? dbFavoriteIds.includes(product.id) : localFavorites.some(p => p.id === product.id);
    if (isFav) {
      removeFromFavorites(product.id);
    } else {
      addToFavorites(product);
    }
  }, [user, dbFavoriteIds, localFavorites, removeFromFavorites, addToFavorites]);

  const isFavorite = useCallback((productId: string) => {
    if (user) return dbFavoriteIds.includes(productId);
    return localFavorites.some(p => p.id === productId);
  }, [user, dbFavoriteIds, localFavorites]);

  return {
    favorites,
    toggleFavorite,
    isFavorite,
    loading
  };
}

import { useEffect, useCallback } from 'react';
import { logForensic } from '@/lib/forensicsDB';

/**
 * useIdleMaintenance v20.0
 * Idle Detection API — triggers background cleanup when user is away.
 * Requires permission 'idle-detection'.
 * 
 * Perfect for: Deep IndexedDB cleanup, Cache pruning, Syncing large datasets.
 */
export function useIdleMaintenance(onIdleMaintenance: () => Promise<void>) {
    const runMaintenance = useCallback(async () => {
        void logForensic({
            t: new Date().toISOString(),
            m: 'Starting Idle Maintenance (User Away)',
            level: 'info',
            source: 'app',
        });

        await onIdleMaintenance();

        void logForensic({
            t: new Date().toISOString(),
            m: 'Idle Maintenance Complete',
            level: 'info',
            source: 'app',
        });
    }, [onIdleMaintenance]);

    useEffect(() => {
        if (!('IdleDetector' in window)) return;

        const controller = new AbortController();
        const { signal } = controller;

        const startDetection = async () => {
            try {
                const detector = new (window as any).IdleDetector();
                detector.addEventListener('change', () => {
                    const { userState, screenState } = detector;
                    if (userState === 'idle' || screenState === 'locked') {
                        runMaintenance();
                    }
                });

                await detector.start({
                    threshold: 60000, // 1 minute of inactivity
                    signal,
                });
                console.log('[IdleDetection] Started successfully');
            } catch (err) {
                // Silently handle start errors if already aborted or background blocked
                if ((err as Error).name !== 'AbortError') {
                    console.warn('[IdleDetection] Start failed:', err);
                }
            }
        };

        const init = async () => {
            try {
                // Check current permission state if available
                if ('permissions' in navigator) {
                    const status = await navigator.permissions.query({ name: 'idle-detection' as any });

                    if (status.state === 'granted') {
                        return startDetection();
                    }

                    if (status.state === 'denied') {
                        console.debug('[IdleDetection] Permission was previously denied.');
                        return;
                    }
                }

                // If prompt or unknown, wait for a natural user gesture to request it
                const requestPerm = async () => {
                    try {
                        const state = await (window as any).IdleDetector.requestPermission();
                        if (state === 'granted') {
                            startDetection();
                        }
                    } catch (err) {
                        // Suppress NotAllowedError noise if gesture wasn't captured perfectly
                        if ((err as Error).name !== 'NotAllowedError') {
                            console.warn('[IdleDetection] requestPermission failed:', err);
                        } else {
                            console.debug('[IdleDetection] requestPermission blocked: No persistent user gesture.');
                        }
                    }
                };

                const handleGesture = () => {
                    requestPerm();
                    window.removeEventListener('click', handleGesture);
                    window.removeEventListener('touchstart', handleGesture);
                };

                window.addEventListener('click', handleGesture, { once: true });
                window.addEventListener('touchstart', handleGesture, { once: true });

            } catch (err) {
                console.debug('[IdleDetection] Setup skipped:', err);
            }
        };

        init();
        return () => controller.abort();
    }, [runMaintenance]);
}

