import { useState, useEffect, useCallback, useRef } from 'react';

interface BeforeInstallPromptEvent extends Event {
    readonly platforms: string[];
    readonly userChoice: Promise<{ outcome: 'accepted' | 'dismissed'; platform: string }>;
    prompt(): Promise<void>;
}

interface InstallAnalytics {
    promptShownAt: string | null;
    promptDeferredAt: string | null;
    installedAt: string | null;
    decisionMs: number | null;
    outcome: 'accepted' | 'dismissed' | 'pending' | null;
    platform: string | null;
}

const ANALYTICS_KEY = 'pwa_install_analytics';

/**
 * useInstallPrompt v17.0
 * Enhanced A2HS (Add to Home Screen) with analytics tracking.
 * - Defers install prompt for optimal timing (after user engagement)
 * - Tracks prompt → decision time for UX analytics
 * - Detects standalone mode vs browser mode
 */
export function useInstallPrompt() {
    const [canInstall, setCanInstall] = useState(false);
    const [isInstalled, setIsInstalled] = useState(false);
    const deferredPromptRef = useRef<BeforeInstallPromptEvent | null>(null);
    const analytics = useRef<InstallAnalytics>({
        promptShownAt: null,
        promptDeferredAt: null,
        installedAt: null,
        decisionMs: null,
        outcome: null,
        platform: null,
    });

    // Detect if already running in standalone (installed)
    const isStandalone =
        window.matchMedia('(display-mode: standalone)').matches ||
        (window.navigator as Navigator & { standalone?: boolean }).standalone === true;

    const saveAnalytics = useCallback(() => {
        try {
            const existing = JSON.parse(localStorage.getItem(ANALYTICS_KEY) || '[]');
            localStorage.setItem(ANALYTICS_KEY, JSON.stringify(
                [{ ...analytics.current, savedAt: new Date().toISOString() }, ...existing].slice(0, 10)
            ));
        } catch { /* silent */ }
    }, []);

    useEffect(() => {
        if (isStandalone) {
            setIsInstalled(true);
            return;
        }

        const handleBeforeInstallPrompt = (e: Event) => {
            e.preventDefault(); // Defer browser's default prompt
            deferredPromptRef.current = e as BeforeInstallPromptEvent;
            setCanInstall(true);
            analytics.current.promptDeferredAt = new Date().toISOString();

            // Log
            try {
                const logs = JSON.parse(localStorage.getItem('pwa_forensics') || '[]');
                localStorage.setItem('pwa_forensics', JSON.stringify(
                    [{ t: new Date().toISOString(), m: 'Install Prompt Deferred' }, ...logs].slice(0, 20)
                ));
            } catch { /* silent */ }
        };

        const handleAppInstalled = () => {
            setIsInstalled(true);
            setCanInstall(false);
            analytics.current.installedAt = new Date().toISOString();
            analytics.current.outcome = 'accepted';
            saveAnalytics();
            deferredPromptRef.current = null;
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        window.addEventListener('appinstalled', handleAppInstalled);

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            window.removeEventListener('appinstalled', handleAppInstalled);
        };
    }, [isStandalone, saveAnalytics]);


    const promptInstall = useCallback(async (): Promise<'accepted' | 'dismissed' | 'unavailable'> => {
        if (!deferredPromptRef.current) return 'unavailable';
        analytics.current.promptShownAt = new Date().toISOString();

        try {
            await deferredPromptRef.current.prompt();
            const { outcome, platform } = await deferredPromptRef.current.userChoice;

            if (analytics.current.promptShownAt) {
                analytics.current.decisionMs = Date.now() - new Date(analytics.current.promptShownAt).getTime();
            }
            analytics.current.outcome = outcome;
            analytics.current.platform = platform;
            saveAnalytics();

            deferredPromptRef.current = null;
            setCanInstall(false);

            if (outcome === 'accepted') setIsInstalled(true);
            return outcome;
        } catch {
            return 'unavailable';
        }
    }, [saveAnalytics]);

    return {
        canInstall,
        isInstalled,
        isStandalone,
        promptInstall,
        getAnalytics: () => analytics.current,
    };
}

import { useState, useRef } from 'react';
import { supabase } from '@/lib/supabase';
import { ThermodynamicSamplingEngine, type ThermodynamicState } from '@/lib/thermodynamicSampling';

export function useLiquidIntelligence() {
    const [loading, setLoading] = useState(false);
    const engineRef = useRef<ThermodynamicSamplingEngine | null>(null);

    // Initialize Thermodynamic Sampling Engine
    if (!engineRef.current) {
        engineRef.current = new ThermodynamicSamplingEngine({
            initialTemperature: 15.0, // High exploration
            finalTemperature: 0.05, // Precise exploitation
            coolingRate: 0.93, // Gradual cooling
            iterations: 150 // More iterations for better convergence
        });
    }

    /**
     * Compute optimal stock thresholds using Thermodynamic Sampling
     * Based on p-bit architecture and energy minimization
     */
    async function computeOptimalThresholds() {
        setLoading(true);
        try {
            // 1. Fetch optimized optimization data via RPC
            // This returns ID, Name, CurrentMin, and Velocity (90d daily average)
            const { data: optimizationData, error } = await (supabase.rpc as any)('get_product_optimization_data');

            if (error) throw error;

            // 2. Prepare products for thermodynamic optimization (rename keys to match engine expectation)
            const productsForOptimization = (optimizationData as any[]).map(prod => ({
                id: prod.id,
                name: prod.name,
                currentMin: prod.current_min,
                velocity: Number(prod.velocity)
            }));

            // 5. Run Thermodynamic Sampling (Annealing)
            const optimizedStates: ThermodynamicState[] = engineRef.current!.optimize(productsForOptimization);

            // 6. Format results for UI (merge velocity back from original products)
            const adjustments = optimizedStates.map(state => {
                const originalProduct = productsForOptimization.find(p => p.id === state.productId);
                return {
                    id: state.productId,
                    nome: state.productName,
                    old_min: state.currentMin,
                    new_min: state.proposedMin,
                    velocity: originalProduct?.velocity.toFixed(4) || '0.0000',
                    energy: state.energy.toFixed(3),
                    probability: state.probability.toFixed(3),
                    surprise: state.energy > 50 ? 'HIGH' : state.energy > 20 ? 'MEDIUM' : 'LOW'
                };
            });

            return adjustments;
        } catch (error) {
            console.error('[Thermodynamic-Sampling] Optimization Error:', error);
            return [];
        } finally {
            setLoading(false);
        }
    }

    return {
        computeOptimalThresholds,
        loading,
        engine: engineRef.current
    };
}

import { useEffect, useState, useCallback } from 'react';

/**
 * useLocalFirstState
 * Camada 3 da v22.0 SINGULARITY.
 * Sincroniza o estado da UI diretamente com o armazenamento persistente (Local-First).
 * Garante que o usuário nunca perca sua posição ou dados de formulário durante um PWA Update.
 */
export function useLocalFirstState<T>(key: string, initialValue: T) {
    // Carrega do storage no init
    const [state, setState] = useState<T>(() => {
        try {
            const saved = localStorage.getItem(`zenith_state_${key}`);
            return saved ? JSON.parse(saved) : initialValue;
        } catch {
            return initialValue;
        }
    });

    const updateState = useCallback((newValue: T | ((prev: T) => T)) => {
        setState(prev => {
            const resolvedValue = newValue instanceof Function ? newValue(prev) : newValue;

            // Persistência em background (microtask)
            queueMicrotask(() => {
                try {
                    localStorage.setItem(`zenith_state_${key}`, JSON.stringify(resolvedValue));
                } catch (e) {
                    console.warn('[LocalFirst] Storage quota exceeded or blocked.');
                }
            });

            return resolvedValue;
        });
    }, [key]);

    // Sincronização multi-aba
    useEffect(() => {
        const handleStorage = (e: StorageEvent) => {
            if (e.key === `zenith_state_${key}` && e.newValue) {
                setState(JSON.parse(e.newValue));
            }
        };
        window.addEventListener('storage', handleStorage);
        return () => window.removeEventListener('storage', handleStorage);
    }, [key]);

    return [state, updateState] as const;
}

