import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Notification {
    id: string;
    usuario_id: string | null;
    tipo: 'order' | 'promo' | 'system' | 'referral' | 'sucesso' | 'erro' | 'info';
    titulo: string;
    mensagem: string;
    dados: any;
    lida: boolean;
    acao?: any;
    created_at: string;
}

export function useNotifications() {
    const { user } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [loading, setLoading] = useState(true);

    const fetchNotifications = useCallback(async () => {
        try {
            setLoading(true);
            let query = supabase
                .from('notificacoes')
                .select('*')
                .order('created_at', { ascending: false });

            const { data, error } = await query.limit(50);

            if (error) throw error;
            if (data) {
                setNotifications(data as Notification[]);
                setUnreadCount(data.filter(n => !n.lida).length);
            }
        } catch (err) {
            console.error('Error fetching notifications:', err);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        if (!user?.id) return;
        fetchNotifications();

        let activeChannel = supabase
            .channel(`notificacoes_realtime_${user.id}_${Date.now()}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'notificacoes'
                },
                (payload) => {
                    console.log('[Realtime] Notification update:', payload.eventType);
                    if (payload.eventType === 'INSERT') {
                        const newNotif = payload.new as Notification;
                        setNotifications(prev => [newNotif, ...prev]);
                        if (!newNotif.lida) setUnreadCount(prev => prev + 1);
                    } else if (payload.eventType === 'UPDATE') {
                        const updated = payload.new as Notification;
                        setNotifications(prev => prev.map(n => n.id === updated.id ? updated : n));
                        setUnreadCount(prev => {
                            const wasRead = payload.old && (payload.old as any).lida;
                            if (!wasRead && updated.lida) return Math.max(0, prev - 1);
                            if (wasRead && !updated.lida) return prev + 1;
                            return prev;
                        });
                    } else if (payload.eventType === 'DELETE') {
                        setNotifications(prev => prev.filter(n => n.id !== payload.old.id));
                        fetchNotifications();
                    }
                }
            );

        activeChannel.subscribe((status) => {
            if (status === 'SUBSCRIBED') {
                console.log(`[Realtime] Successfully subscribed to notifications for ${user.id}`);
            } else if (status === 'TIMED_OUT' || status === 'CHANNEL_ERROR') {
                console.warn(`[Realtime] Notification channel ${status}. Consider refreshing if issues persist.`);
            }
        });

        return () => {
            if (activeChannel) {
                supabase.removeChannel(activeChannel).catch(err => {
                    if (!err?.message?.includes('closed before the connection is established')) {
                        console.warn('[Realtime] Cleanup notifications:', err);
                    }
                });
            }
        };
    }, [fetchNotifications, user?.id]);

    const markAsRead = useCallback(async (id: string) => {
        try {
            const { error } = await supabase
                .from('notificacoes')
                .update({ lida: true })
                .eq('id', id);

            if (error) throw error;
            setNotifications(prev => prev.map(n => n.id === id ? { ...n, lida: true } : n));
            setUnreadCount(prev => Math.max(0, prev - 1));
        } catch (err) {
            console.error('Error marking as read:', err);
        }
    }, []);

    const markAllAsRead = useCallback(async () => {
        try {
            const { error } = await supabase
                .from('notificacoes')
                .update({ lida: true })
                .eq('lida', false);

            if (error) throw error;
            setNotifications(prev => prev.map(n => ({ ...n, lida: true })));
            setUnreadCount(0);
            toast.success('Todas as notificações foram lidas');
        } catch (err) {
            console.error('Error marking all as read:', err);
        }
    }, []);

    const deleteNotification = useCallback(async (id: string) => {
        try {
            const { error } = await supabase
                .from('notificacoes')
                .delete()
                .eq('id', id);

            if (error) throw error;
            setNotifications(prev => prev.filter(n => n.id !== id));
            // Toast? 
        } catch (err) {
            console.error('Error deleting notification:', err);
        }
    }, []);

    return {
        notifications,
        unreadCount,
        loading,
        markAsRead,
        markAllAsRead,
        deleteNotification,
        refresh: fetchNotifications
    };
}

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';
import { useAuth } from '@/contexts/AuthContext';
import { mapOrderFromDB } from '@/lib/mappers';
import type { Order, OrderStatus, DashboardSummary } from '@/types';

export function useOrders(enabled = true, navigationKey?: string) {
  const { user, isAdmin } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [totalOrders, setTotalOrders] = useState(0);

  // Fetch orders for the logged-in user
  const fetchUserOrders = useCallback(async () => {
    if (!user || !enabled) return [];
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('marketplace_orders')
        .select(`
          *,
          items:marketplace_order_items(*)
        `)
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

      if (error) throw error;

      if (data) {
        const mappedOrders = data.map(item => mapOrderFromDB(item as any));
        setOrders(mappedOrders);
        return mappedOrders;
      }
      return [];
    } catch (err) {
      console.error('Error fetching user orders:', err);
      toast.error('Erro ao carregar seus pedidos');
      return [];
    } finally {
      setLoading(false);
    }
  }, [user, enabled]);

  // Load orders with pagination (Admin) - Optimized
  const loadOrders = useCallback(async (page = 0, pageSize = 20, statusFilter?: string) => {
    if (!enabled) return { orders: [], total: 0 };
    try {
      setLoading(true);
      let query = supabase
        .from('marketplace_orders')
        .select(`
          *,
          items:marketplace_order_items(*)
        `, { count: 'exact' })
        .order('created_at', { ascending: false })
        .range(page * pageSize, (page + 1) * pageSize - 1);

      if (statusFilter && statusFilter !== 'all') {
        query = query.eq('status', statusFilter);
      }

      const { data, error, count } = await query;

      if (error) throw error;

      if (data) {
        // Explicit casting to match Mapper expectations for joined data
        const mappedOrders = data.map(item => mapOrderFromDB(item as any));
        setOrders(mappedOrders);
        if (count !== null) setTotalOrders(count);
        return { orders: mappedOrders, total: count || 0 };
      }
      return { orders: [], total: 0 };
    } catch (err) {
      console.error('Error loading orders:', err);
      toast.error('Erro ao carregar pedidos');
      return { orders: [], total: 0 };
    } finally {
      setLoading(false);
    }
  }, [enabled]);

  // Wrapper for backward compatibility
  const fetchOrders = useCallback(async (limitCount?: number) => {
    return loadOrders(0, limitCount || 50);
  }, [loadOrders]);

  // Realtime subscription for orders
  useEffect(() => {
    if (!enabled || !user) return; // Only connect if enabled AND user exists

    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
    let retryCount = 0;
    let isSubscribed = false;
    let isUnmounting = false;
    let reconnectTimeout: ReturnType<typeof setTimeout>;

    // Track if this effect run was triggered by a navigation change
    if (navigationKey) {
      console.log(`[Realtime] Reset triggered by navigation: ${navigationKey}`);
    }

    const setupRealtime = () => {
      if (isUnmounting) return;

      // Cleanup previous channel if it exists
      if (activeChannel) {
        console.log(`[Realtime] Cleaning up previous channel for ${user.id}`);
        const channelToClose = activeChannel; // Closure safety
        supabase.removeChannel(channelToClose).catch(err => {
          if (!err?.message?.includes('closed before the connection is established')) {
            console.warn('[Realtime] Cleanup warning:', err);
          }
        });
        activeChannel = null;
      }

      console.log(`[Realtime] Subscribing to orders for ${user.id}...`);

      const channel = supabase
        .channel(`orders-${user.id}-${Date.now()}`) // Added timestamp to ensure uniquely identified channel instance
        .on(
          'postgres_changes',
          {
            event: '*',
            schema: 'public',
            table: 'marketplace_orders'
          },
          async (payload) => {
            const newId = (payload.new as any)?.id;
            const oldId = (payload.old as any)?.id;

            console.log('[Realtime] Change detected:', payload.eventType, newId || oldId);

            if (payload.eventType === 'INSERT' && payload.new && 'id' in payload.new) {
              const { data, error } = await supabase
                .from('marketplace_orders')
                .select('*, items:marketplace_order_items(*)')
                .eq('id', (payload.new as any).id)
                .single();

              if (!error && data) {
                // Double check if we should show this (Admin or owner)
                // We use the current state values which might have changed since subscription
                if (!isAdmin && data.user_id !== user.id) return;

                const newOrder = mapOrderFromDB(data as any);
                setOrders(prev => {
                  if (prev.some(o => o.id === newOrder.id)) return prev;
                  return [newOrder, ...prev];
                });
                toast.info(`Novo pedido recebido! #${newOrder.id.slice(0, 8)}`);
              }
            } else if (payload.eventType === 'UPDATE') {
              const updatedOrder = payload.new as any;
              if (!updatedOrder.id) return;

              setOrders(prev => prev.map(o =>
                o.id === updatedOrder.id ? { ...o, status: updatedOrder.status, trackingCode: updatedOrder.tracking_code } : o
              ));
            } else if (payload.eventType === 'DELETE') {
              if (oldId) {
                setOrders(prev => prev.filter(o => o.id !== oldId));
              }
            }
          }
        );

      activeChannel = channel;

      channel.subscribe((status, err) => {
        if (isUnmounting || activeChannel !== channel) return;

        if (status === 'SUBSCRIBED') {
          isSubscribed = true;
          retryCount = 0;
          console.log(`[Realtime] Successfully subscribed to orders for ${user.id}`);
        } else if (status === 'CHANNEL_ERROR') {
          isSubscribed = false;
          console.error('[Realtime] Channel error:', err);
          handleReconnect();
        } else if (status === 'TIMED_OUT') {
          isSubscribed = false;
          console.warn('[Realtime] Subscription timed out. Retrying with jitter...');
          // Small jittered delay for timeouts to prevent simultaneous burst of reconnects
          const jitter = Math.random() * 2000;
          setTimeout(() => handleReconnect(), jitter);
        } else if (status === 'CLOSED') {
          isSubscribed = false;
          console.info('[Realtime] Subscription closed.');
          handleReconnect();
        }
      });
    };

    const handleReconnect = () => {
      if (isUnmounting) return;

      const EXTENDED_MAX_RETRIES = 15;
      if (retryCount >= EXTENDED_MAX_RETRIES) {
        console.error('[Realtime] Max retries reached.');
        return;
      }

      // Exponential backoff: 1s, 1.5s, 2.25s, 3.37s... up to 30s
      const timeout = Math.min(1000 * Math.pow(1.5, retryCount), 30000);
      retryCount++;

      console.log(`[Realtime] Reconnect attempt ${retryCount}/${EXTENDED_MAX_RETRIES} in ${Math.round(timeout / 1000)}s`);

      clearTimeout(reconnectTimeout);
      reconnectTimeout = setTimeout(async () => {
        if (isUnmounting) return;
        try {
          // Always sync latest data before trying to resubscribe to avoid missing updates during downtime
          await fetchUserOrders();
          if (!isUnmounting) setupRealtime();
        } catch (err) {
          console.warn('[Realtime] Sync before reconnect failed, retrying setup anyway', err);
          if (!isUnmounting) setupRealtime();
        }
      }, timeout);
    };

    setupRealtime();


    // Handle visibility changes (PWA moving to background/foreground)
    let visibilityTimeout: ReturnType<typeof setTimeout>;
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        // Debounce foregrounding events to prevent sync storms
        clearTimeout(visibilityTimeout);
        visibilityTimeout = setTimeout(() => {
          if (!isSubscribed && !isUnmounting) {
            console.log('[Realtime] App foregrounded, channel not subscribed. Forcing reconnect...');
            retryCount = 0; // Reset
            clearTimeout(reconnectTimeout);
            // Fetch latest data to heal UI State
            fetchUserOrders().then(() => setupRealtime());
          }
        }, 500); // Wait 500ms before aggressively reconnecting
      } else {
        // App went to background
        // Supabase often keeps it alive, but if the OS kills the web socket, 
        // the 'CLOSED' or 'CHANNEL_ERROR' event will trigger the retry loop later.
      }
    };

    // Handle online/offline events
    let onlineTimeout: ReturnType<typeof setTimeout>;
    const handleOnline = () => {
      console.log('[Realtime] Network online. Checking connection...');
      // Debounce network changes similarly
      clearTimeout(onlineTimeout);
      onlineTimeout = setTimeout(() => {
        if (!isSubscribed && !isUnmounting) {
          retryCount = 0;
          clearTimeout(reconnectTimeout);
          fetchUserOrders().then(() => setupRealtime());
        }
      }, 500);
    };

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('online', handleOnline);

    return () => {
      isUnmounting = true;
      clearTimeout(reconnectTimeout);
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('online', handleOnline);
      if (activeChannel) {
        supabase.removeChannel(activeChannel).catch(err => {
          if (!err?.message?.includes('closed before the connection is established')) {
            console.warn('Realtime cleanup orders:', err);
          }
        });
      }
    };
  }, [enabled, user, isAdmin, fetchUserOrders, navigationKey]);

  const updateOrderTracking = useCallback(async (orderId: string, trackingCode: string) => {
    try {
      const { error } = await supabase
        .from('marketplace_orders')
        .update({ tracking_code: trackingCode })
        .eq('id', orderId);

      if (error) throw error;

      setOrders(prev => prev.map(order =>
        order.id === orderId ? { ...order, trackingCode } : order
      ));
      toast.success('Código de rastreio atualizado!');
    } catch (err) {
      console.error('Error updating tracking code:', err);
      toast.error('Erro ao atualizar rastreio');
      throw err;
    }
  }, []);

  const updateOrderStatus = useCallback(async (orderId: string, status: OrderStatus, notes?: string, silent: boolean = false) => {
    try {
      const { error } = await (supabase.rpc as any)('update_order_status_atomic', {
        p_order_id: orderId,
        p_new_status: status,
        p_notes: notes || null,
        p_silent: silent
      });

      if (error) throw error;

      setOrders(prev => prev.map(order =>
        order.id === orderId ? { ...order, status } : order
      ));
      if (!silent) toast.success('Status atualizado com sucesso');
    } catch (err: any) {
      console.error('Error updating status:', err);
      if (!silent) toast.error(err.message || 'Erro ao atualizar status');
      throw err;
    }
  }, []);

  const fetchOrderHistory = useCallback(async (orderId: string) => {
    try {
      // Cast to any because table might be missing in generated types
      const { data, error } = await (supabase as any)
        .from('marketplace_order_history')
        .select('*')
        .eq('order_id', orderId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data;
    } catch (err) {
      console.error('Error fetching order history:', err);
      return [];
    }
  }, []);

  const fetchOrdersByWhatsapp = useCallback(async (whatsapp: string): Promise<Order[]> => {
    try {
      const { data, error } = await (supabase.rpc as any)('get_orders_by_whatsapp', {
        phone_number: whatsapp
      });

      if (error) throw error;
      return (data as any[] || []).map(item => mapOrderFromDB(item));
    } catch (err) {
      console.error('Error fetching orders by whatsapp:', err);
      toast.error('Erro ao buscar pedidos por WhatsApp');
      return [];
    }
  }, []);

  const fetchDashboardSummary = useCallback(async (): Promise<DashboardSummary | null> => {
    try {
      const { data } = await (supabase.rpc as any)('get_admin_analytics_v2');
      if (data) {
        return data as DashboardSummary;
      }
      return null;
    } catch (err) {
      console.error('Error fetching dashboard summary:', err);
      return null;
    }
  }, []);

  const createOrder = useCallback(async (orderData: Omit<Order, 'id' | 'createdAt' | 'updatedAt'>) => {
    try {
      const { data: orderId, error } = await (supabase.rpc as any)('create_marketplace_order', {
        p_user_id: user?.id || null,
        p_customer_name: orderData.customer.name,
        p_customer_data: orderData.customer,
        p_total: orderData.total,
        p_subtotal: orderData.subtotal,
        p_shipping: orderData.shipping,
        p_discount: orderData.discount,
        p_payment_method: orderData.paymentMethod,
        p_coupon_code: orderData.couponCode || null,
        p_items: orderData.items.map(item => ({
          product_id: item.productId,
          variant_id: item.variantId,
          product_name: item.name,
          quantity: item.quantity,
          price: item.price,
          image_url: item.image
        }))
      });

      if (error) throw error;

      return {
        ...orderData,
        id: (orderId as unknown) as string,
        status: 'new' as const,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      };
    } catch (err: any) {
      console.error('Error creating order:', err);
      toast.error(err.message || 'Erro ao processar pedido');
      throw err;
    }
  }, [user]);

  return {
    orders,
    loading,
    isLoaded: !loading,
    totalOrders,
    fetchUserOrders,
    loadOrders,     // New pagination function
    fetchOrders,    // Legacy alias
    updateOrderStatus,
    updateOrderTracking,
    fetchOrdersByWhatsapp,
    createOrder,
    fetchDashboardSummary,
    fetchOrderHistory
  };
}

/* eslint-disable @typescript-eslint/no-explicit-any */
/* eslint-disable @typescript-eslint/no-unused-vars */
import { useState, useCallback, useEffect, useRef } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { mapProductFromDB } from '@/lib/mappers';
import type { Product, ProductVariant } from '@/types';

export function useProducts({ autoFetch = true } = {}) {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(autoFetch);
  const { user } = useAuth();
  const lastLoadId = useRef(0);

  const isFetchingRef = useRef(false);
  const hasFetchedRef = useRef(false);
  const fetchProducts = useCallback(async () => {
    if (isFetchingRef.current) return;
    const loadId = ++lastLoadId.current;
    setLoading(true);
    isFetchingRef.current = true;
    console.log('[Products] Initiating fetch...');
    let attempts = 0;
    const maxRetries = 3;

    while (attempts < maxRetries) {
      try {
        const { data, error } = await supabase
          .from('produtos')
          .select(`
            *,
            product_variants(*)
          `)
          .eq('ativo', true)
          .order('data_cadastro', { ascending: false });

        if (error) {
          console.error('[useProducts] Error fetching products:', error);

          attempts++;
          if (attempts === maxRetries) {
            toast.error('Conexão indisponível ou recusada. O catálogo não pôde ser carregado.');
            setProducts([]);
            setLoading(false); // Ensure loading is false on final failure
            return;
          }
          await new Promise(resolve => setTimeout(resolve, 1000 * attempts));
          continue; // Retry
        }

        if (data) {
          console.log(`[Products] API success: Received ${data.length} rows from Supabase.`);
          if (data.length === 0) {
            console.warn('[Products] Database returned 0 active products. Check RLS or "ativo" flag.');
          }
          const mappedProducts = data.map(item => mapProductFromDB(item as any));
          console.log(`[Products] Mapping complete: ${mappedProducts.length} items ready for React.`);

          if (loadId !== lastLoadId.current) {
            isFetchingRef.current = false;
            return;
          }
          setProducts(mappedProducts);
          setLoading(false);
          isFetchingRef.current = false;

          // Debugging hydration
          setTimeout(() => {
            console.log('[Products] Hydration Verification: React State "products" length is', mappedProducts.length);
          }, 100);
          return;
        }
      } catch (err: any) {
        attempts++;
        console.error(`[Products] Error (attempt ${attempts}/${maxRetries}):`, err.message);

        if (loadId !== lastLoadId.current) {
          isFetchingRef.current = false;
          return;
        }
        if (attempts === maxRetries) {
          toast.error('Erro ao carregar produtos. Verifique sua conexão.');
          isFetchingRef.current = false;
          setLoading(false);
        } else {
          await new Promise(resolve => setTimeout(resolve, 1000 * attempts));
        }
      }
    }
    isFetchingRef.current = false;
    hasFetchedRef.current = true;
    setLoading(false); // Safeguard: ensure loading is false if we exit the loop
  }, [user?.id]);

  // Load products with pagination and filtering (Admin focus)
  const loadProducts = useCallback(async (page = 0, pageSize = 10, filters?: any) => {
    if (isFetchingRef.current) return null;
    const loadId = ++lastLoadId.current;
    try {
      setLoading(true);
      isFetchingRef.current = true;
      let query = supabase
        .from('produtos')
        .select(`
          *,
          product_variants(*)
        `, { count: 'exact' });

      // Apply Search
      if (filters?.search) {
        query = query.ilike('nome', `%${filters.search}%`);
      }

      // Apply Status
      if (filters?.status === 'active') {
        query = query.eq('ativo', true);
      } else if (filters?.status === 'inactive') {
        query = query.eq('ativo', false);
      }

      // Apply Stock
      if (filters?.stock === 'low') {
        query = query.lte('estoque', 5);
      }

      // Pagination
      const from = page * pageSize;
      const to = from + pageSize - 1;

      const { data, error, count } = await query
        .order('data_cadastro', { ascending: false })
        .range(from, to);

      if (error) throw error;

      if (data) {
        if (loadId !== lastLoadId.current) return null;
        const mappedProducts = (data as any[]).map((item: any) => mapProductFromDB(item));
        setProducts(mappedProducts);
        return {
          products: mappedProducts,
          total: count || 0
        };
      }
      return { products: [], total: 0 };
    } catch (err) {
      console.error('Error loading products:', err);
      toast.error('Erro ao listar produtos');
      return null;
    } finally {
      isFetchingRef.current = false;
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (autoFetch && !hasFetchedRef.current && !isFetchingRef.current) {
      fetchProducts();
    }
  }, [autoFetch, fetchProducts]);

  const getProductById = useCallback((id: string) => {
    return products.find(p => p.id === id);
  }, [products]);

  const addProduct = async (productData: Omit<Product, 'id' | 'createdAt' | 'rating' | 'reviewCount' | 'variants'>) => {
    try {
      const { data, error } = await supabase
        .from('produtos')
        .insert({
          nome: productData.name,
          descricao: productData.description,
          preco_venda: productData.price,
          custo: productData.costPrice,
          preco_original: productData.originalPrice,
          estoque: productData.stock,
          categoria: productData.category,
          imagem_url: productData.images[0] || null, // Main image
          imagem_urls: productData.images, // All images
          ativo: productData.isActive,
          is_bestseller: productData.isBestseller,
          frete_gratis: productData.freeShipping,
          meta_title: productData.metaTitle,
          meta_description: productData.metaDescription,
          tags: productData.tags || [],
          sold: 0
        } as any)
        .select()
        .single();

      if (error) throw error;

      if (data) {
        const newProduct = mapProductFromDB(data as any);
        setProducts((prev: any[]) => [newProduct, ...prev]);
        toast.success('Produto cadastrado com sucesso!');
        return newProduct;
      }
    } catch (err: any) {
      console.error('Error adding product:', err);
      toast.error('Erro ao cadastrar produto');
      throw err;
    }
  };

  const updateProduct = async (id: string, updates: Partial<Product>) => {
    try {
      const dbUpdates: any = {};
      if (updates.name !== undefined) dbUpdates.nome = updates.name;
      if (updates.description !== undefined) dbUpdates.descricao = updates.description;
      if (updates.price !== undefined) dbUpdates.preco_venda = updates.price;
      if (updates.costPrice !== undefined) dbUpdates.custo = updates.costPrice;
      if (updates.originalPrice !== undefined) dbUpdates.preco_original = updates.originalPrice;
      if (updates.stock !== undefined) dbUpdates.estoque = updates.stock;
      if (updates.category !== undefined) dbUpdates.categoria = updates.category;
      if (updates.images !== undefined) {
        dbUpdates.imagem_urls = updates.images;
        dbUpdates.imagem_url = updates.images[0] || null;
      }
      if (updates.isActive !== undefined) dbUpdates.ativo = updates.isActive;
      if (updates.isBestseller !== undefined) dbUpdates.is_bestseller = updates.isBestseller;
      if (updates.freeShipping !== undefined) dbUpdates.frete_gratis = updates.freeShipping;
      if (updates.metaTitle !== undefined) dbUpdates.meta_title = updates.metaTitle;
      if (updates.metaDescription !== undefined) dbUpdates.meta_description = updates.metaDescription;
      if (updates.tags !== undefined) dbUpdates.tags = updates.tags;
      if (updates.sold !== undefined) dbUpdates.sold = updates.sold;

      const { data, error } = await supabase
        .from('produtos')
        .update(dbUpdates)
        .eq('id', id)
        .select(`
          *,
          product_variants(*)
        `)
        .single();

      if (error) throw error;

      if (data) {
        const updatedProduct = mapProductFromDB(data as any);
        setProducts((prev: any[]) => prev.map((p: any) => p.id === id ? updatedProduct : p));
        toast.success('Produto atualizado!');
        return updatedProduct;
      }
    } catch (err: any) {
      console.error('Error updating product:', err);
      toast.error('Erro ao atualizar produto');
      throw err;
    }
  };

  const deleteProduct = async (id: string) => {
    try {
      const { error } = await supabase
        .from('produtos')
        .delete()
        .eq('id', id);

      if (error) throw error;

      setProducts((prev: any[]) => prev.filter((p: any) => p.id !== id));
      toast.success('Produto removido');
      return true;
    } catch (err: any) {
      console.error('Error deleting product:', err);
      toast.error('Erro ao excluir produto');
      return false;
    }
  };

  // Bulk Delete
  const deleteProducts = async (ids: string[]) => {
    try {
      const { error } = await supabase
        .from('produtos')
        .delete()
        .in('id', ids);

      if (error) throw error;

      setProducts((prev: any[]) => prev.filter((p: any) => !ids.includes(p.id)));
      toast.success(`${ids.length} produtos removidos`);
      return true;
    } catch (err) {
      console.error('Error deleting products:', err);
      toast.error('Erro ao excluir produtos');
      return false;
    }
  };

  // Bulk Status Update
  const updateProductsStatus = async (ids: string[], isActive: boolean) => {
    try {
      const { error } = await supabase
        .from('produtos')
        .update({ ativo: isActive })
        .in('id', ids);

      if (error) throw error;

      setProducts((prev: any[]) => prev.map((p: any) =>
        ids.includes(p.id) ? { ...p, isActive } : p
      ));
      toast.success('Status atualizado');
      return true;
    } catch (err) {
      console.error('Error updating products status:', err);
      toast.error('Erro ao atualizar status');
      return false;
    }
  };

  const uploadProductImages = async (files: File[]) => {
    const urls: string[] = [];

    for (const file of files) {
      try {
        const fileExt = file.name.split('.').pop();
        const fileName = `${crypto.randomUUID()}.${fileExt}`;
        const filePath = `${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('products')
          .upload(filePath, file);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('products')
          .getPublicUrl(filePath);

        urls.push(publicUrl);
      } catch (err) {
        console.error('Error uploading file:', err);
        toast.error(`Erro ao enviar imagem ${file.name}`);
      }
    }

    return urls;
  };

  // Recommendations Logic - Server Side RPC
