        p_product_id: productId,
        p_limit: limit
      });

      if (error) throw error;

      // Map database results to application model
      return data ? (data as any[]).map((item: any) => mapProductFromDB(item)) : [];
    } catch (err) {
      console.error('Error fetching recommendations:', err);
      // Fallback to local filter if RPC fails (failsafe)
      return products
        .filter(p => p.id !== productId && p.isActive && p.stock > 0)
        .slice(0, limit);
    }
  }, [products]);

  // Fetch single product (Optimized for Edit Form)
  const fetchProduct = useCallback(async (id: string) => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('produtos')
        .select(`
          *,
          product_variants(*)
        `)
        .eq('id', id)
        .single();

      if (error) throw error;

      if (data) {
        return mapProductFromDB(data as any);
      }
      return null;
    } catch (err) {
      console.error('Error fetching product:', err);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  // Deprecated: Synchronous version for backward compatibility
  // Prioritize fetchRecommendations
  const getRecommendations = (productId: string, limit = 4) => {
    return products
      .filter(p => p.id !== productId && p.isActive && p.stock > 0)
      .slice(0, limit);
  };

  const getCartRecommendations = (cartProductIds: string[], limit = 4) => {
    return products
      .filter(p => !cartProductIds.includes(p.id) && p.isActive && p.stock > 0)
      .slice(0, limit);
  };

  // Track Recommendation Click
  const trackRecommendationClick = (_productId: string, _source: string) => {
    // Analytics ping could be restored here if needed
  };



  // Variant Management
  const addVariant = async (variantData: Omit<ProductVariant, 'id'>) => {
    try {
      const { data, error } = await supabase
        .from('product_variants')
        .insert({
          product_id: variantData.productId,
          name: variantData.name,
          value: variantData.value,
          sku: variantData.sku,
          stock_increment: variantData.stockIncrement,
          price_override: variantData.priceOverride,
          active: variantData.active
        } as any)
        .select()
        .single();

      if (error) throw error;

      if (data) {
        const newVariant = {
          id: data.id,
          productId: data.product_id,
          name: data.name,
          value: data.value,
          stockIncrement: data.stock_increment,
          priceOverride: data.price_override,
          active: data.active,
          sku: data.sku
        } as ProductVariant;

        // Update local product state to include this new variant
        setProducts((prev: any[]) => prev.map((p: any) => {
          if (p.id === variantData.productId) {
            return {
              ...p,
              variants: [...(p.variants || []), newVariant]
            };
          }
          return p;
        }));

        toast.success('Variante adicionada');
        return newVariant;
      }
    } catch (err) {
      console.error('Error adding variant:', err);
      toast.error('Erro ao adicionar variante');
      throw err;
    }
  };

  const updateVariant = async (id: string, updates: Partial<ProductVariant>) => {
    try {
      const dbUpdates: any = {};
      if (updates.name !== undefined) dbUpdates.name = updates.name;
      if (updates.value !== undefined) dbUpdates.value = updates.value;
      if (updates.sku !== undefined) dbUpdates.sku = updates.sku;
      if (updates.stockIncrement !== undefined) dbUpdates.stock_increment = updates.stockIncrement;
      if (updates.priceOverride !== undefined) dbUpdates.price_override = updates.priceOverride;
      if (updates.active !== undefined) dbUpdates.active = updates.active;

      const { data, error } = await supabase
        .from('product_variants')
        .update(dbUpdates)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;

      if (data) {
        // Update local state
        setProducts((prev: any[]) => prev.map((p: any) => {
          if (p.variants?.some((v: any) => v.id === id)) {
            return {
              ...p,
              variants: p.variants.map((v: any) => v.id === id ? { ...v, ...updates } : v)
            };
          }
          return p;
        }));
        toast.success('Variante atualizada');
      }
    } catch (err) {
      console.error('Error updating variant:', err);
      toast.error('Erro ao atualizar variante');
      throw err;
    }
  };

  const deleteVariant = async (id: string) => {
    try {
      const { error } = await supabase
        .from('product_variants')
        .delete()
        .eq('id', id);

      if (error) throw error;

      setProducts(prev => prev.map(p => ({
        ...p,
        variants: p.variants?.filter(v => v.id !== id) || []
      })));
      toast.success('Variante removida');
    } catch (err) {
      console.error('Error deleting variant:', err);
      toast.error('Erro ao remover variante');
      throw err;
    }
  };

  return {
    products,
    loading,
    isLoaded: !loading, // Derived property for backward compatibility
    fetchProducts,
    loadProducts,
    fetchAdminProducts: loadProducts, // Alias for backward compatibility if needed
    getProductById,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteProducts,
    updateProductsStatus,
    fetchRecommendations,
    getRecommendations,
    getCartRecommendations,
    uploadProductImages,
    trackRecommendationClick,
    addVariant,
    updateVariant,
    deleteVariant,
    fetchProduct
  };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';

export function usePushNotifications() {
    const [subscription, setSubscription] = useState<PushSubscription | null>(null);
    const [isSupported, setIsSupported] = useState(false);
    const [permission, setPermission] = useState<NotificationPermission>('default');

    useEffect(() => {
        const checkSupport = async () => {
            const supported = 'serviceWorker' in navigator && 'PushManager' in window;
            setIsSupported(supported);

            if (supported) {
                setPermission(Notification.permission);
                const registration = await navigator.serviceWorker.ready;
                const sub = await registration.pushManager.getSubscription();
                setSubscription(sub);
            }
        };

        checkSupport();
    }, []);

    const subscribe = useCallback(async () => {
        if (!isSupported) return;

        try {
            // Get VAPID public key from env or use a default one for dev
            const vapidPublicKey = import.meta.env.VITE_VAPID_PUBLIC_KEY;

            if (!vapidPublicKey) {
                console.warn('VAPID Public Key not found in environment');
                return;
            }

            const result = await Notification.requestPermission();
            setPermission(result);

            if (result !== 'granted') {
                throw new Error('Permissão de notificação negada');
            }

            const registration = await navigator.serviceWorker.ready;

            // Convert VAPID key from base64 to Uint8Array
            const padding = '='.repeat((4 - vapidPublicKey.length % 4) % 4);
            const base64 = (vapidPublicKey + padding).replace(/-/g, '+').replace(/_/g, '/');
            const rawData = window.atob(base64);
            const outputArray = new Uint8Array(rawData.length);
            for (let i = 0; i < rawData.length; ++i) {
                outputArray[i] = rawData.charCodeAt(i);
            }

            const newSubscription = await registration.pushManager.subscribe({
                userVisibleOnly: true,
                applicationServerKey: outputArray
            });

            // Save to Supabase
            const { data: { user } } = await supabase.auth.getUser();
            const subJSON = newSubscription.toJSON();

            const { error } = await (supabase
                .from('push_subscriptions' as any) as any)
                .upsert({
                    endpoint: subJSON.endpoint,
                    p256dh: subJSON.keys?.p256dh,
                    auth: subJSON.keys?.auth,
                    user_id: user?.id || null
                }, { onConflict: 'endpoint' });

            if (error) throw error;

            setSubscription(newSubscription);
            toast.success('Inscrição realizada com sucesso!');
            return newSubscription;
        } catch (error: any) {
            console.error('Error subscribing to push:', error);
            toast.error(error.message || 'Erro ao se inscrever para notificações');
            throw error;
        }
    }, [isSupported]);

    const unsubscribe = useCallback(async () => {
        if (!subscription) return;

        try {
            await subscription.unsubscribe();

            // Remove from Supabase
            const { error } = await (supabase
                .from('push_subscriptions' as any) as any)
                .delete()
                .eq('endpoint', subscription.endpoint);

            if (error) throw error;

            setSubscription(null);
            toast.success('Você não receberá mais notificações.');
        } catch (error) {
            console.error('Error unsubscribing:', error);
            toast.error('Erro ao cancelar inscrição');
        }
    }, [subscription]);

    return {
        subscription,
        isSupported,
        permission,
        subscribe,
        unsubscribe
    };
}

import { useState, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';

export interface Question {
    id: string;
    userId: string;
    productId: string;
    productName?: string;
    productImage?: string;
    customerName: string;
    question: string;
    createdAt: string;
    isVerified?: boolean;
    answers: Answer[];
}

export interface Answer {
    id: string;
    questionId: string;
    answer: string;
    createdAt: string;
    role?: string;
}

export function useQuestions() {
    const [questions, setQuestions] = useState<Question[]>([]);
    const [loading, setLoading] = useState(false);

    const getQuestionsByProduct = useCallback(async (productId: string) => {
        try {
            setLoading(true);
            const { data, error } = await supabase
                .from('questions' as any)
                .select(`
          *,
          user:profiles(full_name),
          product:produtos(nome, imagem_url),
          answers:answers(*)
        `)
                .eq('product_id', productId)
                .order('created_at', { ascending: false });

            if (error) throw error;
            if (!data) return;

            // Fetch verified status for these users/product
            const userIds = data.map((q: any) => q.user_id);
            const { data: orders, error: ordersError } = await supabase
                .from('marketplace_orders')
                .select('user_id, status, order_items!inner(product_id)')
                .in('user_id', userIds)
                .eq('status', 'delivered')
                .eq('order_items.product_id', productId);

            if (ordersError) {
                console.error('Error fetching verified status:', ordersError);
            }

            const verifiedUsers = new Set(orders?.map(o => o.user_id) || []);

            const formattedQuestions: Question[] = data.map((item: any) => ({
                id: item.id,
                userId: item.user_id,
                productId: item.product_id,
                productName: item.product?.nome,
                productImage: item.product?.imagem_url,
                customerName: item.user?.full_name || 'Usuário Anônimo',
                question: item.question,
                createdAt: item.created_at,
                isVerified: verifiedUsers.has(item.user_id),
                answers: (item.answers || []).map((ans: any) => ({
                    id: ans.id,
                    questionId: ans.question_id,
                    answer: ans.answer,
                    createdAt: ans.created_at,
                })).sort((a: any, b: any) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
            }));

            setQuestions(formattedQuestions);
        } catch (error: any) {
            console.error('Error fetching questions:', error);
            toast.error('Erro ao carregar perguntas.');
        } finally {
            setLoading(false);
        }
    }, []);

    const addQuestion = useCallback(async (question: { productId: string, question: string }) => {
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                toast.error('Você precisa estar logado para perguntar.');
                return null;
            }

            const { data, error } = await supabase
                .from('questions' as any)
                .insert({
                    product_id: question.productId,
                    user_id: user.id,
                    question: question.question,
                })
                .select()
                .single();

            if (error) throw error;

            toast.success('Pergunta enviada com sucesso!');
            await getQuestionsByProduct(question.productId);
            return data;
        } catch (error: any) {
            console.error('Error adding question:', error);
            toast.error('Erro ao enviar pergunta.');
            return null;
        }
    }, [getQuestionsByProduct]);

    const addAnswer = useCallback(async (answer: { questionId: string, answer: string }) => {
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                toast.error('Login necessário.');
                return false;
            }

            // Execute Atomic Answer & Log via RPC
            const { error } = await (supabase.rpc as any)('answer_question_atomic', {
                p_question_id: answer.questionId,
                p_answer: answer.answer,
                p_admin_id: user.id
            });

            if (error) throw error;
            toast.success('Resposta enviada!');
            return true;
        } catch (err: any) {
            console.error(err);
            toast.error("Erro ao responder");
            return false;
        }
    }, []);

    const getAllQuestions = useCallback(async (page: number = 0, pageSize: number = 20, filter: 'all' | 'pending' = 'all') => {
        try {
            setLoading(true);
            let query = supabase
                .from('questions' as any)
                .select(`
                  *,
                  user:profiles(full_name),
                  product:produtos(nome, imagem_url),
                  answers:answers(*)
                `, { count: 'exact' });

            if (filter === 'pending') {
                // Return questions that have no answers. 
                // Using .is('answers.id', null) with a LEFT JOIN (default) filters for questions with zero answers.
                query = query.is('answers.id', null);
            }

            const { data, error, count } = await query
                .order('created_at', { ascending: false })
                .range(page * pageSize, (page + 1) * pageSize - 1);

            if (error) throw error;

            const formatted: Question[] = (data || []).map((item: any) => ({
                id: item.id,
                userId: item.user_id,
                productId: item.product_id,
                productName: item.product?.nome || 'Produto removido',
                productImage: item.product?.imagem_url,
                customerName: item.user?.full_name || 'Usuário Anônimo',
                question: item.question,
                createdAt: item.created_at,
                answers: (item.answers || []).map((ans: any) => ({
                    id: ans.id,
                    questionId: ans.question_id,
                    answer: ans.answer,
                    createdAt: ans.created_at,
                })).sort((a: any, b: any) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
            }));

            setQuestions(formatted);
            return { questions: formatted, total: count || 0 };
        } catch (error: any) {
            console.error('Error fetching all questions:', error);
            toast.error('Erro ao carregar perguntas.');
            return { questions: [], total: 0 };
        } finally {
            setLoading(false);
        }
    }, []);

    const deleteQuestion = useCallback(async (questionId: string) => {
        try {
            const { error } = await supabase
                .from('questions' as any)
                .delete()
                .eq('id', questionId);

            if (error) throw error;
            setQuestions(prev => prev.filter(q => q.id !== questionId));
            toast.success('Pergunta removida.');
        } catch (error) {
            console.error('Error deleting question:', error);
            toast.error('Erro ao remover pergunta.');
        }
    }, []);

    const subscribeToQuestions = useCallback((productId?: string) => {
        const channelId = productId ? `questions_prod_${productId}_${Date.now()}` : `questions_all_${Date.now()}`;
        const channel = supabase
            .channel(channelId)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'questions',
                    ...(productId ? { filter: `product_id=eq.${productId}` } : {})
                },
                () => {
                    console.log('[Realtime] Question change');
                    if (productId) {
                        getQuestionsByProduct(productId);
                    } else {
                        getAllQuestions();
                    }
                }
            )
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'answers'
                },
                () => {
                    console.log('[Realtime] Answer change');
                    if (productId) {
                        getQuestionsByProduct(productId);
                    } else {
                        getAllQuestions();
                    }
                }
            );

        channel.subscribe((status) => {
            if (status === 'SUBSCRIBED') {
                console.log(`[Realtime] Active: ${channelId}`);
            }
        });

        return () => {
            if (channel) {
                supabase.removeChannel(channel).catch(err => {
                    if (!err?.message?.includes('closed before the connection is established')) {
                        console.warn('[Realtime] Cleanup questions:', err);
                    }
                });
            }
        };
    }, [getQuestionsByProduct, getAllQuestions]);

    return {
        questions,
        loading,
        getQuestionsByProduct,
        getAllQuestions,
        addQuestion,
        addAnswer,
        deleteQuestion,
        subscribeToQuestions
    };
}

