import { useState, useEffect, useCallback } from 'react';
import { logForensic } from '@/lib/forensicsDB';

interface StorageEstimate {
    quota: number;       // total available storage in bytes
    usage: number;       // bytes used
    usagePercent: number; // percentage used (0-100)
    quotaMB: number;     // quota in MB (rounded)
    usageMB: number;     // usage in MB (rounded)
    isPressured: boolean; // true if > 80% full
}

const EMPTY: StorageEstimate = {
    quota: 0, usage: 0, usagePercent: 0,
    quotaMB: 0, usageMB: 0, isPressured: false,
};

/**
 * useStorageEstimate v19.0
 * StorageManager.estimate() — real-time storage quota monitoring.
 * Shows how much of the device's storage the PWA is using.
 * Warns when approaching quota limits.
 */
export function useStorageEstimate() {
    const [estimate, setEstimate] = useState<StorageEstimate>(EMPTY);
    const [isLoading, setIsLoading] = useState(true);

    const refresh = useCallback(async () => {
        if (!navigator.storage?.estimate) { setIsLoading(false); return; }
        try {
            const result = await navigator.storage.estimate();
            const quota = result.quota ?? 0;
            const usage = result.usage ?? 0;
            const usagePercent = quota > 0 ? Math.round((usage / quota) * 100) : 0;
            const isPressured = usagePercent > 80;

            const est: StorageEstimate = {
                quota,
                usage,
                usagePercent,
                quotaMB: Math.round(quota / 1024 / 1024),
                usageMB: Math.round(usage / 1024 / 1024 * 10) / 10,
                isPressured,
            };
            setEstimate(est);
            setIsLoading(false);

            if (isPressured) {
                void logForensic({
                    t: new Date().toISOString(),
                    m: 'Storage Pressure Detected',
                    d: { usagePercent, usageMB: est.usageMB, quotaMB: est.quotaMB },
                    level: 'warn',
                    source: 'app',
                });
            }
        } catch { setIsLoading(false); }
    }, []);

    useEffect(() => {
        refresh();
        // Re-check every 5 minutes
        const interval = setInterval(refresh, 5 * 60 * 1000);
        return () => clearInterval(interval);
    }, [refresh]);

    return { estimate, isLoading, refresh };
}

import { useState, useCallback, useEffect } from 'react';
import type { StoreConfig } from '@/types';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

const defaultConfig: StoreConfig = {
  freeShippingMin: 100,
  shippingFee: 15,
  whatsappNumber: '34999999999',
  shareText: 'Olha que achei na IKCOUS!',
  businessHours: 'Seg-Sáb: 9h às 18h',
  enableReviews: true,
  enableCoupons: true,
  primaryColor: '#000000',
  themeMode: 'light',
  realTimeSalesAlerts: true,
  pushMarketingEnabled: false
};

export function useStoreConfig() {
  const [config, setConfig] = useState<StoreConfig>(defaultConfig);
  const [isLoaded, setIsLoaded] = useState(false);

  const applyBranding = useCallback((primaryColor?: string) => {
    if (primaryColor) {
      document.documentElement.style.setProperty('--primary', primaryColor);
    }
  }, []);

  const fetchConfig = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('store_config')
        .select('*')
        .single();

      if (error) {
        console.error('Error fetching config:', error);
        if (error.code === 'PGRST116') {
          const { data: newData, error: insertError } = await supabase
            .from('store_config')
            .insert([{
              free_shipping_min: defaultConfig.freeShippingMin,
              shipping_fee: defaultConfig.shippingFee,
              whatsapp_number: defaultConfig.whatsappNumber,
              share_text: defaultConfig.shareText,
              business_hours: defaultConfig.businessHours,
              enable_reviews: defaultConfig.enableReviews,
              enable_coupons: defaultConfig.enableCoupons,
              primary_color: defaultConfig.primaryColor
            }])
            .select()
            .single() as any;

          if (!insertError && newData) {
            const newConfig = {
              freeShippingMin: newData.free_shipping_min ?? defaultConfig.freeShippingMin,
              shippingFee: newData.shipping_fee ?? defaultConfig.shippingFee,
              whatsappNumber: newData.whatsapp_number ?? defaultConfig.whatsappNumber,
              shareText: newData.share_text ?? defaultConfig.shareText,
              businessHours: newData.business_hours ?? defaultConfig.businessHours,
              enableReviews: newData.enable_reviews ?? defaultConfig.enableReviews,
              enableCoupons: newData.enable_coupons ?? defaultConfig.enableCoupons,
              primaryColor: newData.primary_color ?? defaultConfig.primaryColor,
              realTimeSalesAlerts: newData.real_time_sales_alerts ?? defaultConfig.realTimeSalesAlerts,
              pushMarketingEnabled: newData.push_marketing_enabled ?? defaultConfig.pushMarketingEnabled,
              minAppVersion: newData.min_app_version
            };
            setConfig(newConfig);
            applyBranding(newConfig.primaryColor);
          }
        }
      } else if (data) {
        const configData = data as any;
        const mappedConfig: StoreConfig = {
          freeShippingMin: configData.free_shipping_min ?? defaultConfig.freeShippingMin,
          shippingFee: configData.shipping_fee ?? defaultConfig.shippingFee,
          whatsappNumber: configData.whatsapp_number ?? defaultConfig.whatsappNumber,
          shareText: configData.share_text ?? defaultConfig.shareText,
          businessHours: configData.business_hours ?? defaultConfig.businessHours,
          enableReviews: configData.enable_reviews ?? defaultConfig.enableReviews,
          enableCoupons: configData.enable_coupons ?? defaultConfig.enableCoupons,
          logoUrl: configData.logo_url,
          primaryColor: configData.primary_color ?? defaultConfig.primaryColor,
          themeMode: configData.theme_mode ?? defaultConfig.themeMode,
          realTimeSalesAlerts: configData.real_time_sales_alerts ?? defaultConfig.realTimeSalesAlerts,
          pushMarketingEnabled: configData.push_marketing_enabled ?? defaultConfig.pushMarketingEnabled,
          minAppVersion: configData.min_app_version,
        };
        setConfig(mappedConfig);
        applyBranding(mappedConfig.primaryColor);
      }
    } catch (error) {
      console.error('Error in fetchConfig:', error);
    } finally {
      setIsLoaded(true);
    }
  }, [applyBranding]);

  const { user } = useAuth();

  useEffect(() => {
    fetchConfig();

    // Subscribe to real-time changes with a unique channel name per session/instance
    const channel = supabase
      .channel(`store_config_changes_${Date.now()}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'store_config'
        },
        (payload) => {
          if (payload.new) {
            console.log('[Realtime] Store config updated');
            const configData = payload.new as any;
            const mappedConfig: StoreConfig = {
              freeShippingMin: configData.free_shipping_min ?? defaultConfig.freeShippingMin,
              shippingFee: configData.shipping_fee ?? defaultConfig.shippingFee,
              whatsappNumber: configData.whatsapp_number ?? defaultConfig.whatsappNumber,
              shareText: configData.share_text ?? defaultConfig.shareText,
              businessHours: configData.business_hours ?? defaultConfig.businessHours,
              enableReviews: configData.enable_reviews ?? defaultConfig.enableReviews,
              enableCoupons: configData.enable_coupons ?? defaultConfig.enableCoupons,
              logoUrl: configData.logo_url,
              primaryColor: configData.primary_color ?? defaultConfig.primaryColor,
              themeMode: configData.theme_mode ?? defaultConfig.themeMode,
              realTimeSalesAlerts: configData.real_time_sales_alerts ?? defaultConfig.realTimeSalesAlerts,
              pushMarketingEnabled: configData.push_marketing_enabled ?? defaultConfig.pushMarketingEnabled,
              minAppVersion: configData.min_app_version,
            };
            setConfig(mappedConfig);
            applyBranding(mappedConfig.primaryColor);
          }
        }
      );

    channel.subscribe((status) => {
      if (status === 'SUBSCRIBED') {
        console.log('[Realtime] Active: store_config_changes');
      }
    });

    return () => {
      if (channel) {
        supabase.removeChannel(channel).catch(err => {
          if (!err?.message?.includes('closed before the connection is established')) {
            console.warn('[Realtime] Cleanup store_config:', err);
          }
        });
      }
    };
  }, [fetchConfig, applyBranding, user?.id]);

  const updateConfig = useCallback(async (updates: Partial<StoreConfig>) => {
    try {
      const dbUpdates: any = {};
      if (updates.freeShippingMin !== undefined) dbUpdates.free_shipping_min = updates.freeShippingMin;
      if (updates.shippingFee !== undefined) dbUpdates.shipping_fee = updates.shippingFee;
      if (updates.whatsappNumber !== undefined) dbUpdates.whatsapp_number = updates.whatsappNumber;
      if (updates.shareText !== undefined) dbUpdates.share_text = updates.shareText;
      if (updates.businessHours !== undefined) dbUpdates.business_hours = updates.businessHours;
      if (updates.enableReviews !== undefined) dbUpdates.enable_reviews = updates.enableReviews;
      if (updates.enableCoupons !== undefined) dbUpdates.enable_coupons = updates.enableCoupons;
      if (updates.logoUrl !== undefined) dbUpdates.logo_url = updates.logoUrl;
      if (updates.primaryColor !== undefined) dbUpdates.primary_color = updates.primaryColor;
      if (updates.themeMode !== undefined) dbUpdates.theme_mode = updates.themeMode;
      if (updates.realTimeSalesAlerts !== undefined) dbUpdates.real_time_sales_alerts = updates.realTimeSalesAlerts;
      if (updates.pushMarketingEnabled !== undefined) dbUpdates.push_marketing_enabled = updates.pushMarketingEnabled;
      if (updates.minAppVersion !== undefined) dbUpdates.min_app_version = updates.minAppVersion;

      const { error } = await (supabase.rpc as any)('upsert_store_config', {
        config_json: dbUpdates
      });

      if (error) throw error;

      setConfig(prev => {
        const next = { ...prev, ...updates };
        applyBranding(next.primaryColor);
        return next;
      });

      toast.success('Configurações salvas');
    } catch (error) {
      console.error('Error updating config:', error);
      toast.error('Erro ao salvar configurações');
    }
  }, [applyBranding]);

  const calculateShipping = useCallback((subtotal: number) => {
    if (subtotal >= config.freeShippingMin) {
      return 0;
    }
    return config.shippingFee;
  }, [config]);

  return {
    config,
    isLoaded,
    updateConfig,
    calculateShipping,
    refresh: fetchConfig
  };
}

