import { useState, useCallback, useEffect } from 'react';

/**
 * useTemporalFold
 * Camada 1 da v27.0 UNBOUND.
 * Implementa um sistema de estados especulativos e multi-realidade.
 * Mantém três timelines: 'Local' (imediato), 'Peer' (p2p swarm) e 'Consensus' (confirmado).
 */
export function useTemporalFold(initialState: any) {
    const [reality, setReality] = useState({
        local: initialState,
        peer: initialState,
        consensus: initialState
    });

    const fold = useCallback((update: any, type: 'local' | 'peer' | 'consensus' | 'all') => {
        setReality(prev => {
            if (type === 'all') {
                const newState = { ...prev.consensus, ...update };
                return { local: newState, peer: newState, consensus: newState };
            }
            const next = { ...prev, [type]: { ...prev[type], ...update } };
            return next;
        });
    }, []);

    // Sync with initialState changes to prevent zumbie reality
    useEffect(() => {
        setReality(prev => {
            const currentConsensus = JSON.stringify(prev.consensus);
            const nextInitial = JSON.stringify(initialState);

            // If the incoming state matches our current consensus, don't reset
            // This prevents loops where hook state update causes parent re-render 
            // which sends a new object reference for the same data.
            if (currentConsensus === nextInitial) return prev;

            console.log('[Temporal-Fold] 🌀 Resyncing reality with new initial state.');
            return {
                local: initialState,
                peer: initialState,
                consensus: initialState
            };
        });
    }, [initialState]);

    const getActiveState = () => reality.local;

    useEffect(() => {
        const interval = setInterval(() => {
            if (JSON.stringify(reality.local) !== JSON.stringify(reality.consensus)) {
                console.log('[Temporal-Fold] ⚠️ Drift detected between LOCAL and CONSENSUS reality. Folding to merge timelines.');
                // Silenced noisy warning, using trace for debugging only if needed
                setReality(prev => ({ ...prev, local: prev.consensus }));
            }
        }, 10000); // Relaxed to 10s for stability
        return () => clearInterval(interval);
    }, [reality.local, reality.consensus]);

    return { state: getActiveState(), fold };
}

import { useEffect, useCallback, useRef, useState } from 'react';
import { toast } from 'sonner';
import { useStore } from '@/contexts/StoreContext';

declare const __APP_VERSION__: string;

// Exponential backoff: 10s, 20s, 40s, 80s, 160s (cap at 5min)
const BACKOFF_BASE = 10_000;
const BACKOFF_MAX = 5 * 60 * 1000;
const HEARTBEAT_INTERVAL = 3 * 60 * 1000; // 3 min (faster than before)

function calcBackoff(attempt: number): number {
    return Math.min(BACKOFF_BASE * Math.pow(2, attempt), BACKOFF_MAX);
}

interface VersionData {
    version: string;
    etag?: string;
    swVersion?: string;
}

export function useUpdateCheck() {
    const { config } = useStore();
    const [isMandatory, setIsMandatory] = useState(false);
    const [updateAvailable, setUpdateAvailable] = useState(false);
    const [newVersion, setNewVersion] = useState<string | null>(null);

    // Track last known etag to avoid re-processing same version
    const lastEtagRef = useRef<string>(__APP_VERSION__);
    const backoffAttemptRef = useRef(0);
    const backoffTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isOnlineRef = useRef(navigator.onLine);

    // ==============================
    // CORE: Nuclear Purge (mandatory)
    // ==============================
    const performNuclearPurge = useCallback(() => {
        console.warn('[Update] 🔴 Initiating Nuclear Purge for mandatory update...');
        setTimeout(async () => {
            if ('serviceWorker' in navigator) {
                const regs = await navigator.serviceWorker.getRegistrations();
                for (const r of regs) await r.unregister();
            }
            if ('caches' in window) {
                const keys = await caches.keys();
                for (const k of keys) await caches.delete(k);
            }
            // Selective purge: keep auth tokens and PWA control keys
            Object.keys(localStorage).forEach(key => {
                if (!key.startsWith('sb-') && !key.startsWith('supabase.auth') && !key.startsWith('pwa_')) {
                    localStorage.removeItem(key);
                }
            });
            window.location.href = `${window.location.origin}/?forceUpdate=${Date.now()}`;
        }, 2500);
    }, []);

    // ==============================
    // CORE: Check for updates
    // ==============================
    const checkUpdate = useCallback(async (): Promise<boolean> => {
        if (!isOnlineRef.current) {
            console.log('[Update] Offline — skipping check');
            return false;
        }

        const t0 = performance.now();
        try {
            console.log('[Update] 🔍 Checking version.json...');

            // 1. Mandatory update from DB config
            const isDev = import.meta.env.DEV;
            const isTimestampVersion = __APP_VERSION__.length > 10 && !isNaN(Number(__APP_VERSION__));

            if (config.minAppVersion && config.minAppVersion !== __APP_VERSION__ && !isDev && !isTimestampVersion) {
                console.log(`[Update] 🚨 Mandatory: local=${__APP_VERSION__} required=${config.minAppVersion}`);
                setIsMandatory(true);
                localStorage.setItem('pwa_reload_reason', `Mandatory Version Mismatch (DB: ${config.minAppVersion})`);
                performNuclearPurge();
                return true;
            }

            // 2. Pull version.json with no-cache
            const res = await fetch(`/version.json?_=${Date.now()}`, {
                cache: 'no-store',
                headers: { 'Cache-Control': 'no-cache, no-store' },
                signal: AbortSignal.timeout(8000),
            });

            if (!res.ok) throw new Error(`version.json returned ${res.status}`);

            const data: VersionData = await res.json();
            const dt = Math.round(performance.now() - t0);
            const remoteVersion = data.version || data.etag || '';

            // Store forensic log
            try {
                const logs = JSON.parse(localStorage.getItem('pwa_forensics') || '[]');
                localStorage.setItem('pwa_forensics', JSON.stringify(
                    [{ t: new Date().toISOString(), m: 'Version check', d: { local: __APP_VERSION__, remote: remoteVersion, ms: dt } }, ...logs].slice(0, 20)
                ));
            } catch (_) { /* silent */ }

            // 3. Compare etag/version
            if (remoteVersion && remoteVersion !== lastEtagRef.current && remoteVersion !== __APP_VERSION__) {
                console.log(`[Update] ✅ New version detected: ${remoteVersion} (check took ${dt}ms). Dispatching upgrade signal.`);
                lastEtagRef.current = remoteVersion;
                setNewVersion(remoteVersion);
                setUpdateAvailable(true);

                // Dispatch event for App.tsx listeners
                window.dispatchEvent(new CustomEvent('pwa-update-available', {
                    detail: { version: remoteVersion, currentVersion: __APP_VERSION__, checkMs: dt }
                }));

                // Tell SW to update
                if ('serviceWorker' in navigator) {
                    const reg = await navigator.serviceWorker.getRegistration();
                    if (reg?.waiting) {
                        console.log('[Update] 📡 SW waiting found, posting SKIP_WAITING.');
                        reg.waiting.postMessage({ type: 'SKIP_WAITING' });
                    } else {
                        console.log('[Update] 📡 Requesting SW update().');
                        await reg?.update();
                    }
                }

                // Reset backoff on success
                backoffAttemptRef.current = 0;
                return true;
            }

            console.log(`[Update] ✓ Up to date (local=${__APP_VERSION__}, remote=${remoteVersion}) — ${dt}ms`);
            backoffAttemptRef.current = 0;
            return false;
        } catch (err) {
            backoffAttemptRef.current++;
            const delay = calcBackoff(backoffAttemptRef.current);
            console.warn(`[Update] ⚠️ Check failed (attempt ${backoffAttemptRef.current}). Retry in ${delay / 1000}s`, err);

            // Schedule retry with backoff
            if (backoffTimerRef.current) clearTimeout(backoffTimerRef.current);
            backoffTimerRef.current = setTimeout(() => checkUpdate(), delay);
            return false;
        }
    }, [config.minAppVersion, performNuclearPurge]);

    // ==============================
    // LIFECYCLE: Heartbeat + Events
    // ==============================
    useEffect(() => {
        // Initial check (after 2s to avoid blocking app startup)
        const initialTimer = setTimeout(() => checkUpdate(), 2000);

        // Periodic heartbeat
        const heartbeat = setInterval(() => checkUpdate(), HEARTBEAT_INTERVAL);

        // Immediate check when tab becomes visible
        const onVisibilityChange = () => {
            if (document.visibilityState === 'visible' && isOnlineRef.current) {
                console.log('[Update] 👁️ Tab visible — immediate check');
                checkUpdate();
            }
        };

        // Online: resume checks immediately
        const onOnline = () => {
            isOnlineRef.current = true;
            console.log('[Update] 🌐 Back online — checking now');
            toast.info('Conexão restaurada', { description: 'Verificando atualizações...', duration: 2000 });
            checkUpdate();
        };

        // Offline: suspend checks
        const onOffline = () => {
            isOnlineRef.current = false;
            console.log('[Update] 📴 Offline — checks suspended');
            if (backoffTimerRef.current) clearTimeout(backoffTimerRef.current);
        };

        // Page focus check (desktop)
        const onFocus = () => {
            if (isOnlineRef.current) checkUpdate();
        };

        document.addEventListener('visibilitychange', onVisibilityChange);
        window.addEventListener('online', onOnline);
        window.addEventListener('offline', onOffline);
        window.addEventListener('focus', onFocus);

        return () => {
            clearTimeout(initialTimer);
            clearInterval(heartbeat);
            if (backoffTimerRef.current) clearTimeout(backoffTimerRef.current);
            document.removeEventListener('visibilitychange', onVisibilityChange);
            window.removeEventListener('online', onOnline);
            window.removeEventListener('offline', onOffline);
            window.removeEventListener('focus', onFocus);
        };
    }, [checkUpdate]);

    // ==============================
    // BroadcastChannel: SW events
    // ==============================
    useEffect(() => {
        const bc = new BroadcastChannel('sw-messages');
        bc.onmessage = (event) => {
            const { type } = event.data || {};
            // O reload agora é controlado centralmente pelo App.tsx ou via manual trigger.
            // Aqui apenas silenciamos o disparo automático para evitar loops.
            if (type === 'SW_ACTIVATED' || type === 'SW_SKIPPED_WAITING') {
                console.log('[Update] 📡 SW activated signal received.');
            }
            if (type === 'SERVING_OFFLINE') {
                toast.warning('Modo Offline', {
                    description: 'Você está vendo dados em cache. Reconectando...',
                    duration: 4000,
                });
            }
        };
        return () => bc.close();
    }, []);

    // ==============================
    // ChunkLoadError auto-recovery
    // ==============================
    useEffect(() => {
        const handleError = (e: ErrorEvent) => {
            const msg = (e.message || '').toLowerCase();
            const isChunkError =
                msg.includes('loading chunk') ||
                msg.includes('unexpected token') ||
                msg.includes('failed to fetch dynamically imported module') ||
                msg.includes('importing a module script failed');

            if (isChunkError) {
                console.error('[Update] 💥 ChunkLoadError detected — checking guard');

                const lastReload = sessionStorage.getItem('pwa_chunk_error_reload');
                const now = Date.now();

                if (lastReload && now - parseInt(lastReload) < 15000) {
                    console.warn('[Update] 🛡️ Reload Guard Active: Preventing infinite loop for ChunkLoadError.');
                    toast.error('Ocorreu um erro persistente', {
                        description: 'Por favor, tente recarregar manualmente ou use o modo de recuperação.',
                        duration: 10000,
                    });
                    return;
                }

                sessionStorage.setItem('pwa_chunk_error_reload', now.toString());
                localStorage.setItem('pwa_reload_reason', 'ChunkLoadError (Asset Missing/Network)');
                toast.error('Erro de carregamento', {
                    description: 'Sincronizando nova versão automaticamente...',
                });

                setTimeout(() => window.location.reload(), 2000);
            }
        };

        window.addEventListener('error', handleError);
        return () => window.removeEventListener('error', handleError);
    }, []);

    return { isMandatory, updateAvailable, newVersion };
}

