type VariantRow = Database['public']['Tables']['product_variants']['Row'];
type OrderRow = Database['public']['Tables']['marketplace_orders']['Row'];
type OrderItemRow = Database['public']['Tables']['marketplace_order_items']['Row'];

/**
 * Maps a database product row to the application Product interface
 */
export function mapProductFromDB(
    row: ProductRow & { product_variants?: VariantRow[]; imagem_urls?: string[] | null }
): Product {
    try {
        if (!row) throw new Error('Product row is null');

        return {
            id: row.id,
            name: (row.nome === 'boobie goods' || row.nome === 'Boobie Goods') ? 'Bobbie Goods' : (row.nome || 'Produto sem nome'),
            description: row.descricao || '',
            price: Number(row.preco_venda) || 0,
            costPrice: Number(row.custo) || 0,
            originalPrice: (row as any).preco_original ? Number((row as any).preco_original) : undefined,
            images: (row.nome?.includes('Aliança Luxo'))
                ? ['https://m.media-amazon.com/images/I/51-mYyA-zXL._AC_SL1000_.jpg']
                : (row.imagem_urls && row.imagem_urls.length > 0
                    ? row.imagem_urls
                    : (row.imagem_url ? [row.imagem_url] : ['https://placehold.co/600x400?text=Sem+Imagem'])),
            category: row.categoria || 'Geral',
            stock: Number(row.estoque) || 0,
            sold: Number((row as any).sold) || 0,
            isActive: row.ativo ?? true,
            isBestseller: !!(row as any).is_bestseller || !!(row as any).bestseller,
            freeShipping: !!(row as any).frete_gratis || !!(row as any).shipped_free,
            createdAt: row.data_cadastro || '1970-01-01T00:00:00.000Z',
            rating: Number((row as any).rating) || 5,
            reviewCount: Number((row as any).review_count) || 0,
            tags: Array.isArray(row.tags) ? row.tags : [],
            metaTitle: row.meta_title || undefined,
            metaDescription: row.meta_description || undefined,
            variants: Array.isArray(row.product_variants) ? row.product_variants.map(mapVariantFromDB) : []
        };
    } catch (err) {
        console.error('[Mapper] Critical error mapping product:', err, row);
        // Return a minimal valid product to prevent crash, but log it
        return {
            id: row?.id || 'error-' + Date.now(),
            name: 'Erro ao carregar',
            description: '',
            price: 0,
            costPrice: 0,
            images: ['https://placehold.co/600x400?text=Erro+de+Dados'],
            category: 'Erro',
            stock: 0,
            sold: 0,
            isActive: false,
            isBestseller: false,
            freeShipping: false,
            createdAt: '1970-01-01T00:00:00.000Z',
            rating: 0,
            reviewCount: 0,
            tags: [],
            variants: []
        };
    }
}

/**
 * Maps a database variant row to the application ProductVariant interface
 */
export function mapVariantFromDB(row: VariantRow): ProductVariant {
    return {
        id: row.id,
        productId: row.product_id,
        sku: row.sku || undefined,
        name: row.name || 'Padrão',
        value: row.value || '',
        stockIncrement: Number(row.stock_increment) || 0,
        priceOverride: row.price_override ? Number(row.price_override) : undefined,
        active: row.active ?? true
    };
}

/**
 * Maps a database order row to the application Order interface
 */
export function mapOrderFromDB(
    row: OrderRow & { items?: OrderItemRow[] }
): Order {
    const customerData = row.customer_data as unknown as Customer; // Trusting the JSON structure for now, ideally validate with Zod

    return {
        id: row.id,
        userId: row.user_id || undefined,
        customer: {
            ...customerData,
            name: row.customer_name || customerData?.name || 'Cliente',
            whatsapp: customerData?.whatsapp || ''
        },
        items: row.items?.map(item => ({
            productId: item.product_id || '',
            variantId: undefined, // variant_id missing in order_items schema based on previous view, need to check
            name: item.product_name || '',
            price: Number(item.price),
            quantity: Number(item.quantity),
            image: item.image_url || ''
        })) || [],
        total: Number(row.total),
        subtotal: Number(row.subtotal),
        shipping: Number(row.shipping || 0),
        discount: Number(row.discount || 0),
        paymentMethod: (row.payment_method as PaymentMethod) || 'cash',
        status: (row.status as OrderStatus) || 'new',
        notes: row.notes || undefined,
        couponCode: row.coupon_code || undefined,
        trackingCode: row.tracking_code || undefined,
        createdAt: row.created_at,
        updatedAt: row.updated_at
    };
}

