/**
 * PWA Sentinel — The Guardian
 * Camada 3 da v23.0 OMNIPOTENCE.
 * Este script roda fora do ciclo de vida principal do React para monitorar a saúde do SW.
 * Se o SW travar ou falhar em responder corações (heartbeats), o Sentinel intervém.
 */
export const initSentinel = () => {
    if (!('serviceWorker' in navigator)) return;

    console.log('[PWA-Sentinel] Guardian active. Monitoring Service Worker health...');

    let lastHeartbeat = Date.now();
    const channel = new BroadcastChannel('sw-heartbeat');

    channel.onmessage = (event) => {
        if (event.data === 'HEARTBEAT_ACK') {
            lastHeartbeat = Date.now();
        }
    };

    // Verificação de pulso a cada 30 segundos
    setInterval(() => {
        const timeSinceLastPulse = Date.now() - lastHeartbeat;

        if (timeSinceLastPulse > 300000) { // 5 minutos sem sinal = falha crítica (Mais tolerante que antes)
            console.error(`[PWA-Sentinel] ⚠️ CRITICAL: Service Worker pulse lost (${timeSinceLastPulse}ms since last heartbeat). Attempting Emergency Recovery...`);

            navigator.serviceWorker.getRegistrations().then(registrations => {
                for (let registration of registrations) {
                    registration.unregister();
                }
                console.warn('[PWA-Sentinel] 🔌 Unregistered SWs. Forcing reload for fresh state.');
                localStorage.setItem('pwa_reload_reason', `Sentinel Recovery (${timeSinceLastPulse}ms pulse loss)`);
                window.location.reload(); // Força re- registro limpo
            });
        } else {
            // Envia ping para o SW
            console.log(`[PWA-Sentinel] 💓 Heartbeat check: OK. Last pulse was ${timeSinceLastPulse}ms ago.`);
            navigator.serviceWorker.controller?.postMessage('HEARTBEAT_PING');
        }
    }, 30000);
};

