/**
 * VOR (Verified Observation Runtime) - Truth Gate G17
 * Garante a integridade lógica dos dados no domínio do marketplace.
 */

export interface VerificationReceipt {
    hash: string;
    timestamp: string;
    status: 'VERIFIED' | 'ABORTED';
    violations: string[];
}

export const TruthGate = {
    /**
     * Verifica axiomas fundamentais de um produto.
     * VOR Implementation: Prova ou Abortagem.
     */
    verifyProductAxiom: (product: any): VerificationReceipt => {
        const violations: string[] = [];

        // Axioma 1: Preço não pode ser negativo
        if (product.price < 0) {
            violations.push('Axiom violation: price_non_negative');
        }

        // Axioma 2: Estoque dentro do limite termodinâmico
        if (product.stock > 10000) {
            violations.push('Axiom violation: stock_limit_exceeded');
        }

        // Axioma 3: Nome do produto é mandatório (Identidade)
        if (!product.name || product.name.trim().length === 0) {
            violations.push('Axiom violation: identity_null_error');
        }

        // Axioma 4: Validação Financeira
        if (product.costPrice && product.costPrice < 0) {
            violations.push('Axiom violation: cost_price_negative');
        }
        if (product.costPrice && product.price > 0 && product.costPrice >= product.price) {
            violations.push('Axiom warning: price_margin_negative (Prejuízo detectado)');
        }

        const status = violations.length === 0 ? 'VERIFIED' : 'ABORTED';
        const timestamp = new Date().toISOString();
        const hash = btoa(`${product.id || 'new'}-${timestamp}-${status}`).slice(0, 16);

        const receipt: VerificationReceipt = {
            hash,
            timestamp,
            status,
            violations
        };

        // Protocolo SROS: Registro de recibo para auditoria de enxame
        console.log(`%c[VOR-G17] Receipt Generated: ${hash}`, 'color: #10b981; font-weight: bold;', receipt);

        if (status === 'ABORTED') {
            console.error(`[VOR-G17] Execution ABORTED due to violations`, violations);
        }

        return receipt;
    }
};

import { useState, useEffect, useCallback } from 'react';
import { ArrowLeft, DollarSign, ShoppingBag, Users, Calendar, Filter, Download } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
    XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    BarChart, Bar, Cell, PieChart, Pie, Legend, AreaChart, Area
} from 'recharts';
import type { View } from '@/types';

interface AdminAnalyticsViewProps {
    onNavigate: (view: View) => void;
}

import { useAnalytics } from '@/hooks/useAnalytics';

export function AdminAnalyticsView({ onNavigate }: AdminAnalyticsViewProps) {
    const { fetchExecutiveSummary, fetchRetentionAnalytics, fetchCategoryAnalytics } = useAnalytics();
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState<any[]>([]);
    const [summary, setSummary] = useState({
        totalRevenue: 0,
        totalOrders: 0,
        avgTicket: 0,
        activeCustomers: 0,
        revTrend: 0,
        orderTrend: 0,
        ticketTrend: 0,
        activeTrend: 0
    });
    const [categoryData, setCategoryData] = useState<any[]>([]);
    const [topProducts, setTopProducts] = useState<any[]>([]);
    const [retentionRate, setRetentionRate] = useState(0);
    const [activities, setActivities] = useState<any[]>([]);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            // 1. Fetch Unified Executive Summary
            const data = await fetchExecutiveSummary();

            if (data) {
                const executive = data.executive || {};

                setSummary({
                    totalRevenue: Number(executive.revenue30d || 0),
                    totalOrders: Number(executive.orders30d || 0),
                    avgTicket: Number(executive.avgTicket || 0),
                    activeCustomers: Number(executive.activeCustomers || 0),
                    revTrend: Number(executive.revenueTrend || 0),
                    orderTrend: Number(executive.ordersTrend || 0),
                    ticketTrend: Number(executive.avgTicketTrend || 0),
                    activeTrend: Number(executive.activeCustomersTrend || 0)
                });

                // Revenue & Orders History (30 Days)
                if (data.revenueHistory) {
                    setStats(data.revenueHistory.map((h: any) => ({
                        date: h.date,
                        revenue: Number(h.revenue),
                        orders: Number(h.orders || 0),
                        ticket: Number(h.orders) > 0 ? Number(h.revenue) / Number(h.orders) : 0
                    })));
                }

                // Top Products
                if (data.topProducts) {
                    setTopProducts(data.topProducts.map((p: any) => ({
                        id: p.name,
                        name: p.name,
                        sold: p.quantity,
                        images: [p.image],
                        price: p.quantity > 0 ? p.total / p.quantity : 0
                    })));
                }

                // Category Analytics
                const now = new Date();
                const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
                const catData = await fetchCategoryAnalytics(thirtyDaysAgo.toISOString(), now.toISOString());
                if (catData) setCategoryData(catData);

                // Retention
                const retRate = await fetchRetentionAnalytics(90);
                if (retRate) setRetentionRate(Number(retRate));

                // Recent Activities
                const { data: recentOrders } = await supabase
                    .from('marketplace_orders')
                    .select('id, customer_name, total, created_at')
                    .order('created_at', { ascending: false })
                    .limit(5);

                if (recentOrders) {
                    setActivities(recentOrders.map(a => ({
                        id: a.id,
                        type: 'order',
                        message: `Pedido de R$ ${Number(a.total).toFixed(2)} por ${a.customer_name}`,
                        time: new Date(a.created_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
                    })));
                }
            }
        } catch (error) {
            console.error('Error fetching analytics:', error);
        } finally {
            setLoading(false);
        }
    }, [fetchExecutiveSummary, fetchCategoryAnalytics, fetchRetentionAnalytics]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleExport = () => {
        if (!stats.length) {
            console.warn('No stats to export');
            return;
        }

        const headers = ['Data', 'Faturamento (R$)', 'Pedidos', 'Ticket Médio (R$)'];
        const rows = stats.map(s => [
            s.date,
            s.revenue.toFixed(2),
            s.orders,
            s.ticket.toFixed(2)
        ]);

        const csvContent = [
            headers.join(','),
            ...rows.map(row => row.join(','))
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);

        link.setAttribute('href', url);
        link.setAttribute('download', `relatorio_vendas_${new Date().toISOString().split('T')[0]}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-zinc-50/50 flex flex-col items-center justify-center p-10">
                <div className="w-12 h-12 border-2 border-zinc-200 border-t-zinc-900 rounded-full animate-spin mb-6" />
                <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.3em]">Gerando relatório executivo...</p>
            </div>
        );
    }

    const CustomTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white border border-zinc-100 p-4 rounded-2xl shadow-premium backdrop-blur-xl">
                    <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-2">{label}</p>
                    <p className="text-sm font-black text-zinc-900">
                        {payload[0].name === 'Faturamento' ? `R$ ${(payload[0].value || 0).toLocaleString('pt-BR')}` : payload[0].value}
                    </p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="min-h-screen bg-zinc-50/30 pb-32 selection:bg-zinc-900 selection:text-white">
            {/* Executive Header */}
            <div className="glass px-6 py-6 flex items-center justify-between sticky top-0 z-50 border-b border-zinc-100">
                <div className="flex items-center gap-4">
                    <button
                        onClick={() => onNavigate('admin-dashboard')}
                        className="w-12 h-12 flex items-center justify-center bg-white text-zinc-900 rounded-2xl border border-zinc-100 hover:bg-zinc-900 hover:text-white transition-all duration-500 active:scale-90 shadow-sm"
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-xl font-black text-zinc-900 tracking-tighter">Business Intelligence</h1>
                        <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-[0.2em] mt-0.5">Visão Gerencial do Ecossistema</p>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={handleExport}
                        className="rounded-xl border border-zinc-100 bg-white text-zinc-400 hover:text-zinc-600 hover:bg-zinc-50"
                        title="Exportar CSV"
                    >
                        <Download className="w-4 h-4" />
                    </Button>
                    <button
                        onClick={fetchData}
                        className="px-6 py-3 bg-zinc-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all active:scale-95 shadow-premium-sm"
                    >
                        Refresh
                    </button>
                </div>
            </div>

            <div className="p-6 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-1000">
                {/* Executive Scorecards */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    {[
                        { label: 'Revenue (30d)', value: `R$ ${(summary.totalRevenue || 0).toLocaleString()}`, icon: DollarSign, trend: `${summary.revTrend > 0 ? '+' : ''}${summary.revTrend}%`, inverse: summary.revTrend < 0 },
                        { label: 'Volume Pedidos', value: (summary.totalOrders || 0).toString(), icon: ShoppingBag, trend: `${summary.orderTrend > 0 ? '+' : ''}${summary.orderTrend}%`, inverse: summary.orderTrend < 0 },
                        { label: 'Average Ticket', value: `R$ ${(summary.avgTicket || 0).toFixed(0)}`, icon: Calendar, trend: `${summary.ticketTrend > 0 ? '+' : ''}${summary.ticketTrend}%`, inverse: summary.ticketTrend < 0 },
                        { label: 'Active Core', value: (summary.activeCustomers || 0).toString(), icon: Users, trend: `${summary.activeTrend > 0 ? '+' : ''}${summary.activeTrend}%`, inverse: summary.activeTrend < 0 },
                    ].map((card, i) => (
                        <Card key={i} className="bg-white border-zinc-100 border rounded-[2.5rem] p-6 group hover:border-zinc-200 shadow-premium-sm hover:shadow-premium transition-all duration-700">
                            <div className="flex justify-between items-start mb-4">
                                <div className="p-3 bg-zinc-50 rounded-2xl border border-zinc-100 group-hover:scale-110 group-hover:bg-zinc-900 group-hover:text-white transition-all duration-500">
                                    <card.icon className="w-5 h-5" />
                                </div>
                                <span className={`text-[9px] font-black px-2 py-1 rounded-full ${card.inverse ? 'bg-red-50 text-red-600' : 'bg-emerald-50 text-emerald-600'} border border-zinc-100`}>
                                    {card.trend}
                                </span>
                            </div>
                            <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em] mb-1">{card.label}</p>
                            <h3 className="text-3xl font-black tracking-tighter text-zinc-900">{card.value}</h3>
                        </Card>
                    ))}
                </div>

                {/* Main Performance Graph */}
                <Card className="bg-white border-zinc-100 border rounded-[3rem] p-8 overflow-hidden relative group shadow-premium-sm">
                    <div className="absolute top-0 right-0 w-96 h-96 bg-zinc-900/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-[100px]" />

                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-10 relative z-10">
                        <div>
                            <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-400">Fluxo de Faturamento</h3>
                            <p className="text-[11px] font-medium text-zinc-600 mt-1">Análise temporal de liquidez e volume</p>
                        </div>
                        <div className="flex items-center gap-3">
                            <div className="flex items-center gap-2 px-4 py-2 bg-zinc-50 rounded-xl border border-zinc-100">
                                <Filter className="w-3 h-3 text-zinc-400" />
                                <span className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Últimos 30 Dias</span>
                            </div>
                        </div>
                    </div>

                    <div className="h-[400px] w-full relative z-10">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart data={stats}>
                                <defs>
                                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#18181b" stopOpacity={0.1} />
                                        <stop offset="95%" stopColor="#18181b" stopOpacity={0} />
                                    </linearGradient>
                                </defs>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f4f4f5" />
                                <XAxis
                                    dataKey="date"
                                    fontSize={10}
                                    axisLine={false}
                                    tickLine={false}
                                    tick={{ fill: '#a1a1aa', fontWeight: 900 }}
                                    dy={15}
                                />
                                <YAxis
                                    fontSize={10}
                                    axisLine={false}
                                    tickLine={false}
                                    tickFormatter={(v) => `R$${v}`}
                                    tick={{ fill: '#a1a1aa', fontWeight: 900 }}
                                />
                                <Tooltip content={<CustomTooltip />} />
                                <Area
                                    type="monotone"
                                    dataKey="revenue"
                                    name="Faturamento"
                                    stroke="#18181b"
                                    strokeWidth={3}
                                    fillOpacity={1}
                                    fill="url(#colorRevenue)"
                                    animationDuration={2000}
                                />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </Card>

                {/* Secondary Charts Block */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    <Card className="bg-white border-zinc-100 border rounded-[3rem] p-8 shadow-premium-sm">
                        <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-400 mb-8">Performance por Categoria</h3>
                        <div className="h-[300px] w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={categoryData}
                                        innerRadius={80}
                                        outerRadius={110}
                                        paddingAngle={10}
                                        dataKey="value"
                                        stroke="none"
                                    >
                                        {categoryData.map((_entry, index) => (
                                            <Cell
                                                key={`cell-${index}`}
                                                fill={index === 0 ? '#18181b' : index === 1 ? '#3f3f46' : index === 2 ? '#71717a' : '#a1a1aa'}
                                            />
                                        ))}
                                    </Pie>
                                    <Tooltip content={<CustomTooltip />} />
                                    <Legend
                                        verticalAlign="bottom"
                                        height={36}
                                        iconType="circle"
                                        wrapperStyle={{ fontSize: '10px', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.1em', paddingTop: '30px' }}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                    </Card>

                    <Card className="bg-white border-zinc-100 border rounded-[3rem] p-8 shadow-premium-sm">
                        <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-400 mb-8">Capacidade Operacional</h3>
                        <div className="h-[300px] w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={stats}>
                                    <XAxis
                                        dataKey="date"
                                        fontSize={10}
                                        axisLine={false}
                                        tickLine={false}
                                        tick={{ fill: '#3f3f46', fontWeight: 900 }}
                                    />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Bar dataKey="orders" name="Pedidos" radius={[4, 4, 0, 0]} barSize={12}>
                                        {stats.map((_entry, index) => (
                                            <Cell key={`cell-${index}`} fill={index === stats.length - 1 ? '#18181b' : '#f4f4f5'} />
                                        ))}
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </Card>
                </div>

                {/* Top Products & Live Activity Section */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <Card className="lg:col-span-2 bg-white border-zinc-100 border rounded-[3rem] p-8 shadow-premium-sm">
                        <div className="flex items-center justify-between mb-8">
                            <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-400">Ranking de Produtos (Top 5)</h3>
                            <ShoppingBag className="w-4 h-4 text-zinc-600" />
                        </div>
                        <div className="space-y-4">
                            {topProducts.map((product, i) => (
                                <div key={product.id} className="flex items-center justify-between p-4 bg-zinc-50 rounded-2xl border border-zinc-100 group hover:bg-zinc-950 hover:text-white transition-all duration-500">
                                    <div className="flex items-center gap-4">
                                        <div className="text-xs font-black text-zinc-500 w-4">#{i + 1}</div>
                                        <img src={product.images?.[0]} className="w-12 h-12 rounded-xl object-cover" alt={product.name} />
                                        <div>
                                            <p className="text-[11px] font-black uppercase tracking-widest">{product.name}</p>
                                            <p className="text-[9px] font-bold opacity-50 uppercase tracking-tighter">R$ {(product.price || 0).toLocaleString()}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-sm font-black">{product.sold}</p>
                                        <p className="text-[8px] font-black uppercase tracking-widest opacity-40">Vendidos</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </Card>

                    {/* Live Activity */}
                    <Card className="lg:col-span-1 bg-white border-zinc-100 border rounded-[3rem] p-8 shadow-premium-sm">
                        <div className="flex items-center justify-between mb-8">
                            <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-400">Atividade Live</h3>
                            <div className="w-2 h-2 bg-red-500 rounded-full animate-ping" />
                        </div>
                        <div className="space-y-6">
                            {activities.map((activity) => (
                                <div key={activity.id} className="flex gap-4 group">
                                    <div className="w-1 h-12 bg-zinc-100 rounded-full overflow-hidden group-hover:bg-zinc-950 transition-colors">
                                        <div className="w-full bg-zinc-300 h-1/3 group-hover:h-full transition-all duration-700" />
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-[11px] font-black uppercase tracking-wider text-zinc-900 leading-tight mb-1 group-hover:translate-x-1 transition-transform">{activity.message}</p>
                                        <p className="text-[9px] font-bold text-zinc-400 uppercase tracking-tighter">{activity.time}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </Card>
                </div>

                {/* Retention Phase 12 */}
                <div className="grid grid-cols-1 gap-8">

                    <Card className="bg-zinc-950 border-white/5 border rounded-[3rem] p-8 flex flex-col justify-center items-center text-center relative overflow-hidden group shadow-premium-lg">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-white/10 transition-all" />

                        <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mb-6 border border-white/10">
                            <Users className="w-8 h-8 text-white" />
                        </div>

                        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-500 mb-2 font-antialiased">Taxa de Retenção</p>
                        <h3 className="text-5xl font-black tracking-tighter text-white mb-4">{retentionRate.toFixed(1)}%</h3>

                        <div className="w-full bg-white/5 h-2 rounded-full overflow-hidden mb-6">
                            <div className="h-full bg-white rounded-full transition-all duration-1000" style={{ width: `${retentionRate}%` }} />
                        </div>

                        <span className="text-zinc-500 text-[10px] font-black uppercase tracking-widest leading-relaxed max-w-xs">
                            Clientes que realizaram mais de uma compra no ecossistema <span className="text-white italic">IKCOUS</span>.
                        </span>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, type ChangeEvent } from 'react';
import { Plus, ArrowLeft, Upload, ArrowUp, ArrowDown, Layout, Sparkles, Eye, Zap, Trash, Edit, ExternalLink } from 'lucide-react';
import { useBanners } from '@/hooks/useBanners';
import type { Banner, View } from '@/types';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { toast } from 'sonner';

interface AdminBannersViewProps {
    onNavigate: (view: View) => void;
}

export function AdminBannersView({ onNavigate }: AdminBannersViewProps) {
    const { banners, isLoaded, uploadBannerImage, addBanner, updateBanner, deleteBanner, reorderBanners, refreshBanners } = useBanners();
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingBanner, setEditingBanner] = useState<Banner | null>(null);
    const [uploading, setUploading] = useState(false);
    const [formData, setFormData] = useState<Partial<Banner>>({
        title: '',
        imageUrl: '',
        link: '',
        position: 'home_top',
        active: true,
        order: 0
    });

    useEffect(() => {
        refreshBanners(false);
    }, [refreshBanners]);

    const handleOpenDialog = (banner?: Banner) => {
        if (banner) {
            setEditingBanner(banner);
            setFormData({ ...banner });
        } else {
            setEditingBanner(null);
            setFormData({
                title: '',
                imageUrl: '',
                link: '',
                position: 'home_top',
                active: true,
                order: banners.length + 1
            });
        }
        setIsDialogOpen(true);
    };

    const handleFileUpload = async (e: ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setUploading(true);
        try {
            const url = await uploadBannerImage(file);
            setFormData(prev => ({ ...prev, imageUrl: url }));
            toast.success('Imagem enviada com sucesso');
        } catch {
            toast.error('Erro ao enviar imagem');
        } finally {
            setUploading(false);
        }
    };

    const handleSubmit = async () => {
        try {
            if (!formData.imageUrl) {
                toast.error('Imagem é obrigatória');
                return;
            }

            if (editingBanner) {
                await updateBanner(editingBanner.id, formData);
            } else {
                await addBanner(formData as Required<Omit<Banner, 'id'>>);
            }
            await refreshBanners(false);
            setIsDialogOpen(false);
            toast.success(editingBanner ? 'Banner atualizado' : 'Banner criado');
        } catch {
            // Error handled in hook
        }
    };

    const handleDelete = async (id: string, imageUrl: string) => {
        if (confirm('Tem certeza que deseja excluir este banner?')) {
            await deleteBanner(id, imageUrl);
            await refreshBanners(false);
            toast.success('Banner removido');
        }
    };

    const moveBanner = async (banner: Banner, direction: 'up' | 'down') => {
        const bannersInPosition = banners
            .filter(b => b.position === banner.position)
            .sort((a, b) => (a.order ?? 0) - (b.order ?? 0));

        const currentIndex = bannersInPosition.findIndex(b => b.id === banner.id);
        const targetIndex = direction === 'up' ? currentIndex - 1 : currentIndex + 1;

        if (targetIndex >= 0 && targetIndex < bannersInPosition.length) {
            const targetBanner = bannersInPosition[targetIndex];
            await reorderBanners(banner.id, targetBanner.id);
            // hook handles fetchBanners or re-syncing
        }
    };

    const positions = [
        { value: 'home_top', label: 'Topo (Home)' },
        { value: 'home_middle', label: 'Meio (Home)' },
        { value: 'home_bottom', label: 'Rodapé (Home)' }
    ];

    return (
        <div className="min-h-screen bg-zinc-50/30 text-zinc-950 pb-32">
            {/* Header Executivo */}
            <div className="glass px-6 py-6 sticky top-0 z-50 border-b border-zinc-100">
                <div className="max-w-5xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => onNavigate('admin-dashboard')}
                            className="w-12 h-12 flex items-center justify-center bg-zinc-100 text-zinc-600 rounded-2xl hover:bg-zinc-200 transition-all active:scale-95 border border-zinc-200 group"
                        >
                            <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                        </button>
                        <div>
                            <h1 className="text-xl font-black text-zinc-900 tracking-tight flex items-center gap-2">
                                Visual Engine <Layout className="w-4 h-4 text-zinc-400" />
                            </h1>
                            <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.2em]">Curadoria Estética de Banners</p>
                        </div>
                    </div>

                    <button
                        onClick={() => handleOpenDialog()}
                        className="h-14 px-8 bg-zinc-950 text-white rounded-[1.5rem] text-xs font-black uppercase tracking-[0.2em] hover:bg-black transition-all active:scale-95 shadow-premium flex items-center gap-3"
                    >
                        <Plus className="w-4 h-4" />
                        Novo Banner
                    </button>
                </div>
            </div>

            <div className="max-w-5xl mx-auto p-6 space-y-8">
                {/* Stats & Mood */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="bg-white border border-zinc-100 rounded-[2.5rem] p-8 flex items-center gap-6 shadow-premium-sm">
                        <div className="w-16 h-16 bg-zinc-50 rounded-3xl flex items-center justify-center border border-zinc-100 text-emerald-600">
                            <Eye className="w-8 h-8" />
                        </div>
                        <div>
                            <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Exposição Ativa</p>
                            <h3 className="text-3xl font-black tracking-tighter text-zinc-900">{banners.filter(b => b.active).length}</h3>
                        </div>
                    </div>
                    <div className="bg-white border border-zinc-100 rounded-[2.5rem] p-8 flex items-center gap-6 shadow-premium-sm">
                        <div className="w-16 h-16 bg-zinc-50 rounded-3xl flex items-center justify-center border border-zinc-100 text-amber-600">
                            <Zap className="w-8 h-8" />
                        </div>
                        <div>
                            <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Impacto Estimado</p>
                            <h3 className="text-3xl font-black tracking-tighter text-zinc-900">Alto</h3>
                        </div>
                    </div>
                </div>

                {!isLoaded ? (
                    <div className="flex flex-col items-center justify-center py-32 space-y-4">
                        <div className="w-12 h-12 border-3 border-zinc-200 border-t-zinc-900 rounded-full animate-spin" />
                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Sincronizando Galeria...</p>
                    </div>
                ) : (
                    <div className="space-y-12">
                        {positions.map((pos) => {
                            const positionBanners = banners.filter(b => b.position === pos.value).sort((a, b) => (a.order ?? 0) - (b.order ?? 0));

                            return (
                                <div key={pos.value} className="space-y-6">
                                    <div className="flex items-center gap-3 px-2">
                                        <h2 className="text-[11px] font-black text-zinc-400 uppercase tracking-[0.3em]">{pos.label}</h2>
                                        <div className="h-[1px] flex-1 bg-zinc-100" />
                                    </div>

                                    {positionBanners.length === 0 ? (
                                        <div className="bg-white p-12 rounded-[3rem] border border-zinc-100 shadow-premium-sm text-center">
                                            <p className="text-[10px] font-black text-zinc-300 uppercase tracking-widest">Vazio nesta seção</p>
                                        </div>
                                    ) : (
                                        <div className="grid gap-6">
                                            {positionBanners.map(banner => (
                                                <div
                                                    key={banner.id}
                                                    className={`group bg-white border border-zinc-100 rounded-[3rem] p-6 transition-all hover:shadow-premium overflow-hidden relative ${!banner.active ? 'opacity-40 grayscale' : ''}`}
                                                >
                                                    <div className="flex flex-col lg:flex-row gap-8 items-center">
                                                        {/* Preview Imagem Premium */}
                                                        <div className="relative w-full lg:w-[450px] aspect-[21/9] rounded-[2rem] overflow-hidden border border-zinc-100 shadow-2xl">
                                                            <img
                                                                src={banner.imageUrl}
                                                                alt={banner.title || 'Banner'}
                                                                className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                                                            />
                                                            <div className="absolute inset-0 bg-gradient-to-t from-zinc-900/40 via-transparent to-transparent opacity-60" />
                                                            {!banner.active && (
                                                                <div className="absolute inset-0 bg-white/60 backdrop-blur-sm flex items-center justify-center text-[10px] font-black uppercase tracking-[0.3em] text-zinc-600">
                                                                    Em Pausa
                                                                </div>
                                                            )}
                                                        </div>

                                                        {/* Infos & Controles */}
                                                        <div className="flex-1 space-y-4 w-full">
                                                            <div className="flex items-center justify-between">
                                                                <div>
                                                                    <h3 className="text-lg font-black text-zinc-900 uppercase tracking-tight italic">
                                                                        {banner.title || 'Sem Título'}
                                                                    </h3>
                                                                    <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2 mt-1">
                                                                        Ordem de Exibição: <span className="text-zinc-900">#{banner.order}</span>
                                                                    </p>
                                                                </div>
                                                                <div className="flex gap-2">
                                                                    <button
                                                                        onClick={() => moveBanner(banner, 'up')}
                                                                        className="w-10 h-10 bg-zinc-50 text-zinc-600 rounded-xl flex items-center justify-center hover:bg-zinc-900 hover:text-white disabled:opacity-20 border border-zinc-100"
                                                                    >
                                                                        <ArrowUp className="w-4 h-4" />
                                                                    </button>
                                                                    <button
                                                                        onClick={() => moveBanner(banner, 'down')}
                                                                        className="w-10 h-10 bg-zinc-50 text-zinc-600 rounded-xl flex items-center justify-center hover:bg-zinc-900 hover:text-white disabled:opacity-20 border border-zinc-100"
                                                                    >
                                                                        <ArrowDown className="w-4 h-4" />
                                                                    </button>
                                                                </div>
                                                            </div>

                                                            <div className="flex flex-wrap items-center gap-4 py-4 border-y border-zinc-50">
                                                                <div className="px-5 py-2.5 bg-zinc-50 rounded-2xl border border-zinc-100 text-[9px] font-black uppercase tracking-widest text-zinc-400 flex items-center gap-2">
                                                                    <ExternalLink className="w-3 h-3" />
                                                                    Destino: {banner.link || '/'}
                                                                </div>
                                                                <div className={`px-5 py-2.5 rounded-2xl border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 ${banner.active ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-red-50 border-red-100 text-red-500'}`}>
                                                                    <div className={`w-1.5 h-1.5 rounded-full ${banner.active ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`} />
                                                                    {banner.active ? 'Em Exibição' : 'Inativo'}
                                                                </div>
                                                            </div>

                                                            <div className="flex items-center justify-end gap-3 pt-2">
                                                                <button
                                                                    onClick={() => handleOpenDialog(banner)}
                                                                    className="h-12 px-6 bg-zinc-50 border border-zinc-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-zinc-600 hover:bg-zinc-900 hover:text-white transition-all flex items-center gap-2"
                                                                >
                                                                    <Edit className="w-3.5 h-3.5" /> Editar
                                                                </button>
                                                                <button
                                                                    onClick={() => handleDelete(banner.id, banner.imageUrl)}
                                                                    className="h-12 px-6 bg-red-50 border border-red-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-red-500 hover:bg-red-500 hover:text-white transition-all flex items-center gap-2"
                                                                >
                                                                    <Trash className="w-3.5 h-3.5" /> Excluir
                                                                </button>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>

            {/* Dialog de Edição Premium */}
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="sm:max-w-xl bg-white border-zinc-100 text-zinc-950 p-0 overflow-hidden rounded-[3rem] shadow-premium-lg">
                    <div className="p-10 space-y-8">
                        <DialogHeader>
                            <DialogTitle className="text-2xl font-black text-zinc-900 italic flex items-center gap-3">
                                {editingBanner ? 'Refinar Banner' : 'Esculpir Banner'}
                                <Sparkles className="w-5 h-5 text-amber-500" />
                            </DialogTitle>
                            <DialogDescription className="text-zinc-400 font-bold uppercase text-[10px] tracking-widest">
                                Configure as propriedades visuais da peça publicitária
                            </DialogDescription>
                        </DialogHeader>

                        <div className="space-y-6">
                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Imagem High-Fidelity</Label>
                                <div className="flex flex-col gap-4">
                                    {formData.imageUrl && (
                                        <div className="w-full aspect-[21/9] rounded-2xl overflow-hidden border border-zinc-100">
                                            <img src={formData.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                                        </div>
                                    )}
                                    <div className="relative">
                                        <Label htmlFor="banner-upload" className="cursor-pointer w-full h-16 flex items-center justify-center gap-3 bg-zinc-50 border-2 border-dashed border-zinc-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-zinc-300 hover:bg-zinc-100 hover:border-zinc-200 transition-all">
                                            {uploading ? 'Enviando p/ Nuvem...' : 'Fazer Upload de Peça'}
                                            <Upload className="w-4 h-4" />
                                        </Label>
                                        <Input id="banner-upload" type="file" accept="image/*" className="hidden" onChange={handleFileUpload} disabled={uploading} />
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Título Interno</Label>
                                <Input
                                    value={formData.title || ''}
                                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    placeholder="Ex: Campanha de Inverno VIP"
                                    className="h-16 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 text-base font-black transition-all"
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Posição</Label>
                                    <Select
                                        value={formData.position}
                                        onValueChange={(value: any) => setFormData({ ...formData, position: value })}
                                    >
                                        <SelectTrigger className="h-16 bg-zinc-50 border-zinc-100 rounded-2xl text-xs font-bold">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-white border-zinc-100">
                                            {positions.map(pos => (
                                                <SelectItem key={pos.value} value={pos.value}>{pos.label}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Ordem</Label>
                                    <Input
                                        type="number"
                                        value={formData.order ?? ''}
                                        onChange={(e) => setFormData({ ...formData, order: Number(e.target.value) })}
                                        className="h-16 bg-zinc-50 border-zinc-100 rounded-2xl text-xs font-bold"
                                    />
                                </div>
                            </div>

                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">CTA Redirect (Link)</Label>
                                <Input
                                    value={formData.link || ''}
                                    onChange={(e) => setFormData({ ...formData, link: e.target.value })}
                                    placeholder="/categoria/exclusivos"
                                    className="h-16 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 text-sm font-bold font-mono transition-all"
                                />
                            </div>

                            <div className="flex items-center justify-between p-6 bg-zinc-50 rounded-2xl border border-zinc-100">
                                <div className="space-y-1">
                                    <Label className="text-[10px] font-black text-zinc-900 uppercase tracking-widest flex items-center gap-2">
                                        Visibilidade Pública <Zap className="w-3 h-3 text-amber-500" />
                                    </Label>
                                    <p className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest">Ative para exibir instantaneamente na Home</p>
                                </div>
                                <Switch
                                    checked={formData.active}
                                    onCheckedChange={(checked) => setFormData({ ...formData, active: checked })}
                                    className="data-[state=checked]:bg-zinc-950"
                                />
                            </div>
                        </div>

                        <div className="flex gap-4 pt-4">
                            <Button
                                variant="ghost"
                                onClick={() => setIsDialogOpen(false)}
                                className="flex-1 h-16 rounded-2xl text-zinc-400 hover:text-zinc-900 hover:bg-zinc-50 text-[10px] font-black uppercase tracking-widest"
                            >
                                Cancelar
                            </Button>
                            <Button
                                onClick={handleSubmit}
                                disabled={uploading}
                                className="flex-[2] h-16 rounded-2xl bg-zinc-950 text-white hover:bg-black text-[10px] font-black uppercase tracking-widest shadow-premium transition-all active:scale-95"
                            >
                                Finalizar Peça Publicitária
                            </Button>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Plus, Trash, Edit, ArrowLeft, Ticket, Percent, Coins, Users, Calendar, Sparkles } from 'lucide-react';
import { useCoupons } from '@/hooks/useCoupons';
import type { Coupon } from '@/types';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

interface AdminCouponsViewProps {
    onNavigate: (view: any) => void;
}

export function AdminCouponsView({ onNavigate }: AdminCouponsViewProps) {
    const { coupons, loading, addCoupon, updateCoupon, deleteCoupon, getCouponStats } = useCoupons();
    const [stats, setStats] = useState<any>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingCoupon, setEditingCoupon] = useState<Coupon | null>(null);
    const [formData, setFormData] = useState<Partial<Coupon>>({
        code: '',
        type: 'percentage',
        value: 0,
        active: true,
        usageLimit: 0,
        minPurchase: 0,
        validUntil: undefined
    });

    useEffect(() => {
        const fetchStats = async () => {
            const data = await getCouponStats();
            setStats(data);
        };
        fetchStats();
    }, [getCouponStats, coupons]);

    const handleOpenDialog = (coupon?: Coupon) => {
        if (coupon) {
            setEditingCoupon(coupon);
            setFormData({ ...coupon });
        } else {
            setEditingCoupon(null);
            setFormData({
                code: '',
                type: 'percentage',
                value: 0,
                active: true,
                usageLimit: 0,
                minPurchase: 0,
                validUntil: undefined
            });
        }
        setIsDialogOpen(true);
    };

    const handleSubmit = async () => {
        try {
            if (!formData.code || formData.value! <= 0) {
                toast.error('O código e o valor (maior que 0) são obrigatórios');
                return;
            }
            if (formData.type === 'percentage' && formData.value! > 100) {
                toast.error('Porcentagem não pode exceder 100%');
                return;
            }
            // Ensure numbers are positive
            const sanitizedData = {
                ...formData,
                value: Math.max(0, formData.value || 0),
                minPurchase: Math.max(0, formData.minPurchase || 0),
                usageLimit: Math.max(0, formData.usageLimit || 0)
            };

            if (editingCoupon) {
                await updateCoupon(editingCoupon.id, sanitizedData);
            } else {
                await addCoupon(sanitizedData as Required<Omit<Coupon, 'id' | 'usageCount'>>);
            }
            setIsDialogOpen(false);
        } catch {
            // Error handled in hook
        }
    };

    const handleDelete = async (id: string) => {
        if (confirm('Tem certeza que deseja excluir este cupom?')) {
            await deleteCoupon(id);
        }
    };

    return (
        <div className="min-h-screen bg-zinc-50/30 text-zinc-950 pb-32">
            {/* Header Executivo */}
            <div className="glass px-6 py-6 sticky top-0 z-50 border-b border-zinc-100">
                <div className="max-w-5xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => onNavigate('admin-dashboard')}
                            className="w-12 h-12 flex items-center justify-center bg-zinc-100 text-zinc-600 rounded-2xl hover:bg-zinc-200 transition-all active:scale-95 border border-zinc-200 group"
                        >
                            <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                        </button>
                        <div>
                            <h1 className="text-xl font-black text-zinc-900 tracking-tight flex items-center gap-2">
                                Cupons <Sparkles className="w-4 h-4 text-emerald-600" />
                            </h1>
                            <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.2em]">{coupons.length} Estratégias Ativas</p>
                        </div>
                    </div>
                    <button
                        onClick={() => handleOpenDialog()}
                        className="flex items-center gap-3 px-6 py-3.5 bg-zinc-950 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] hover:bg-black transition-all active:scale-95 shadow-premium"
                    >
                        <Plus className="w-4 h-4" />
                        Criar Oferta
                    </button>
                </div>
            </div>

            <div className="max-w-5xl mx-auto p-6 space-y-8">
                {/* Dashboard Rápido de Cupons */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    {[
                        { label: 'Cupons Ativos', value: stats?.active_coupons ?? coupons.filter(c => c.active).length, icon: Ticket, color: 'text-emerald-500' },
                        { label: 'Uso Total', value: stats?.total_uses ?? coupons.reduce((acc, c) => acc + (c.usageCount ?? 0), 0), icon: Users, color: 'text-blue-500' },
                        { label: 'Média Desconto', value: stats?.avg_discount ? `${Number(stats.avg_discount).toFixed(1)}%` : '...', icon: Percent, color: 'text-emerald-500' },
                        { label: 'Total Cupons', value: stats?.total_coupons ?? coupons.length, icon: Sparkles, color: 'text-amber-500' },
                    ].map((stat, i) => (
                        <div key={i} className="bg-white border border-zinc-100 p-4 rounded-3xl shadow-premium-sm">
                            <stat.icon className={`w-4 h-4 ${stat.color} mb-3`} />
                            <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mb-1">{stat.label}</p>
                            <p className="text-xl font-black text-zinc-900 tracking-tighter">{stat.value}</p>
                        </div>
                    ))}
                </div>

                {loading ? (
                    <div className="text-center py-20 flex flex-col items-center">
                        <div className="w-12 h-12 border-2 border-zinc-100 border-t-zinc-900 rounded-full animate-spin mb-4" />
                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.3em] animate-pulse">Sincronizando Vault...</p>
                    </div>
                ) : coupons.length === 0 ? (
                    <div className="bg-white p-20 rounded-[3rem] border border-zinc-100 shadow-premium-sm text-center">
                        <div className="w-20 h-20 bg-zinc-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6">
                            <Ticket className="w-10 h-10 text-zinc-300" />
                        </div>
                        <p className="text-sm font-bold text-zinc-400 uppercase tracking-widest">Nenhuma campanha estratégica ativa</p>
                        <Button variant="link" onClick={() => handleOpenDialog()} className="mt-4 text-emerald-600 font-black uppercase text-[10px] tracking-widest">Ativar Primeira Oferta</Button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {coupons.map((coupon) => (
                            <div
                                key={coupon.id}
                                className={`group relative bg-white border border-zinc-100 rounded-[2.5rem] p-8 transition-all hover:border-zinc-200 hover:shadow-premium ${!coupon.active ? 'opacity-40 grayscale pointer-events-none' : ''}`}
                            >
                                <div className="absolute top-6 right-6 flex gap-2">
                                    <button
                                        onClick={() => handleOpenDialog(coupon)}
                                        className="w-10 h-10 flex items-center justify-center bg-zinc-50 text-zinc-400 rounded-xl hover:bg-zinc-900 hover:text-white transition-all border border-zinc-100"
                                    >
                                        <Edit className="w-4 h-4" />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(coupon.id)}
                                        className="w-10 h-10 flex items-center justify-center bg-red-50 text-red-500 rounded-xl hover:bg-red-600 hover:text-white transition-all border border-red-100"
                                    >
                                        <Trash className="w-4 h-4" />
                                    </button>
                                </div>

                                <div className="space-y-6">
                                    <div className="flex flex-col gap-1">
                                        <span className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.3em] mb-2 px-3 py-1 bg-emerald-50 rounded-full self-start border border-emerald-100 shadow-premium-sm">
                                            {coupon.type === 'percentage' ? `${coupon.value}% OFF` : `R$ ${coupon.value.toFixed(2)} OFF`}
                                        </span>
                                        <h2 className="text-3xl font-black text-zinc-900 tracking-tighter leading-none group-hover:scale-105 transition-transform origin-left">
                                            {coupon.code}
                                        </h2>
                                    </div>

                                    <div className="grid grid-cols-2 gap-4 pb-6 border-b border-white/5">
                                        <div>
                                            <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                                                <Coins className="w-3 h-3" /> Mínimo
                                            </p>
                                            <p className="text-sm font-black text-zinc-900 font-mono tracking-tight">
                                                {coupon.minPurchase ? `R$ ${coupon.minPurchase.toFixed(2)}` : 'S/ Limite'}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                                                <Calendar className="w-3 h-3" /> Validade
                                            </p>
                                            <p className="text-sm font-black text-zinc-900 font-mono tracking-tight">
                                                {coupon.validUntil ? new Date(coupon.validUntil).toLocaleDateString() : '∞'}
                                            </p>
                                        </div>
                                    </div>

                                    <div>
                                        <div className="flex items-center justify-between mb-3">
                                            <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em]">Desempenho da Oferta</p>
                                            <p className="text-xs font-black text-zinc-900 tabular-nums">
                                                {coupon.usageCount ?? 0} <span className="text-zinc-300">/</span> {coupon.usageLimit || '∞'}
                                            </p>
                                        </div>
                                        {coupon.usageLimit ? (
                                            <div className="h-2 w-full bg-zinc-50 rounded-full overflow-hidden border border-zinc-100 p-[1px] shadow-inner">
                                                <div
                                                    className="h-full bg-gradient-to-r from-emerald-500 to-sky-500 rounded-full transition-all duration-1000 shadow-premium-sm"
                                                    style={{ width: `${Math.min(((coupon.usageCount ?? 0) / coupon.usageLimit) * 100, 100)}%` }}
                                                />
                                            </div>
                                        ) : (
                                            <div className="flex gap-1">
                                                {[...Array(5)].map((_, i) => (
                                                    <div key={i} className="h-1 flex-1 bg-zinc-100 rounded-full" />
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="bg-white border-zinc-100 text-zinc-950 p-8 rounded-[3rem] shadow-premium-lg">
                    <DialogHeader className="mb-6">
                        <DialogTitle className="text-2xl font-black tracking-tighter uppercase italic text-zinc-900">
                            {editingCoupon ? 'Editar Estratégia' : 'Nova Campanha'}
                        </DialogTitle>
                    </DialogHeader>
                    <div className="space-y-6">
                        <div className="space-y-3">
                            <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Código Promocional</Label>
                            <Input
                                value={formData.code}
                                onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                                placeholder="EX: LUXO2024"
                                className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 text-lg font-black tracking-widest uppercase placeholder:text-zinc-300 transition-all focus:bg-white"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Tipo de Incentivo</Label>
                                <Select
                                    value={formData.type}
                                    onValueChange={(value: any) => setFormData({ ...formData, type: value })}
                                >
                                    <SelectTrigger className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl text-xs font-bold uppercase tracking-widest">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent className="bg-white border-zinc-100">
                                        <SelectItem value="percentage">Porcentagem (%)</SelectItem>
                                        <SelectItem value="fixed">Valor Fixo (R$)</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Valor do Desconto</Label>
                                <Input
                                    type="number"
                                    value={formData.value}
                                    onChange={(e) => setFormData({ ...formData, value: Number(e.target.value) })}
                                    className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 font-black"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Ticket Mínimo (R$)</Label>
                                <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={formData.minPurchase || ''}
                                    onChange={(e) => setFormData({ ...formData, minPurchase: Math.max(0, Number(e.target.value)) })}
                                    className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 font-black"
                                />
                            </div>
                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Limite Global de Usos</Label>
                                <Input
                                    type="number"
                                    min="0"
                                    value={formData.usageLimit || ''}
                                    onChange={(e) => setFormData({ ...formData, usageLimit: Math.max(0, Number(e.target.value)) })}
                                    placeholder="Ilimitado"
                                    className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 font-black"
                                />
                            </div>
                        </div>

                        <div className="space-y-3">
                            <Label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Validade do Cupom (Opcional)</Label>
                            <Input
                                type="datetime-local"
                                value={formData.validUntil ? new Date(formData.validUntil).toISOString().slice(0, 16) : ''}
                                onChange={(e) => setFormData({ ...formData, validUntil: e.target.value ? new Date(e.target.value).toISOString() : undefined })}
                                className="h-14 bg-zinc-50 border-zinc-100 rounded-2xl focus:ring-zinc-900 font-black text-xs uppercase tracking-widest text-zinc-600 block w-full"
                            />
                        </div>

                        <div className="flex items-center justify-between p-6 bg-zinc-50 rounded-3xl border border-zinc-100 shadow-inner">
                            <div className="flex flex-col gap-1">
                                <Label className="text-xs font-black uppercase tracking-widest leading-none text-zinc-900">Status da Campanha</Label>
                                <p className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest">Ativar imediatamente após salvar</p>
                            </div>
                            <Switch
                                checked={formData.active}
                                onCheckedChange={(checked) => setFormData({ ...formData, active: checked })}
                                className="data-[state=checked]:bg-zinc-950"
                            />
                        </div>
                    </div>
                    <DialogFooter className="mt-8 gap-4 sm:justify-center">
                        <Button variant="ghost" onClick={() => setIsDialogOpen(false)} className="h-14 px-8 text-zinc-400 hover:text-zinc-900 hover:bg-zinc-50 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all">Cancelar</Button>
                        <Button onClick={handleSubmit} className="h-14 px-10 bg-zinc-950 text-white hover:bg-black rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all shadow-premium active:scale-95">Salvar Estratégia</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import type { View } from '@/types';
import {
    Users,
    Search,
    Mail,
    Phone,
    Calendar,
    MoreHorizontal,
    Shield,
    ArrowUpDown,
    Filter,
    ArrowLeft,
    TrendingUp,
    ShoppingBag,
    Wallet,
    Zap
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { toast } from 'sonner';

interface Customer {
    id: string;
    email: string | null;
    full_name: string | null;
    phone: string | null;
    role: string;
    created_at: string;
    orders_count?: number;
    total_spent?: number;
    last_order_date?: string;
    avatar_url?: string;
    is_push_subscribed?: boolean;
}

interface AdminCustomersViewProps {
    onNavigate: (view: View, id?: string) => void;
}

export function AdminCustomersView({ onNavigate }: AdminCustomersViewProps) {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [sortField, setSortField] = useState<keyof Customer>('created_at');
    const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');
    const [totalCustomers, setTotalCustomers] = useState(0);
    const [page, setPage] = useState(0);
    const pageSize = 10;

    useEffect(() => {
        // Debounce search
        const handler = setTimeout(() => {
            fetchCustomers();
        }, 300);
        return () => clearTimeout(handler);
    }, [searchTerm, sortField, sortDirection, page]);


    const fetchCustomers = async () => {
        try {
            setLoading(true);

            const { data, error } = await (supabase.rpc as any)('get_admin_customers_paged', {
                p_search: searchTerm,
                p_sort_field: sortField,
                p_sort_direction: sortDirection,
                p_page: page,
                p_page_size: pageSize
            });

            if (error) throw error;

            if (data) {
                setCustomers(data.data || []);
                setTotalCustomers(data.total_count || 0);
            }
        } catch (error) {
            console.error('Error fetching customers:', error);
            toast.error('Erro ao carregar clientes');
        } finally {
            setLoading(false);
        }
    };

    const totalPages = Math.ceil(totalCustomers / pageSize);
    const paginatedCustomers = customers; // Already paginated from server

    const handleSort = (field: keyof Customer) => {
        if (sortField === field) {
            setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
        } else {
            setSortField(field);
            setSortDirection('asc');
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-zinc-50/50 flex flex-col items-center justify-center p-10">
                <div className="w-12 h-12 border-2 border-zinc-200 border-t-zinc-900 rounded-full animate-spin mb-6" />
                <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.3em]">Carregando base de clientes...</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-zinc-50/30 pb-32">
            {/* Header */}
            <div className="glass px-8 py-8 flex flex-col md:flex-row md:items-center justify-between sticky top-0 z-50 border-b border-zinc-100 gap-6">
                <div>
                    <h1 className="text-2xl font-black text-zinc-900 tracking-tighter flex items-center gap-3">
                        <Users className="w-6 h-6 text-zinc-900" />
                        Clientes
                    </h1>
                    <p className="text-[11px] font-bold text-zinc-400 uppercase tracking-[0.2em] mt-1 pl-9">
                        Gestão da Base ({totalCustomers})
                    </p>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <Button
                        variant="outline"
                        onClick={() => fetchCustomers()}
                        className="rounded-xl border-zinc-200 h-10 px-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-50"
                    >
                        Atualizar
                    </Button>
                    <div className="relative group w-full md:w-80">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Search className="h-4 w-4 text-zinc-400" />
                        </div>
                        <Input
                            type="text"
                            placeholder="Buscar por nome ou email..."
                            className="pl-10 h-10 rounded-xl border-zinc-200 bg-white focus:ring-zinc-900 focus:border-zinc-900 transition-all font-medium text-sm"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Button variant="outline" size="icon" className="rounded-xl border-zinc-200 hover:bg-zinc-50">
                        <Filter className="w-4 h-4 text-zinc-500" />
                    </Button>
                </div>
            </div>

            <main className="max-w-7xl mx-auto px-6 py-8 space-y-8">
                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                    {[
                        { label: 'Total Clientes', value: totalCustomers, icon: Users, color: 'text-zinc-900', bg: 'bg-zinc-100' },
                        { label: 'Novos (30d)', value: customers.filter(c => new Date(c.created_at) > new Date(Date.now() - 30 * 24 * 60 * 60 * 1000)).length, icon: TrendingUp, color: 'text-emerald-600', bg: 'bg-emerald-50' },
                        { label: 'Ticket Médio', value: `R$ ${(customers.reduce((acc, c) => acc + (c.total_spent || 0), 0) / (customers.length || 1)).toFixed(2)}`, icon: Wallet, color: 'text-blue-600', bg: 'bg-blue-50' },
                        { label: 'Pedidos Totais', value: customers.reduce((acc, c) => acc + (c.orders_count || 0), 0), icon: ShoppingBag, color: 'text-amber-600', bg: 'bg-amber-50' }
                    ].map((stat, i) => (
                        <Card key={i} className="rounded-[2rem] border-zinc-100 p-6 shadow-premium-sm hover:shadow-premium transition-all">
                            <div className="flex items-center justify-between mb-4">
                                <div className={`w-10 h-10 ${stat.bg} ${stat.color} rounded-xl flex items-center justify-center`}>
                                    <stat.icon className="w-5 h-5" />
                                </div>
                                <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">{stat.label}</span>
                            </div>
                            <h3 className="text-2xl font-black text-zinc-900 tracking-tighter">{stat.value}</h3>
                        </Card>
                    ))}
                </div>
                <div className="bg-white border border-zinc-100 rounded-[2.5rem] shadow-premium overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead>
                                <tr className="border-b border-zinc-100 bg-zinc-50/50">
                                    <th className="text-left py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400 cursor-pointer hover:text-zinc-600 transition-colors" onClick={() => handleSort('full_name')}>
                                        <div className="flex items-center gap-2">Cliente <ArrowUpDown className="w-3 h-3" /></div>
                                    </th>
                                    <th className="text-left py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400 cursor-pointer hover:text-zinc-600 transition-colors" onClick={() => handleSort('role')}>
                                        <div className="flex items-center gap-2">Status / Role <ArrowUpDown className="w-3 h-3" /></div>
                                    </th>
                                    <th className="text-left py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400 cursor-pointer hover:text-zinc-600 transition-colors" onClick={() => handleSort('total_spent')}>
                                        <div className="flex items-center gap-2">LTV (Total Gasto) <ArrowUpDown className="w-3 h-3" /></div>
                                    </th>
                                    <th className="text-left py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400 cursor-pointer hover:text-zinc-600 transition-colors" onClick={() => handleSort('orders_count')}>
                                        <div className="flex items-center gap-2">Pedidos <ArrowUpDown className="w-3 h-3" /></div>
                                    </th>
                                    <th className="text-left py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400 cursor-pointer hover:text-zinc-600 transition-colors" onClick={() => handleSort('last_order_date')}>
                                        <div className="flex items-center gap-2">Última Atividade <ArrowUpDown className="w-3 h-3" /></div>
                                    </th>
                                    <th className="text-right py-4 px-6 text-[10px] font-black uppercase tracking-wider text-zinc-400">Ações</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-zinc-50">
                                {paginatedCustomers.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="py-12 text-center">
                                            <div className="flex flex-col items-center justify-center text-zinc-400">
                                                <Users className="w-12 h-12 mb-4 opacity-20" />
                                                <p className="text-sm font-bold">Nenhum cliente encontrado</p>
                                            </div>
                                        </td>
                                    </tr>
                                ) : (
                                    paginatedCustomers.map((customer) => (
                                        <tr
                                            key={customer.id}
                                            className="group hover:bg-zinc-50/80 transition-colors cursor-pointer"
                                            onClick={() => onNavigate('admin-user-detail', customer.id)}
                                        >
                                            <td className="py-4 px-6">
                                                <div className="flex items-center gap-4">
                                                    <Avatar className="h-10 w-10 border border-zinc-100">
                                                        <AvatarImage src={customer.avatar_url} />
                                                        <AvatarFallback className="bg-zinc-100 text-zinc-500 font-bold text-xs">{customer.full_name?.substring(0, 2).toUpperCase()}</AvatarFallback>
                                                    </Avatar>
                                                    <div>
                                                        <div className="flex items-center gap-2">
                                                            <p className="text-sm font-bold text-zinc-900 leading-tight">{customer.full_name}</p>
                                                            {customer.is_push_subscribed && (
                                                                <Zap className="w-3 h-3 text-amber-500 fill-amber-500 animate-pulse" />
                                                            )}
                                                        </div>
                                                        <p className="text-[10px] font-medium text-zinc-400 uppercase tracking-wide">ID: {customer.id.slice(0, 8)}</p>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="py-4 px-6">
                                                <div className="space-y-1">
                                                    <div className="flex items-center gap-2 text-xs font-medium text-zinc-600">
                                                        <Mail className="w-3 h-3 text-zinc-400" />
                                                        {customer.email}
                                                    </div>
                                                    {customer.phone && (
                                                        <div className="flex items-center gap-2 text-xs font-medium text-zinc-600">
                                                            <Phone className="w-3 h-3 text-zinc-400" />
                                                            {customer.phone}
                                                        </div>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="py-4 px-6">
                                                <Badge variant={customer.role === 'admin' ? 'default' : 'secondary'} className={customer.role === 'admin' ? 'bg-zinc-900 hover:bg-black' : 'bg-zinc-100 text-zinc-600 hover:bg-zinc-200'}>
                                                    {customer.role === 'admin' && <Shield className="w-3 h-3 mr-1" />}
                                                    <span className="uppercase text-[9px] font-black tracking-widest">{customer.role}</span>
                                                </Badge>
                                            </td>
                                            <td className="py-4 px-6">
                                                <div className="text-sm font-black text-zinc-900 tracking-tight">
                                                    R$ {Number(customer.total_spent || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                                </div>
                                            </td>
                                            <td className="py-4 px-6 text-center">
                                                <div className="w-8 h-8 rounded-lg bg-zinc-50 flex items-center justify-center text-xs font-black text-zinc-600 border border-zinc-100">
                                                    {customer.orders_count || 0}
                                                </div>
                                            </td>
                                            <td className="py-4 px-6">
                                                <div className="flex items-center gap-2 text-xs font-medium text-zinc-500">
                                                    <Calendar className="w-3 h-3 text-zinc-300" />
                                                    {customer.last_order_date ? new Date(customer.last_order_date).toLocaleDateString() : 'Nenhuma'}
                                                </div>
                                            </td>
                                            <td className="py-4 px-6 text-right">
                                                <DropdownMenu>
                                                    <DropdownMenuTrigger asChild>
                                                        <Button variant="ghost" size="icon" className="rounded-xl hover:bg-zinc-200 text-zinc-400 hover:text-zinc-600">
                                                            <MoreHorizontal className="w-4 h-4" />
                                                        </Button>
                                                    </DropdownMenuTrigger>
                                                    <DropdownMenuContent align="end" className="w-[160px] rounded-xl border-zinc-100 shadow-premium p-1">
                                                        <DropdownMenuLabel className="text-[10px] uppercase tracking-widest text-zinc-400 p-2">Ações do Cliente</DropdownMenuLabel>
                                                        <DropdownMenuSeparator className="bg-zinc-100" />
                                                        <DropdownMenuItem
                                                            className="rounded-lg text-xs font-bold cursor-pointer focus:bg-zinc-50"
                                                            onClick={() => onNavigate('admin-push')}
                                                        >
                                                            Enviar Push
                                                        </DropdownMenuItem>
                                                        <DropdownMenuSeparator className="bg-zinc-100" />
                                                        <DropdownMenuItem className="rounded-lg text-xs font-bold cursor-pointer text-red-600 focus:bg-red-50 focus:text-red-700">
                                                            Bloquear Acesso
                                                        </DropdownMenuItem>
                                                    </DropdownMenuContent>
                                                </DropdownMenu>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                    {totalPages > 1 && (
                        <div className="flex items-center justify-between px-6 py-4 border-t border-zinc-100 bg-zinc-50/50">
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(prev => Math.max(0, prev - 1))}
                                disabled={page === 0}
                                className="h-8 w-8 rounded-xl border-zinc-200"
                            >
                                <ArrowLeft className="h-4 w-4" />
                            </Button>
                            <span className="text-[11px] font-black uppercase tracking-widest text-zinc-500">
                                Página <span className="text-zinc-900">{page + 1}</span> de <span className="text-zinc-900">{totalPages}</span>
                            </span>
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(prev => Math.min(totalPages - 1, prev + 1))}
                                disabled={page === totalPages - 1}
                                className="h-8 w-8 rounded-xl border-zinc-200"
                            >
                                <ArrowLeft className="h-4 w-4 rotate-180" />
                            </Button>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
}

