            key={i}
            className="snap-start flex-shrink-0 flex items-center gap-3 p-3 bg-white/60 backdrop-blur-xl rounded-2xl border border-white/50 shadow-sm hover:border-red-200/50 transition-all duration-300 group min-w-[200px]"
          >
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors shadow-inner ${item.current_stock <= 3 ? 'bg-red-50 text-red-600' : 'bg-zinc-50 text-zinc-400'}`}>
