              <div className="flex items-center gap-2">
                <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-tighter bg-white/50 px-1.5 py-0.5 rounded">Estoque: {item.current_stock}</span>
                {item.days_remaining && item.days_remaining < 7 && (
                  <span className="text-[8px] font-black text-red-500 uppercase leading-none bg-red-50 px-1.5 py-0.5 rounded border border-red-100">~{Math.round(item.days_remaining)}d</span>
                )}
