export function AdminDashboardView({ onNavigate }: AdminDashboardViewProps) {
  const { fetchOrders, fetchDashboardSummary, orders } = useOrders();
  const { fetchInventoryHealth } = useAnalytics();
  const [loadingSummary, setLoadingSummary] = useState(true);
  const [loadingHealth, setLoadingHealth] = useState(true);
  const [loadingOrders, setLoadingOrders] = useState(true);
  const [inventoryHealth, setInventoryHealth] = useState<any[]>([]);
  const [stats, setStats] = useState<DashboardSummary>({
    today: { count: 0, revenue: 0, pending: 0 },
    month: { count: 0, revenue: 0, pending: 0 },
    averageTicket: 0,
    revenueHistory: [],
    topProducts: [],
  });

  useEffect(() => {
    const loadFullDashboard = async () => {
      // 1. Fetch Summary (Progressive)
      fetchDashboardSummary().then((summaryData) => {
        if (summaryData) {
          setStats({
            today: summaryData.today,
            month: summaryData.month,
            averageTicket: summaryData.averageTicket,
            revenueHistory: summaryData.revenueHistory,
            topProducts: summaryData.topProducts
          });
        }
        setLoadingSummary(false);
      }).catch(err => {
        console.error('Failed to load summary', err);
        setLoadingSummary(false);
      });

      // 2. Fetch Inventory Health (Progressive)
      fetchInventoryHealth().then((data) => {
        setInventoryHealth(data);
        setLoadingHealth(false);
      }).catch(err => {
        console.error('Failed to load inventory', err);
        setLoadingHealth(false);
      });

      // 3. Fetch Critical Orders (Progressive)
      // We fetch more orders to find the pending ones, or use a specific filter
      fetchOrders(50).then(() => {
        setLoadingOrders(false);
      }).catch(err => {
        console.error('Failed to load recent orders', err);
        setLoadingOrders(false);
      });
    };

    loadFullDashboard();
  }, [fetchOrders, fetchDashboardSummary, fetchInventoryHealth]);


  const pendingOrders = orders.filter(o => o.status === 'new' || o.status === 'processing');

  const kpiCards = [
    {
      label: 'Vendas Hoje',
      value: `R$ ${(stats?.today?.revenue || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      subValue: `${stats?.today?.count || 0} pedidos`,
      icon: DollarSign,
      color: "bg-emerald-500 text-white border-emerald-400",
      trend: stats?.today?.revenueTrend !== undefined ? `${stats.today.revenueTrend > 0 ? '+' : ''}${stats.today.revenueTrend}%` : "0%"
    },
    {
      label: 'Faturamento Mês',
      value: `R$ ${(stats?.month?.revenue || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      subValue: "Mês atual",
      icon: TrendingUp,
      color: "bg-zinc-900 text-white border-zinc-700",
      trend: stats?.month?.revenueTrend !== undefined ? `${stats.month.revenueTrend > 0 ? '+' : ''}${stats.month.revenueTrend}%` : "0%"
    },
    {
      label: 'Ticket Médio',
      value: `R$ ${(stats?.averageTicket || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      subValue: "Por pedido",
      icon: Star,
      color: "bg-amber-500 text-white border-amber-400",
      trend: stats?.executive?.avgTicketTrend !== undefined ? `${stats.executive.avgTicketTrend > 0 ? '+' : ''}${stats.executive.avgTicketTrend}%` : "0%"
    },
    {
      label: 'Pendentes',
      value: (stats?.today?.pending || 0).toString(),
      subValue: "Aguardando ação",
      icon: Package,
      color: "bg-rose-500 text-white border-rose-400",
      trend: (stats?.today?.pending || 0) > 0 ? "Urgente" : "Ok"
    },
  ];

  const quickActions = [
    { label: 'Novo Produto', icon: Plus, color: 'bg-zinc-900', onClick: () => onNavigate('admin-product-form') },
    { label: 'Pedidos', icon: ShoppingBag, color: 'bg-zinc-800', onClick: () => onNavigate('admin-orders') },
    { label: 'Cupons', icon: Ticket, color: 'bg-zinc-700', onClick: () => onNavigate('admin-coupons') },
    { label: 'Analytics', icon: Activity, color: 'bg-zinc-600', onClick: () => onNavigate('admin-analytics') },
    { label: 'Banners', icon: ImageIcon, color: 'bg-zinc-500', onClick: () => onNavigate('admin-banners') },
  ];

  return (
    <div className="min-h-screen bg-zinc-50/30 pb-24 font-sans text-zinc-900">
      <main className="max-w-7xl mx-auto px-4 md:px-6 py-4 space-y-10">
        {/* Inventory Alert Block */}
        {loadingHealth ? (
          <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
            {[1, 2, 3].map(i => <Skeleton key={i} className="h-20 w-64 rounded-2xl shrink-0" />)}
          </div>
        ) : (
          <InventoryHealthWidget items={inventoryHealth} />
        )}

        {/* KPI Grid */}
        {/* Premium KPI Dashboard Panel */}
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-zinc-200 to-zinc-100 rounded-[2.5rem] blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
          <Card className="relative border border-white/20 shadow-2xl rounded-[2.5rem] overflow-hidden bg-white/80 backdrop-blur-xl">
            <div className="absolute top-0 right-0 w-64 h-64 bg-zinc-900/5 rounded-full -mr-32 -mt-32 blur-3xl pointer-events-none" />

            <div className="grid grid-cols-2 md:grid-cols-4 divide-x divide-zinc-100">
              {kpiCards.map((stat, index) => (
                <div key={index} className="p-5 md:p-8 flex flex-col justify-between hover:bg-zinc-50/50 transition-colors group/card">
                  {loadingSummary ? (
                    <div className="space-y-4">
                      <div className="flex justify-between">
                        <Skeleton className="h-10 w-10 rounded-xl" />
                        <Skeleton className="h-4 w-12 rounded-lg" />
                      </div>
                      <div className="space-y-2">
                        <Skeleton className="h-8 w-32" />
                        <Skeleton className="h-4 w-24" />
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="flex justify-between items-start mb-4">
                        <div className={cn(
                          "w-10 h-10 rounded-xl flex items-center justify-center border shadow-sm",
                          index === 0 ? "bg-emerald-50 border-emerald-100 text-emerald-600" :
                            index === 1 ? "bg-zinc-900 border-zinc-800 text-white" :
                              index === 2 ? "bg-amber-50 border-amber-100 text-amber-600" :
                                "bg-rose-50 border-rose-100 text-rose-600"
                        )}>
                          <stat.icon className="w-5 h-5" />
                        </div>
                        <span className={cn(
                          "text-[9px] font-black uppercase tracking-wider px-2 py-1 rounded-lg border",
                          stat.trend.startsWith('+') ? "bg-emerald-50 text-emerald-600 border-emerald-100" :
                            stat.trend.startsWith('-') ? "bg-rose-50 text-rose-600 border-rose-100" :
                              "bg-zinc-100 text-zinc-500 border-zinc-200"
