        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Chart */}
          <Card className="lg:col-span-2 border border-white/20 shadow-premium rounded-3xl overflow-hidden glass">
            <CardHeader className="flex flex-row items-center justify-between pb-8">
              <div>
                <CardTitle className="text-lg font-black tracking-tight">Performance Semanal</CardTitle>
                <CardDescription className="text-xs font-medium uppercase tracking-wider">Faturamento (últimos 7 dias)</CardDescription>
              </div>
              <Button variant="outline" size="sm" className="rounded-xl font-black text-[10px] uppercase tracking-widest border-zinc-200 hover:bg-zinc-50" onClick={() => onNavigate('admin-analytics')}>
                Analytics <ArrowUpRight className="ml-1 w-3 h-3" />
              </Button>
            </CardHeader>
            <CardContent>
              {loadingSummary ? (
                <Skeleton className="h-[300px] w-full rounded-2xl" />
              ) : (
                <div className="h-[300px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={stats.revenueHistory}>
                      <defs>
                        <linearGradient id="barGradient" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="0%" stopColor="#18181b" stopOpacity={1} />
                          <stop offset="100%" stopColor="#3f3f46" stopOpacity={1} />
