                        axisLine={false}
                        tickLine={false}
                        fontSize={10}
                        tick={{ fill: '#a1a1aa', fontWeight: 700 }}
                        dy={10}
                      />
                      <Tooltip
                        cursor={{ fill: '#f4f4f5', radius: 4, opacity: 0.5 }}
                        contentStyle={{
                          borderRadius: '16px',
                          border: '1px solid rgba(255,255,255,0.5)',
                          boxShadow: '0 8px 32px rgba(0,0,0,0.1)',
                          padding: '12px',
                          backgroundColor: 'rgba(255,255,255,0.8)',
                          backdropFilter: 'blur(12px)',
                          minWidth: '150px'
                        }}
                        itemStyle={{ fontWeight: 900, color: '#09090b', fontSize: '12px', letterSpacing: '-0.02em' }}
                        labelStyle={{ fontWeight: 800, color: '#71717a', marginBottom: '8px', fontSize: '9px', textTransform: 'uppercase', letterSpacing: '0.1em' }}
                      />
                      <Bar dataKey="revenue" radius={[10, 10, 0, 0]} barSize={32}>
                        {(stats.revenueHistory || []).map((_, index) => (
                          <Cell
                            key={`cell-${index}`}
                            fill={index === (stats.revenueHistory || []).length - 1 ? 'url(#barGradient)' : '#f4f4f5'}
                            className="transition-all duration-300 hover:opacity-80"
                          />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Quick Actions Panel */}
          <div className="space-y-4">
            <h3 className="text-sm font-black uppercase tracking-widest text-zinc-400 px-1">Atalhos do Ninja</h3>
            <div className="grid grid-cols-1 gap-3">
              {quickActions.map((action) => (
                <button
                  key={action.label}
                  onClick={action.onClick}
                  className={cn(
                    "group flex items-center justify-between p-4 rounded-2xl text-white transition-all duration-300 hover:translate-x-1 active:scale-95 shadow-sm",
                    action.color
                  )}
                >
                  <div className="flex items-center gap-4">
                    <div className="p-2 bg-white/20 rounded-xl">
                      <action.icon className="w-5 h-5" />
                    </div>
                    <span className="font-bold text-sm tracking-tight">{action.label}</span>
                  </div>
                  <ChevronRight className="w-5 h-5 opacity-40 group-hover:opacity-100 transition-opacity" />
                </button>
              ))}
              <button
                onClick={() => onNavigate('admin-settings')}
                className="flex items-center justify-center gap-2 p-4 glass border border-white/20 rounded-2xl text-zinc-600 font-bold text-sm hover:bg-white/50 transition-colors"
              >
                <Settings className="w-4 h-4" /> Configurações Gerais
              </button>
            </div>
          </div>
        </div>

        {/* Lists Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-12">
          {/* Critical Orders */}
          <Section CardTitle="Pedidos Críticos" icon={AlertCircle}>
            <div className="divide-y divide-zinc-50">
              {loadingOrders ? (
                <div className="p-6 space-y-4">
                  {[1, 2, 3].map(i => <Skeleton key={i} className="h-16 w-full rounded-2xl" />)}
                </div>
              ) : pendingOrders.length === 0 ? (
                <div className="p-12 text-center bg-zinc-50/50">
                  <Package className="w-12 h-12 text-zinc-200 mx-auto mb-3" />
                  <p className="text-sm font-bold text-zinc-400">Tudo em dia por aqui!</p>
                </div>
              ) : (
                pendingOrders.slice(0, 5).map((order) => (
                  <div key={order.id} onClick={() => onNavigate('admin-orders')} className="group p-5 hover:bg-zinc-50 transition-all duration-300 cursor-pointer">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-2xl bg-zinc-50 border border-zinc-100 flex items-center justify-center text-zinc-400 group-hover:bg-zinc-900 group-hover:border-zinc-900 group-hover:text-white transition-all">
                          <ShoppingBag className="w-5 h-5" />
                        </div>
                        <div>
                          <p className="text-sm font-black text-zinc-900">
                            {order.customer.name}
                          </p>
                          <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">
                            #{order.id.slice(-6).toUpperCase()} • {(order.total || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                          </p>
                        </div>
                      </div>
                      <ChevronRight className="w-4 h-4 text-zinc-300 group-hover:text-zinc-900 transition-colors" />
                    </div>
                  </div>
                ))
              )}
            </div>
          </Section>

          {/* Top Products */}
          <Section CardTitle="Mais Procurados" icon={TrendingUp}>
            <div className="divide-y divide-zinc-50">
              {loadingSummary ? (
                <div className="p-6 space-y-4">
                  {[1, 2, 3].map(i => <Skeleton key={i} className="h-16 w-full rounded-2xl" />)}
                </div>
              ) : (
                (stats.topProducts || []).map((p, i) => (
                  <div key={i} onClick={() => onNavigate('admin-products')} className="group p-5 hover:bg-zinc-50 transition-all duration-300 cursor-pointer">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-4">
                        <div className="relative">
                          <div className="w-14 h-14 rounded-2xl overflow-hidden bg-zinc-50 border border-zinc-100">
                            <img src={p.image} alt={p.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                          </div>
                          <div className="absolute -top-1 -left-1 w-6 h-6 bg-zinc-900 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-white group-hover:bg-emerald-500 transition-colors">
                            {i + 1}
                          </div>
                        </div>
                        <div>
                          <p className="text-sm font-black text-zinc-900 truncate max-w-[150px]">
                            {p.name}
                          </p>
                          <div className="flex items-center gap-2 mt-1">
                            <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">
                              {p.quantity} vendidos
                            </span>
                          </div>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-sm font-black text-zinc-900">
                          {(p.total || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
