        </div>

        {/* Bottom Section: Q&A & Reviews Quick Look */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-12">
          <Card className="bg-emerald-600 text-white border-none shadow-premium overflow-hidden relative cursor-pointer active:scale-[0.98] transition-transform" onClick={() => onNavigate('admin-reviews')}>
            <div className="absolute top-0 right-0 p-8 opacity-10">
              <Star className="w-24 h-24" />
            </div>
            <CardContent className="p-8">
              <h3 className="text-lg font-black leading-tight">Gestão de Experiência</h3>
              <p className="text-sm text-emerald-100 mt-2 opacity-80">Veja o que seus clientes dizem sobre os produtos e responda avaliações.</p>
              <div className="mt-6 flex items-center gap-2 font-black text-xs uppercase tracking-widest bg-white/20 w-fit px-4 py-2 rounded-full">
                Gerenciar Reviews <ChevronRight className="w-4 h-4" />
              </div>
