          <Card className="bg-black text-white border-none shadow-premium overflow-hidden relative cursor-pointer active:scale-[0.98] transition-transform" onClick={() => onNavigate('admin-qa')}>
            <div className="absolute top-0 right-0 p-8 opacity-10">
              <MessageSquare className="w-24 h-24" />
