import { useState, useEffect } from 'react';
import { Search, Eye, MessageCircle, Package, XCircle, ChevronLeft, ChevronRight } from 'lucide-react';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabase';
import type { Order, OrderStatus } from '@/types';
import { useOrders } from '@/hooks/useOrders';
import { OrderStatusBadge, statusConfig } from '@/components/admin/orders/OrderStatusBadge';
import { OrderDetail } from '@/components/admin/orders/OrderDetail';

interface AdminOrdersViewProps {
  onNavigate: (view: any) => void;
}

export function AdminOrdersView({ onNavigate: _onNavigate }: AdminOrdersViewProps) {
  const { orders, fetchOrders, updateOrderStatus, updateOrderTracking, isLoaded } = useOrders(true, 'admin-orders');
  const [searchQuery, setSearchQuery] = useState('');
  const [dateRange, setDateRange] = useState({
    start: '',
    end: ''
  });
  const [filter, setFilter] = useState<OrderStatus | 'all'>('all');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [currentPage, setCurrentPage] = useState(0);
  const itemsPerPage = 15;

  const toggleSelectOrder = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredOrders.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredOrders.map(o => o.id)));
    }
  };

  const handleBulkStatusChange = async (status: OrderStatus) => {
    if (selectedIds.size === 0) return;
    try {
      const promises = Array.from(selectedIds).map(id => handleStatusChange(id, status, true));
      await Promise.all(promises);
      setSelectedIds(new Set());
      toast.success(`${selectedIds.size} pedidos atualizados.`);
    } catch (err) {
      console.error('Error in bulk update:', err);
      toast.error('Erro ao atualizar pedidos em massa');
    }
  };

  useEffect(() => {
    fetchOrders();
  }, [fetchOrders]);

  useEffect(() => {
    setCurrentPage(0);
  }, [searchQuery, filter, dateRange]);

  if (!isLoaded) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="w-8 h-8 border-2 border-black/30 border-t-black rounded-full animate-spin" />
      </div>
    );
  }

  const filteredOrders = orders.filter(order => {
    if (filter !== 'all' && order.status !== filter) return false;

    // Date Filtering
    if (dateRange.start || dateRange.end) {
      const orderDate = new Date(order.createdAt);
      orderDate.setHours(0, 0, 0, 0);

      if (dateRange.start) {
        const start = new Date(dateRange.start);
        start.setHours(0, 0, 0, 0);
        if (orderDate < start) return false;
      }

      if (dateRange.end) {
        const end = new Date(dateRange.end);
        end.setHours(0, 0, 0, 0);
        if (orderDate > end) return false;
      }
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      return (
        order.customer.name.toLowerCase().includes(query) ||
        order.id.includes(query) ||
        order.customer.whatsapp.includes(query)
      );
    }
    return true;
  });

  const totalPages = Math.ceil(filteredOrders.length / itemsPerPage);
  const paginatedOrders = filteredOrders.slice(
    currentPage * itemsPerPage,
    (currentPage + 1) * itemsPerPage
  );

  const handleStatusChange = async (orderId: string, newStatus: OrderStatus, silent: boolean = false) => {
    const order = orders.find(o => o.id === orderId);

    // Send Push Notification (Edge Function) only if NOT silent
    // The in-app DB notification is handled securely by the backend RPC
    if (order && order.userId && !silent) {
      try {
        const title = 'Status do Pedido Atualizado';
        const body = `Seu pedido #${orderId.slice(-6)} agora está: ${statusConfig[newStatus].label}`;

        // Send via Edge Function
        await supabase.functions.invoke('send-push', {
          body: {
            userId: order.userId,
            title,
            body,
            data: { orderId, type: 'order_status' }
          }
        });
      } catch (err) {
        console.error('Error sending status push:', err);
      }
    }

    await updateOrderStatus(orderId, newStatus, undefined, silent);

    if (selectedOrder && selectedOrder.id === orderId) {
      setSelectedOrder({ ...selectedOrder, status: newStatus });
    }
  };

  const handleTrackingUpdate = async (orderId: string, code: string) => {
    await updateOrderTracking(orderId, code);
    if (selectedOrder && selectedOrder.id === orderId) {
      setSelectedOrder({ ...selectedOrder, trackingCode: code });
    }
  };

  const handleWhatsApp = (order: Order) => {
    const message = `Olá ${order.customer.name}!\n\n` +
      `Seu pedido #${order.id.slice(-6)} foi atualizado.\n` +
      `Status: ${statusConfig[order.status].label}\n\n` +
      `Obrigado por comprar na IKCOUS!`;

    const url = `https://wa.me/55${order.customer.whatsapp.replace(/\D/g, '')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  if (selectedOrder) {
    return (
      <OrderDetail
        order={selectedOrder}
        onBack={() => setSelectedOrder(null)}
        onStatusChange={handleStatusChange}
        onWhatsApp={handleWhatsApp}
        onTrackingUpdate={handleTrackingUpdate}
      />
    );
  }

  return (
    <div className="pb-8">
      {/* Unified Sticky Header */}
      <div className="glass sticky top-0 z-50 border-b border-zinc-100">
        <div className="px-4 py-4 space-y-4">
          <div className="flex items-center justify-between mb-2">
            <h1 className="text-xl font-black text-zinc-900 tracking-tight">Pedidos <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest ml-2">{filteredOrders.length} transações</span></h1>
            {filteredOrders.length > 0 && (
              <button
                onClick={toggleSelectAll}
                className="text-[10px] font-black uppercase tracking-widest text-zinc-400 hover:text-zinc-900 transition-colors"
              >
                {selectedIds.size === filteredOrders.length ? 'Desmarcar Todos' : 'Selecionar Todos'}
              </button>
            )}
          </div>
          <div className="relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400 group-focus-within:text-zinc-900 transition-colors" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Buscar por cliente, ID ou WhatsApp..."
              className="w-full pl-11 pr-4 py-3.5 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-950/5 focus:bg-white focus:border-zinc-950 transition-all"
            />
          </div>

          <div className="flex gap-3">
            <div className="flex-1 relative">
              <input
                type="date"
                value={dateRange.start}
                onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))}
                className="w-full bg-zinc-50 border border-zinc-100 rounded-xl px-4 py-2.5 text-[11px] font-bold text-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white transition-all appearance-none"
              />
              <span className="absolute -top-2 left-3 bg-white px-1 text-[8px] font-black uppercase text-zinc-400 tracking-widest">Início</span>
            </div>
            <div className="flex-1 relative">
              <input
                type="date"
                value={dateRange.end}
                onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))}
                className="w-full bg-zinc-50 border border-zinc-100 rounded-xl px-4 py-2.5 text-[11px] font-bold text-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white transition-all appearance-none"
              />
              <span className="absolute -top-2 left-3 bg-white px-1 text-[8px] font-black uppercase text-zinc-400 tracking-widest">Fim</span>
            </div>
            {(dateRange.start || dateRange.end) && (
              <button
                onClick={() => setDateRange({ start: '', end: '' })}
                className="w-10 h-10 flex items-center justify-center bg-zinc-100 text-zinc-900 rounded-xl hover:bg-zinc-200 transition-colors active:scale-95"
              >
                <XCircle className="w-4 h-4" />
              </button>
            )}
          </div>
        </div>

        {/* Filter Tabs - Integrated */}
        <div className="px-4 py-3 border-t border-zinc-100 overflow-x-auto scrollbar-none">
          <div className="flex gap-2 pb-1">
            <button
              onClick={() => setFilter('all')}
              className={`flex-shrink-0 px-5 py-2 rounded-full text-[11px] font-black uppercase tracking-widest transition-all active:scale-95 ${filter === 'all'
                ? 'bg-zinc-900 text-white shadow-premium'
                : 'bg-zinc-100 text-zinc-400 hover:bg-zinc-200'
                }`}
            >
              Todos
            </button>
            {Object.entries(statusConfig).map(([status, cfg]) => (
              <button
                key={status}
                onClick={() => setFilter(status as OrderStatus)}
                className={`flex-shrink-0 px-5 py-2 rounded-full text-[11px] font-black uppercase tracking-widest transition-all active:scale-95 flex items-center gap-2 ${filter === status
                  ? 'bg-zinc-900 text-white shadow-premium'
                  : 'bg-zinc-100 text-zinc-400 hover:bg-zinc-200'
                  }`}
              >
                {cfg.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Orders List */}
      <div className="p-4 space-y-3">
        {filteredOrders.length === 0 ? (
          <div className="text-center py-20">
            <div className="w-20 h-20 bg-zinc-50 rounded-full flex items-center justify-center mx-auto mb-6 border border-zinc-100">
              <Package className="w-10 h-10 text-zinc-200" />
            </div>
            <h3 className="text-sm font-black text-zinc-900 uppercase tracking-widest mb-1">
              Sem resultados
            </h3>
            <p className="text-xs font-bold text-zinc-400">
              Tente ajustar seus filtros ou busca
            </p>
          </div>
        ) : (
          paginatedOrders.map((order) => {
            return (
              <div
                key={order.id}
                onClick={() => setSelectedOrder(order)}
                className={`bg-white rounded-3xl border ${selectedIds.has(order.id) ? 'border-zinc-950 ring-1 ring-zinc-950' : 'border-zinc-100'} p-5 cursor-pointer hover:shadow-premium hover:-translate-y-1 transition-all duration-300 active:scale-[0.98] relative overflow-hidden group`}
              >
                {/* Selection Checkbox */}
                <div
                  className="absolute top-5 left-5 z-10 w-5 h-5 rounded-full border border-zinc-200 bg-white flex items-center justify-center transition-colors group-hover:border-zinc-900"
                  onClick={(e) => toggleSelectOrder(order.id, e)}
                >
                  {selectedIds.has(order.id) && <div className="w-2.5 h-2.5 rounded-full bg-zinc-900" />}
                </div>

                <div className="flex items-center justify-between mb-4 pl-8">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-2xl bg-zinc-50 flex items-center justify-center border border-zinc-100 group-hover:bg-zinc-900 transition-colors duration-300">
                      <Package className="w-6 h-6 text-zinc-400 group-hover:text-white transition-colors" />
                    </div>
                    <div>
                      <span className="text-[11px] font-black text-zinc-400 uppercase tracking-widest block mb-0.5">#{order.id.slice(-6)}</span>
                      <span className="text-xs font-bold text-zinc-900">
                        {new Date(order.createdAt).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })} • {new Date(order.createdAt).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </div>
                  <OrderStatusBadge status={order.status} />
                </div>

                <div className="mb-5">
                  <p className="text-sm font-black text-zinc-900 uppercase tracking-tight mb-1">{order.customer.name}</p>
                  <div className="flex items-center gap-3">
                    <span className="text-[11px] font-bold text-zinc-400 px-2 py-0.5 bg-zinc-50 rounded-md border border-zinc-100">
                      {order.items.length} ITENS
                    </span>
                    <span className="text-[11px] font-bold text-zinc-400 uppercase">
                      {order.paymentMethod === 'pix' ? 'PIX' : order.paymentMethod === 'card' ? 'CARTÃO' : 'DINHEIRO'}
                    </span>
                  </div>
                </div>

                <div className="flex items-center justify-between pt-4 border-t border-zinc-50">
                  <div>
                    <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest block mb-1">Total do Pedido</span>
                    <span className="text-xl font-black text-zinc-900 tracking-tighter">
                      R$ {(order.total || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </span>
                  </div>
                  <div className="flex gap-2">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleWhatsApp(order);
                      }}
                      className="w-10 h-10 flex items-center justify-center bg-emerald-50 text-emerald-600 rounded-xl hover:bg-emerald-500 hover:text-white transition-all active:scale-90 border border-emerald-100"
                    >
                      <MessageCircle className="w-5 h-5" />
                    </button>
                    <button className="w-10 h-10 flex items-center justify-center bg-zinc-50 text-zinc-400 rounded-xl hover:bg-zinc-900 hover:text-white transition-all active:scale-90 border border-zinc-100">
                      <Eye className="w-5 h-5" />
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div className="px-4 pb-8 pt-4 flex items-center justify-center gap-4">
          <button
            onClick={() => setCurrentPage(p => Math.max(0, p - 1))}
            disabled={currentPage === 0}
            className="w-10 h-10 flex items-center justify-center bg-white border border-zinc-100 rounded-xl text-zinc-900 shadow-sm hover:shadow-premium hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:hover:translate-y-0 disabled:hover:shadow-sm"
          >
            <ChevronLeft className="w-5 h-5" />
          </button>
          <span className="text-xs font-black text-zinc-400 uppercase tracking-widest">
            Página {currentPage + 1} de {totalPages}
          </span>
          <button
            onClick={() => setCurrentPage(p => Math.min(totalPages - 1, p + 1))}
            disabled={currentPage === totalPages - 1}
            className="w-10 h-10 flex items-center justify-center bg-white border border-zinc-100 rounded-xl text-zinc-900 shadow-sm hover:shadow-premium hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:hover:translate-y-0 disabled:hover:shadow-sm"
          >
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>
      )}

      {/* Bulk Action Bar */}
      {selectedIds.size > 0 && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-bottom-10 fade-in duration-300 w-full max-w-md px-4">
          <div className="bg-zinc-900 text-white px-6 py-4 rounded-[3rem] shadow-2xl flex items-center justify-between border border-white/10 backdrop-blur-xl">
            <div className="flex flex-col ml-2">
              <span className="text-[9px] font-black uppercase tracking-widest text-zinc-400">Selecionados</span>
              <span className="text-sm font-bold">{selectedIds.size} itens</span>
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={() => handleBulkStatusChange('processing')}
                className="px-4 py-2 bg-white/10 hover:bg-white/20 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-colors"
              >
                Atender
              </button>
              <button
                onClick={() => handleBulkStatusChange('shipping')}
                className="px-4 py-2 bg-zinc-100 text-zinc-900 hover:bg-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-colors"
              >
                Enviar
              </button>
            </div>

            <button
              onClick={() => setSelectedIds(new Set())}
              className="p-2 text-zinc-400 hover:text-white transition-colors mr-1"
            >
              <XCircle className="w-5 h-5" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { ArrowLeft, Plus, X, Camera, Check, Layers, Trash2, Edit2, DollarSign, TrendingUp } from 'lucide-react';
import type { View, ProductVariant } from '@/types';
import { useProducts } from '@/hooks/useProducts';
import { useCategories } from '@/hooks/useCategories';
import { TruthGate } from '@/utils/truth_gate';
import { toast } from 'sonner';

interface AdminProductFormViewProps {
  productId?: string;
  onNavigate: (view: View) => void;
  onBack?: () => void;
}

export function AdminProductFormView({ productId, onNavigate, onBack }: AdminProductFormViewProps) {
  const { addProduct, updateProduct, addVariant, updateVariant, deleteVariant, uploadProductImages, fetchProduct } = useProducts({ autoFetch: false });
  const { categories: dbCategories } = useCategories();

  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    price: '',
    costPrice: '',
    originalPrice: '',
    stock: '',
    category: '',
    images: [] as string[],
    freeShipping: false,
    isBestseller: false,
    isActive: true,
    metaTitle: '',
    metaDescription: '',
    variants: [] as ProductVariant[],
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [showVariantForm, setShowVariantForm] = useState(false);
  const [editingVariant, setEditingVariant] = useState<ProductVariant | null>(null);
  const [variantFormData, setVariantFormData] = useState({
    name: '',
    value: '',
    sku: '',
    stockIncrement: '0',
    priceOverride: '',
    active: true
  });
  const [currentProduct, setCurrentProduct] = useState<any>(null);

  useEffect(() => {
    if (productId) {
      const loadProduct = async () => {
        setIsLoading(true);
        const product = await fetchProduct(productId);
        if (product) {
          setFormData({
            name: product.name,
            description: product.description,
            price: product.price.toString(),
            costPrice: product.costPrice?.toString() || '',
            originalPrice: product.originalPrice?.toString() || '',
            stock: product.stock.toString(),
            category: product.category,
            images: product.images,
            freeShipping: product.freeShipping,
            isBestseller: product.isBestseller,
            isActive: product.isActive,
            metaTitle: product.metaTitle || '',
            metaDescription: product.metaDescription || '',
            variants: product.variants || [],
          });
          setCurrentProduct(product);
        } else {
          toast.error('Produto não encontrado');
          onNavigate('admin-products');
        }
        setIsLoading(false);
      };
      loadProduct();
    }
  }, [productId, fetchProduct, onNavigate]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const loadingToast = toast.loading(`Enviando ${files.length} imagem(ns)...`);

    try {
      const urls = await uploadProductImages(files);
      setFormData(prev => ({
        ...prev,
        images: [...prev.images, ...urls]
      }));
      toast.success('Imagens enviadas com sucesso!', { id: loadingToast });
    } catch (error) {
      console.error('Upload error:', error);
      toast.error('Erro ao enviar imagens', { id: loadingToast });
    }
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images.filter((_, i) => i !== index)
    }));
  };

  const handleVariantSubmit = async () => {
    if (!productId) return;

    try {
      const parsedPriceOverride = variantFormData.priceOverride ? parseFloat(variantFormData.priceOverride) : undefined;

      const vData = {
        productId,
        name: variantFormData.name,
        value: variantFormData.value,
        sku: variantFormData.sku,
        stockIncrement: parseInt(variantFormData.stockIncrement) || 0,
        priceOverride: parsedPriceOverride !== undefined ? Math.max(0, parsedPriceOverride) : undefined,
        active: variantFormData.active
      };

      if (editingVariant) {
        await updateVariant(editingVariant.id, vData);
      } else {
        await addVariant(vData);
      }

      setShowVariantForm(false);
      setEditingVariant(null);
      setVariantFormData({
        name: '',
        value: '',
        sku: '',
        stockIncrement: '0',
        priceOverride: '',
        active: true
      });

      // Refresh local variants (using fresh fetch)
      const updatedProduct = await fetchProduct(productId);
      if (updatedProduct) {
        setFormData(prev => ({ ...prev, variants: updatedProduct.variants || [] }));
      }
    } catch (err) {
      console.error('Variant error:', err);
    }
  };

  const handleDeleteVariant = async (vId: string) => {
    if (window.confirm('Excluir esta variante?')) {
      await deleteVariant(vId);
      // Refresh local variants (using fresh fetch)
      const updatedProduct = await fetchProduct(productId!);
      if (updatedProduct) {
        setFormData(prev => ({ ...prev, variants: updatedProduct.variants || [] }));
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const pPrice = parseFloat(formData.price) || 0;
    const pCost = formData.costPrice ? parseFloat(formData.costPrice) : undefined;
    const pOriginal = formData.originalPrice ? parseFloat(formData.originalPrice) : undefined;
    const pStock = parseInt(formData.stock) || 0;

    const productData = {
      name: formData.name,
      description: formData.description,
      price: Math.max(0, pPrice),
      costPrice: pCost !== undefined ? Math.max(0, pCost) : undefined,
      originalPrice: pOriginal !== undefined ? Math.max(0, pOriginal) : undefined,
      stock: Math.max(0, pStock),
      category: formData.category,
      images: formData.images,
      freeShipping: formData.freeShipping,
      isBestseller: formData.isBestseller,
      isActive: formData.isActive,
      metaTitle: formData.metaTitle,
      metaDescription: formData.metaDescription,
      sold: productId ? (currentProduct?.sold || 0) : 0,
    };

    // VOR G17: Truth Gate Verification
    const receipt = TruthGate.verifyProductAxiom(productData);
    if (receipt.status === 'ABORTED') {
      setIsSubmitting(false);
      receipt.violations.forEach(v => toast.error(v));
      return;
    }

    try {
      if (productId) {
        await updateProduct(productId, productData);
      } else {
        await addProduct(productData);
      }

      setIsSubmitting(false);
      setShowSuccess(true);
      toast.success(`Recibo gerado: ${receipt.hash}`);

      setTimeout(() => {
        onNavigate('admin-products');
      }, 1500);
    } catch (err) {
      setIsSubmitting(false);
      // Erro já tratado no hook useProducts com toast
    }
  };

  const isValid =
    formData.name &&
    formData.description &&
    formData.price &&
    formData.stock &&
    formData.category !== '' &&
    parseFloat(formData.price) > 0 &&
    parseInt(formData.stock) >= 0;

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-zinc-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-8 h-8 border-4 border-zinc-900/10 border-t-zinc-900 rounded-full animate-spin" />
          <p className="text-xs font-bold text-zinc-400 uppercase tracking-widest">Carregando Produto...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="pb-8 relative">
      {/* Variant Form Modal-ish */}
      {showVariantForm && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 space-y-4">
            <h3 className="font-bold text-lg">{editingVariant ? 'Editar Variante' : 'Nova Variante'}</h3>

            <div className="space-y-3">
              <div>
                <label className="text-xs font-bold text-gray-500">Tipo (ex: Cor, Tamanho)</label>
                <input
                  type="text"
                  value={variantFormData.name}
                  onChange={e => setVariantFormData(p => ({ ...p, name: e.target.value }))}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm"
                  placeholder="Ex: Cor"
                />
              </div>
              <div>
                <label className="text-xs font-bold text-gray-500">Valor (ex: Azul, G)</label>
                <input
                  type="text"
                  value={variantFormData.value}
                  onChange={e => setVariantFormData(p => ({ ...p, value: e.target.value }))}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm"
                  placeholder="Ex: Azul"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-bold text-gray-500">Ajuste Estoque</label>
                  <input
                    type="number"
                    value={variantFormData.stockIncrement}
                    onChange={e => setVariantFormData(p => ({ ...p, stockIncrement: e.target.value }))}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-500">Sobrescrever Preço</label>
                  <input
                    type="number"
                    min="0"
                    step="0.01"
                    value={variantFormData.priceOverride}
                    onChange={e => setVariantFormData(p => ({ ...p, priceOverride: e.target.value }))}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm"
                    placeholder="Opcional"
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button
                onClick={() => {
                  setShowVariantForm(false);
                  setEditingVariant(null);
                }}
                className="flex-1 py-3 text-sm font-bold text-gray-500"
              >
                Cancelar
              </button>
              <button
                onClick={handleVariantSubmit}
                className="flex-1 py-3 bg-black text-white rounded-xl text-sm font-bold"
              >
                {editingVariant ? 'Salvar' : 'Adicionar'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="glass px-4 py-4 sticky top-0 z-50 flex items-center justify-between border-b border-zinc-100">
        <div className="flex items-center gap-3">
          <button
            onClick={() => onBack ? onBack() : onNavigate('admin-products')}
            className="w-10 h-10 flex items-center justify-center bg-white text-zinc-900 rounded-xl hover:bg-zinc-100 transition-all active:scale-95 border border-zinc-100 shadow-sm group"
          >
            <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
          </button>
          <div>
            <h1 className="text-lg font-black text-zinc-900 tracking-tight">
              {productId ? 'Editar Produto' : 'Novo Produto'}
            </h1>
            <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">
              {productId ? 'Atualizar catálogo' : 'Expandir inventário'}
            </p>
          </div>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-4 space-y-6">
        {/* Images */}
        <div className="bg-white p-6 border border-zinc-100 shadow-premium rounded-3xl">
          <label className="block text-xs font-black uppercase tracking-widest text-zinc-400 mb-4">
            Galeria de Imagens
          </label>
          <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-none">
            {formData.images.map((image, index) => (
              <div key={index} className="relative flex-shrink-0 w-28 h-28 group">
                <img
                  src={image}
                  alt={`Product ${index + 1}`}
                  className="w-full h-full object-cover rounded-2xl shadow-sm border border-zinc-100 group-hover:scale-[1.02] transition-transform duration-300"
                />
                <button
                  type="button"
                  onClick={() => removeImage(index)}
                  className="absolute -top-2 -right-2 w-8 h-8 bg-red-500 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white scale-0 group-hover:scale-100 transition-transform active:scale-90"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 w-28 h-28 border-2 border-dashed border-zinc-200 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:border-zinc-400 hover:bg-zinc-50 transition-all group">
              <Camera className="w-6 h-6 text-zinc-300 mb-1 group-hover:text-zinc-500 transition-colors" />
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Upload</span>
              <input
                type="file"
                accept="image/*"
                multiple
                onChange={handleImageUpload}
                className="hidden"
              />
            </label>
          </div>
        </div>

        {/* Basic Info */}
        <div className="bg-white p-6 border border-zinc-100 shadow-premium rounded-3xl space-y-5">
          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-zinc-400 mb-2">
              Nome do Produto *
            </label>
            <input
              type="text"
              value={formData.name}
              onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
              placeholder="Ex: Fone de Ouvido Bluetooth"
              className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-950/5 focus:bg-white focus:border-zinc-950 transition-all shadow-sm"
            />
          </div>

          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-zinc-400 mb-2">
              Descrição *
            </label>
            <textarea
              value={formData.description}
              onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
              placeholder="Descreva o produto..."
              rows={4}
              className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-950/5 focus:bg-white focus:border-zinc-950 transition-all resize-none shadow-sm"
            />
          </div>

          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-zinc-400 mb-2">
              Categoria *
            </label>
            <select
              value={formData.category}
              onChange={(e) => setFormData(prev => ({ ...prev, category: e.target.value }))}
              className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all appearance-none cursor-pointer"
            >
              <option value="">Selecione uma categoria</option>
              {dbCategories.map((category) => (
                <option key={category.id} value={category.name}>{category.name}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Pricing & Profitability */}
        <div className="bg-white p-6 border border-zinc-100 shadow-premium rounded-3xl space-y-6">
          <div className="flex items-center justify-between">
            <label className="block text-xs font-black uppercase tracking-widest text-zinc-400">
              Precificação & Inteligência
            </label>
            {formData.price && formData.costPrice && (
              <div className="flex gap-2">
                <span className="text-[9px] font-black bg-emerald-50 text-emerald-600 px-2 py-1 rounded-md border border-emerald-100 uppercase tracking-widest">
                  MARGEM: {parseFloat(formData.price) > 0 ? (((parseFloat(formData.price) - parseFloat(formData.costPrice)) / parseFloat(formData.price)) * 100).toFixed(1) : '0.0'}%
                </span>
                <span className="text-[9px] font-black bg-blue-50 text-blue-600 px-2 py-1 rounded-md border border-blue-100 uppercase tracking-widest">
                  ROI: {parseFloat(formData.costPrice) > 0 ? (((parseFloat(formData.price) - parseFloat(formData.costPrice)) / parseFloat(formData.costPrice)) * 100).toFixed(1) : '0.0'}%
                </span>
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Preço de Custo *
              </label>
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 font-bold text-sm group-focus-within:text-zinc-900 transition-colors">R$</span>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.costPrice}
                  onChange={(e) => setFormData(prev => ({ ...prev, costPrice: e.target.value }))}
                  placeholder="0,00"
                  className="w-full pl-12 pr-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-black focus:outline-none focus:ring-2 focus:ring-emerald-900/5 focus:bg-white focus:border-emerald-900 transition-all tabular-nums"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Preço de Venda *
              </label>
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 font-bold text-sm group-focus-within:text-zinc-900 transition-colors">R$</span>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.price}
                  onChange={(e) => setFormData(prev => ({ ...prev, price: e.target.value }))}
                  placeholder="0,00"
                  className="w-full pl-12 pr-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-black focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all tabular-nums"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Preço Original
              </label>
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 font-bold text-sm group-focus-within:text-zinc-900 transition-colors">R$</span>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.originalPrice}
                  onChange={(e) => setFormData(prev => ({ ...prev, originalPrice: e.target.value }))}
                  placeholder="0,00"
                  className="w-full pl-12 pr-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-black focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all tabular-nums text-zinc-400"
                />
              </div>
            </div>
          </div>

          {/* Profitability Insight Card */}
          {formData.price && formData.costPrice && parseFloat(formData.costPrice) > 0 && (
            <div className="p-4 bg-zinc-900 rounded-2xl border border-zinc-800 flex items-center justify-between shadow-premium-lg bg-gradient-to-br from-zinc-900 to-black">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                  <TrendingUp className="w-5 h-5 text-emerald-500" />
                </div>
                <div>
                  <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest leading-none mb-1">Lucro Líquido Previsto</p>
                  <p className="text-lg font-black text-white leading-none">
                    R$ {(parseFloat(formData.price) - parseFloat(formData.costPrice)).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-[8px] font-bold text-zinc-500 uppercase tracking-widest leading-none mb-1.5">Eficiência</p>
                <span className="text-[9px] font-black text-emerald-400 uppercase px-2 py-1 rounded bg-emerald-500/10 border border-emerald-500/20 tracking-widest">Otimizado</span>
              </div>
            </div>
          )}
        </div>

        {/* Stock */}
        <div className="bg-white p-6 border border-zinc-100 shadow-premium rounded-3xl space-y-4">
          <label className="block text-xs font-black uppercase tracking-widest text-zinc-400 mb-2">
            Gestão de Inventário
          </label>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Estoque Base *
              </label>
              <input
                type="number"
                min="0"
                value={formData.stock}
                onChange={(e) => setFormData(prev => ({ ...prev, stock: e.target.value }))}
                placeholder="0"
                className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-black focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all tabular-nums"
              />
              <p className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest mt-2 ml-1">
                Este estoque é compartilhado. Variantes somam estoques extras.
              </p>
            </div>
          </div>
        </div>

        {/* Variants Section */}
        {productId && (
          <div className="space-y-4">
            <div className="flex items-center justify-between pb-1 border-b border-gray-100">
              <h3 className="text-sm font-bold text-gray-900 flex items-center gap-2">
                <Layers className="w-4 h-4" />
                Variantes (Grade)
              </h3>
              <button
                type="button"
                onClick={() => setShowVariantForm(true)}
                className="text-xs font-bold text-blue-600 hover:text-blue-700"
              >
                + Adicionar
              </button>
            </div>

            <div className="space-y-2">
              {formData.variants.length === 0 ? (
                <div className="bg-gray-50 border border-dashed border-gray-200 rounded-xl p-4 text-center">
                  <p className="text-xs text-gray-400 font-medium">Nenhuma variante cadastrada</p>
                </div>
              ) : (
                formData.variants.map((v) => (
                  <div key={v.id} className="bg-white border border-zinc-100 rounded-2xl p-4 flex items-center justify-between shadow-premium group">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[13px] font-black text-zinc-900 uppercase tracking-tight">{v.name}: {v.value}</span>
                        {!v.active && <span className="text-[9px] font-black bg-zinc-100 text-zinc-400 px-2 py-0.5 rounded-full uppercase">Inativo</span>}
                      </div>
                      <div className="flex items-center gap-4 text-[11px] font-bold text-zinc-400 tracking-wide">
                        <span className="flex items-center gap-1">
                          <Layers className="w-3 h-3" />
                          Aj. Estoque: <span className="text-zinc-900">{v.stockIncrement > 0 ? `+${v.stockIncrement}` : v.stockIncrement}</span>
                        </span>
                        {v.priceOverride && (
                          <span className="flex items-center gap-1 text-emerald-600">
                            <DollarSign className="w-3 h-3" />
                            R$ {v.priceOverride.toFixed(2)}
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <button
                        type="button"
                        onClick={() => {
                          setEditingVariant(v);
                          setVariantFormData({
                            name: v.name,
                            value: v.value,
                            sku: v.sku || '',
                            stockIncrement: v.stockIncrement.toString(),
                            priceOverride: v.priceOverride?.toString() || '',
                            active: v.active
                          });
                          setShowVariantForm(true);
                        }}
                        className="w-10 h-10 flex items-center justify-center rounded-xl bg-zinc-50 text-zinc-400 hover:bg-zinc-900 hover:text-white transition-all active:scale-90"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button
                        type="button"
                        onClick={() => handleDeleteVariant(v.id)}
                        className="w-10 h-10 flex items-center justify-center rounded-xl bg-zinc-50 text-zinc-400 hover:bg-red-500 hover:text-white transition-all active:scale-90"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Options */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <label className="flex items-center justify-between p-5 bg-white border border-zinc-100 rounded-[1.5rem] cursor-pointer shadow-premium-sm hover:shadow-premium transition-all">
            <div className="space-y-1">
              <span className="text-[11px] font-black uppercase tracking-tight text-zinc-900 leading-none block">Frete Grátis</span>
              <span className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest block">Incentivo de Venda</span>
            </div>
            <input
              type="checkbox"
              checked={formData.freeShipping}
              onChange={(e) => setFormData(prev => ({ ...prev, freeShipping: e.target.checked }))}
              className="w-5 h-5 rounded-lg border-zinc-200 text-zinc-900 focus:ring-zinc-900/5 transition-all"
            />
          </label>

          <label className="flex items-center justify-between p-5 bg-white border border-zinc-100 rounded-[1.5rem] cursor-pointer shadow-premium-sm hover:shadow-premium transition-all">
            <div className="space-y-1">
              <span className="text-[11px] font-black uppercase tracking-tight text-zinc-900 leading-none block">Mais Vendido</span>
              <span className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest block">Destaque na Home</span>
            </div>
            <input
              type="checkbox"
              checked={formData.isBestseller}
              onChange={(e) => setFormData(prev => ({ ...prev, isBestseller: e.target.checked }))}
              className="w-5 h-5 rounded-lg border-zinc-200 text-zinc-900 focus:ring-zinc-900/5 transition-all"
            />
          </label>

          <label className="flex items-center justify-between p-5 bg-white border border-zinc-100 rounded-[1.5rem] cursor-pointer shadow-premium-sm hover:shadow-premium transition-all">
            <div className="space-y-1">
              <span className="text-[11px] font-black uppercase tracking-tight text-zinc-900 leading-none block">Ativo</span>
              <span className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest block">Disponibilidade</span>
            </div>
            <input
              type="checkbox"
              checked={formData.isActive}
              onChange={(e) => setFormData(prev => ({ ...prev, isActive: e.target.checked }))}
              className="w-5 h-5 rounded-lg border-zinc-200 text-zinc-900 focus:ring-zinc-900/5 transition-all"
            />
          </label>
        </div>

        {/* SEO Info */}
        <div className="bg-white p-6 border border-zinc-100 shadow-premium rounded-3xl space-y-6">
          <div className="flex items-center gap-2">
            <TrendingUp className="w-4 h-4 text-zinc-400" />
            <h3 className="text-xs font-black uppercase tracking-widest text-zinc-400">Otimização (SEO)</h3>
          </div>

          <div className="space-y-5">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Meta Title
              </label>
              <input
                type="text"
                value={formData.metaTitle}
                onChange={(e) => setFormData(prev => ({ ...prev, metaTitle: e.target.value }))}
                placeholder="Título estratégico para buscadores"
                className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">
                Meta Description
              </label>
              <textarea
                value={formData.metaDescription}
                onChange={(e) => setFormData(prev => ({ ...prev, metaDescription: e.target.value }))}
                placeholder="Descrição persuasiva para o Google..."
                rows={3}
                className="w-full px-4 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all resize-none"
              />
            </div>
          </div>
        </div>

        {/* Submit */}
        <div className="sticky bottom-4 left-0 right-0 z-40 bg-zinc-900 text-white rounded-3xl shadow-2xl p-2 max-w-[calc(100%-32px)] mx-auto border border-zinc-800">
          <button
            type="submit"
            disabled={!isValid || isSubmitting}
            className="w-full py-4 rounded-2xl flex items-center justify-center gap-2 bg-gradient-to-r from-zinc-800 to-zinc-900 hover:from-black hover:to-zinc-900 disabled:from-zinc-100 disabled:to-zinc-100 disabled:text-zinc-400 transition-all active:scale-[0.98] font-black uppercase tracking-widest text-xs"
          >
            {isSubmitting ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : showSuccess ? (
              <>
                <Check className="w-5 h-5 text-emerald-400" />
                Salvo com sucesso!
              </>
            ) : (
              <>
                {productId ? <Edit2 className="w-4 h-4" /> : <Plus className="w-4 h-4" />}
                {productId ? 'Confirmar Alterações' : 'Publicar Produto'}
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { ArrowLeft, Send, Users, Info, Sparkles, Zap, History, Target } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';
import { usePushNotifications } from '@/hooks/usePushNotifications';
import { useVOR } from '@/hooks/useVOR';
import type { View } from '@/types';

interface AdminPushViewProps {
    onNavigate: (view: View) => void;
}

export function AdminPushView({ onNavigate }: AdminPushViewProps) {
    const [loading, setLoading] = useState(false);
    const [subCount, setSubCount] = useState(0);
    const [notification, setNotification] = useState({
        title: '',
        body: '',
        url: '/'
    });
    const { isSupported, subscribe } = usePushNotifications();
    const { recordAction } = useVOR();
    const [isTestSubscribed, setIsTestSubscribed] = useState(false);
    const [segment, setSegment] = useState('all');
    const [predictedReach, setPredictedReach] = useState(0);
    const [history, setHistory] = useState<any[]>([]);

    useEffect(() => {
        fetchSubscribers();
        fetchHistory();
    }, []);

    useEffect(() => {
        calculateReach();
    }, [segment]);

    const calculateReach = async () => {
        if (segment === 'all') {
            setPredictedReach(subCount);
            return;
        }

        try {
            const { data, error } = await (supabase.rpc as any)('get_segmented_push_targets', {
                p_segment: segment
            });
            if (!error && data) {
                setPredictedReach(data.length);
            }
        } catch (err) {
            console.error('Error calculating reach:', err);
        }
    };

    const fetchHistory = async () => {
        const { data, error } = await supabase
            .from('push_notifications_log')
            .select('*')
            .order('sent_at', { ascending: false })
            .limit(20);

        if (!error && data) setHistory(data);
    };

    const fetchSubscribers = async () => {
        const { count, error } = await supabase
            .from('push_subscriptions')
            .select('*', { count: 'exact', head: true });

        if (!error) setSubCount(count || 0);
    };

    const handleTestSubscription = async () => {
        try {
            await subscribe();
            setIsTestSubscribed(true);
            fetchSubscribers();
        } catch (error) {
            // Error handled in hook
        }
    };

    const handleSend = async () => {
        if (!notification.title || !notification.body) {
            toast.error('Preencha título e mensagem');
            return;
        }

        setLoading(true);
        try {
            const { data: { user } } = await supabase.auth.getUser();

            // 1. Fetch real targets based on segment
            const { data: targets, error: targetError } = await (supabase.rpc as any)('get_segmented_push_targets', {
                p_segment: segment
            });

            if (targetError) throw targetError;

            const finalRecipientCount = targets?.length || 0;

            if (finalRecipientCount === 0) {
                toast.error('Nenhum destinatário encontrado para este segmento');
                return;
            }

            // 2. Save to logs
            const { error: logError } = await supabase
                .from('push_notifications_log')
                .insert({
                    title: notification.title,
                    body: notification.body,
                    url: notification.url,
                    recipient_count: finalRecipientCount,
                    created_by: user?.id,
                    metadata: { segment }
                });

            if (logError) throw logError;

            // 3. Call Edge Function to send real push notifications
            const { error: pushError } = await supabase.functions.invoke('send-push', {
                body: {
                    title: notification.title,
                    body: notification.body,
                    url: notification.url,
                    tokens: targets.map((t: any) => ({
                        endpoint: t.endpoint,
                        keys: { p256dh: t.p256dh, auth: t.auth }
                    }))
                }
            });

            if (pushError) {
                console.warn('Real push delivery failed, but log was created:', pushError);
                toast.warning('Log criado, mas houve erro no disparo real');
            } else {
                toast.success(`Notificação enviada para ${finalRecipientCount} dispositivos!`);
                recordAction('PUSH_DISPATCH',
                    { title: notification.title, recipient_count: finalRecipientCount, segment },
                    { status: 'success', timestamp: new Date().toISOString() }
                );
            }

            setNotification({ title: '', body: '', url: '/' });
            fetchHistory();
        } catch (error) {
            console.error('Error sending push:', error);
            toast.error('Falha ao registrar notificação no banco');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-zinc-50/30 pb-32">
            {/* Header Executivo */}
            <div className="glass px-6 py-6 sticky top-0 z-50 border-b border-zinc-100">
                <div className="max-w-4xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => onNavigate('admin-dashboard')}
                            className="w-12 h-12 flex items-center justify-center bg-white text-zinc-900 rounded-2xl hover:bg-zinc-100 transition-all active:scale-95 border border-zinc-100 group shadow-sm"
                        >
                            <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                        </button>
                        <div>
                            <h1 className="text-xl font-black text-zinc-900 tracking-tight flex items-center gap-2">
                                Push Center <Target className="w-4 h-4 text-emerald-500" />
                            </h1>
                            <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-[0.2em]">Centro de Comando de Engajamento</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="max-w-4xl mx-auto p-6 space-y-8">
                {/* SROS Agentic Generator */}
                <div className="bg-zinc-950 rounded-[3rem] p-10 border border-white/10 shadow-2xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-8 scale-150 opacity-10 group-hover:opacity-20 transition-opacity">
                        <Sparkles className="w-20 h-20 text-emerald-400" />
                    </div>

                    <div className="relative z-10 space-y-8">
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-emerald-500/20 rounded-2xl flex items-center justify-center border border-emerald-500/30">
                                <Zap className="w-6 h-6 text-emerald-400" />
                            </div>
                            <div>
                                <h3 className="text-xl font-black text-white tracking-tight">Gerador de Manifesto SROS</h3>
                                <p className="text-[10px] font-bold text-emerald-500/70 uppercase tracking-[0.2em]">Compilador Agêntico v1.0 • Geração 19</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {[
                                { id: 'fomo', title: 'Otimização de Surpresa', desc: 'Gera urgência através de escassez e exclusividade.', icon: Zap },
                                { id: 'auth', title: 'Simetria Lógica', desc: 'Foca em autoridade, provas sociais e dados.', icon: Info },
                                { id: 'value', title: 'Minimização de Energia', desc: 'Enfatiza facilidade, valor e economia direta.', icon: Target }
                            ].map((arch) => (
                                <button
                                    key={arch.id}
                                    className="p-6 rounded-[2rem] bg-white/5 border border-white/10 text-left hover:bg-white/10 transition-all group/arch active:scale-95"
                                    onClick={() => {
                                        if (arch.id === 'fomo') {
                                            setNotification({
                                                title: 'Última Chamada: Estágio VIP Encerra em 2h! ⏳',
                                                body: 'Apenas 3 unidades restantes no estoque Apex. Garanta sua prioridade agora.',
                                                url: '/favorites'
                                            });
                                        } else if (arch.id === 'auth') {
                                            setNotification({
                                                title: '98% de Aprovação: Conheça os Favoritos da Semana 💎',
                                                body: 'Nossa comunidade validou: estes são os produtos que estão definindo a tendência em Monte Carmelo.',
                                                url: '/search'
                                            });
                                        } else {
                                            setNotification({
                                                title: 'Seu Desconto de Fidelidade foi Ativado! 🎁',
                                                body: 'Como forma de reduzir sua energia livre, liberamos um cupom exclusivo para sua próxima compra.',
                                                url: '/profile'
                                            });
                                        }

                                        // VOR Record for Manifesto Compilation
                                        recordAction('SROS_MANIFESTO_COMPILE',
                                            { archetype: arch.id, title: arch.title },
                                            { result: 'compiled', timestamp: new Date().toISOString() }
                                        );

                                        toast.success(`Manifesto ${arch.title} Compilado!`);
                                    }}
                                >
                                    <arch.icon className="w-5 h-5 text-emerald-400 mb-4" />
                                    <h4 className="text-xs font-black text-white tracking-tight uppercase mb-1">{arch.title}</h4>
                                    <p className="text-[10px] font-medium text-zinc-500 leading-none">{arch.desc}</p>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {isSupported && !isTestSubscribed && (
                    <div className="flex justify-end pr-10">
                        <button
                            onClick={handleTestSubscription}
                            className="px-6 py-3 bg-white text-emerald-600 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-emerald-50 transition-all border border-emerald-100 flex items-center gap-3 shadow-premium-sm active:scale-95"
                        >
                            <Zap className="w-4 h-4 fill-emerald-500" />
                            Monitorar este Dispositivo (Admin Test)
                        </button>
                    </div>
                )}
                {/* Stats Card - Radar Estilo Hi-Tech */}
                <div className="bg-white rounded-[3rem] p-10 border border-zinc-100 relative overflow-hidden shadow-premium">
                    <div className="relative z-10 flex items-center justify-between">
                        <div className="space-y-4">
                            <div>
                                <p className="text-zinc-400 text-[10px] font-black uppercase tracking-[0.3em] mb-2 flex items-center gap-2">
                                    <Sparkles className="w-3 h-3 text-amber-500" /> Alcance Instantâneo
                                </p>
                                <h2 className="text-6xl font-black tracking-tighter text-zinc-900 tabular-nums">
                                    {subCount}
                                </h2>
                                <p className="text-emerald-600 text-[10px] font-bold mt-2 uppercase tracking-widest flex items-center gap-2">
                                    <Zap className="w-3 h-3" /> Dispositivos Prontos para Receber
                                </p>
                            </div>
                            <div className="flex gap-4 pt-4">
                                <div className="px-5 py-2.5 bg-zinc-50 rounded-2xl border border-zinc-100 text-[10px] font-black uppercase tracking-widest text-zinc-400">
                                    iOS: {Math.floor(subCount * 0.4)}
                                </div>
                                <div className="px-5 py-2.5 bg-zinc-50 rounded-2xl border border-zinc-100 text-[10px] font-black uppercase tracking-widest text-zinc-400">
                                    Android: {Math.ceil(subCount * 0.6)}
                                </div>
                            </div>
                        </div>

                        {/* Radar Animation */}
                        <div className="relative w-48 h-48 hidden md:block">
                            <div className="absolute inset-0 border-2 border-emerald-500/20 rounded-full" />
                            <div className="absolute inset-4 border border-emerald-500/10 rounded-full" />
                            <div className="absolute inset-10 border border-emerald-500/5 rounded-full" />
                            <div className="absolute top-1/2 left-1/2 w-full h-[2px] bg-gradient-to-r from-transparent to-emerald-500/50 -translate-y-1/2 origin-left animate-[spin_4s_linear_infinite]" />
                            <div className="absolute top-1/2 left-1/2 w-48 h-48 -translate-x-1/2 -translate-y-1/2 flex items-center justify-center">
                                <Users className="w-12 h-12 text-zinc-800" />
                            </div>
                            {/* Blips */}
                            <div className="absolute top-10 right-10 w-2 h-2 bg-emerald-400 rounded-full animate-pulse shadow-[0_0_10px_#34d399]" />
                            <div className="absolute bottom-12 left-8 w-2 h-2 bg-emerald-400 rounded-full animate-pulse delay-700 shadow-[0_0_10px_#34d399]" />
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-5 gap-8">
                    {/* Formulário - 3 Colunas */}
                    <div className="md:col-span-3 space-y-6">
                        <div className="bg-white border border-zinc-100 rounded-[2.5rem] p-8 space-y-8 shadow-premium-sm">
                            <div className="flex items-center gap-3">
                                <div className="w-12 h-12 bg-zinc-950 text-white rounded-2xl flex items-center justify-center shadow-premium-sm border border-white/10">
                                    <Send className="w-5 h-5" />
                                </div>
                                <div>
                                    <h3 className="text-sm font-black text-zinc-900 uppercase tracking-widest italic">Redigir Campanha</h3>
                                    <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Disparo imediato segmentado</p>
                                </div>
                            </div>

                            <div className="space-y-6">
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">Segmentação do Público</Label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {[
                                            { id: 'all', label: 'Todos' },
                                            { id: 'vip', label: 'Clientes VIP' },
                                            { id: 'inactive', label: 'Inativos (30d)' },
                                            { id: 'new', label: 'Novos Clientes' }
                                        ].map(s => (
                                            <button
                                                key={s.id}
                                                onClick={() => setSegment(s.id)}
                                                className={`h-12 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all ${segment === s.id
                                                    ? 'bg-zinc-900 text-white border-zinc-900 shadow-md'
                                                    : 'bg-zinc-50 text-zinc-400 border-zinc-100 hover:bg-zinc-100'
                                                    }`}
                                            >
                                                {s.label}
                                            </button>
                                        ))}
                                    </div>
                                    <p className="text-[9px] font-bold text-emerald-600 uppercase tracking-widest ml-1">
                                        Alcance Estimado: {segment === 'all' ? subCount : predictedReach} dispositivos
                                    </p>
                                </div>

                                <div className="space-y-3">
