                                            </span>
                                        </div>
                                        <h4 className="text-[10px] font-black text-zinc-900 uppercase tracking-wider mb-2 line-clamp-1">{item.title}</h4>
                                        <div className="flex items-center justify-between text-[9px] font-bold text-zinc-400 uppercase tracking-widest">
                                            <span className="flex items-center gap-1"><Users className="w-3 h-3" /> {item.recipient_count}</span>
                                            <span className="text-zinc-200">|</span>
                                            <span className="truncate max-w-[80px]">{item.url}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { MessageSquare, ArrowLeft, Trash2 } from 'lucide-react';
import { useQuestions } from '@/hooks/useQuestions';
import type { Question } from '@/hooks/useQuestions';
import { toast } from 'sonner';

import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
interface AdminQAViewProps {
    onNavigate: (view: any) => void;
}

export function AdminQAView({ onNavigate }: AdminQAViewProps) {
    const { questions, loading, getAllQuestions, addAnswer, deleteQuestion, subscribeToQuestions } = useQuestions();
    const [selectedQuestion, setSelectedQuestion] = useState<Question | null>(null);
    const [answer, setAnswer] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [filter, setFilter] = useState<'pending' | 'all'>('pending');
    const [page, setPage] = useState(0);
    const [totalQuestions, setTotalQuestions] = useState(0);
    const pageSize = 10;

    useEffect(() => {
        const load = async () => {
            const result = await getAllQuestions(page, pageSize, filter);
            if (result) setTotalQuestions(result.total);
        };
        load();
        const unsubscribe = subscribeToQuestions();
        return () => unsubscribe();
    }, [getAllQuestions, subscribeToQuestions, page, filter]);

    const handleSendAnswer = async () => {
        if (!selectedQuestion || !answer.trim()) return;

        setIsSubmitting(true);
        try {
            const success = await addAnswer({
                questionId: selectedQuestion.id,
                answer: answer
            });

            if (success) {
                toast.success('Resposta enviada e cliente notificado!');
                setSelectedQuestion(null);
                setAnswer('');
                getAllQuestions(page, pageSize, filter);
            }
        } catch (error) {
            console.error('Error answering:', error);
            toast.error('Erro ao processar resposta');
        } finally {
            setIsSubmitting(false);
        }
    };

    const filteredQuestions = questions; // Server-side filtering planned

    const totalPages = Math.ceil(totalQuestions / pageSize);

    return (
        <div className="min-h-screen bg-zinc-50/30 pb-20">
            {/* Header */}
            <div className="glass px-4 py-4 sticky top-0 z-50 border-b border-zinc-100">
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => onNavigate('admin-dashboard')}
                        className="w-10 h-10 flex items-center justify-center bg-zinc-50 text-zinc-900 rounded-xl hover:bg-zinc-100 transition-all active:scale-95 border border-zinc-100"
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-lg font-black text-zinc-900 tracking-tight">Perguntas & Respostas</h1>
                        <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">
                            {totalQuestions} perguntas no total
                        </p>
                    </div>
                </div>
            </div>

            <div className="px-4 py-6 space-y-6">
                {/* Filters */}
                <div className="flex gap-2 p-1 bg-zinc-50 rounded-2xl w-fit border border-zinc-100 shadow-inner">
                    <button
                        onClick={() => setFilter('pending')}
                        className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${filter === 'pending'
                            ? 'bg-white text-zinc-900 shadow-premium-sm border border-zinc-100'
                            : 'text-zinc-400 hover:text-zinc-600'}`}
                    >
                        Pendentes
                    </button>
                    <button
                        onClick={() => setFilter('all')}
                        className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${filter === 'all'
                            ? 'bg-white text-zinc-900 shadow-premium-sm border border-zinc-100'
                            : 'text-zinc-400 hover:text-zinc-600'}`}
                    >
                        Todas
                    </button>
                </div>

                {loading ? (
                    <div className="flex flex-col items-center justify-center py-20">
                        <div className="w-12 h-12 border-2 border-zinc-100 border-t-zinc-900 rounded-full animate-spin mb-4" />
                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Sincronizando dúvidas...</p>
                    </div>
                ) : filteredQuestions.length === 0 ? (
                    <div className="bg-zinc-50/50 rounded-[2.5rem] border border-dashed border-zinc-200 p-16 text-center">
                        <MessageSquare className="w-16 h-16 text-zinc-200 mx-auto mb-4" />
                        <h3 className="text-sm font-black text-zinc-900 uppercase tracking-widest">Tudo limpo!</h3>
                        <p className="text-[11px] font-bold text-zinc-400 uppercase tracking-tight mt-1">Nenhuma pergunta encontrada.</p>
                    </div>
                ) : (
                    <div className="grid gap-6">
                        {filteredQuestions.map((q) => (
                            <div key={q.id} className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden shadow-premium-sm hover:shadow-premium transition-all duration-300">
                                <div className="p-6 bg-zinc-50/30 border-b border-zinc-100/50">
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1">
                                            <div className="flex items-center gap-3 mb-3">
                                                <div className="w-10 h-10 rounded-2xl bg-zinc-900 text-white flex items-center justify-center text-[12px] font-black shadow-premium">
                                                    {q.customerName.charAt(0).toUpperCase()}
                                                </div>
                                                <div>
                                                    <p className="text-[11px] font-black text-zinc-900 uppercase tracking-tight">{q.customerName}</p>
                                                    <p className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest">
                                                        {new Date(q.createdAt).toLocaleDateString('pt-BR')}
                                                    </p>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2 p-1.5 bg-white rounded-2xl border border-zinc-100 shadow-premium-sm">
                                                <img
                                                    src={q.productImage || 'https://placehold.co/100x100?text=Sem+Imagem'}
                                                    alt={q.productName}
                                                    className="w-8 h-8 rounded-lg object-cover bg-zinc-100"
                                                />
                                                <span className="text-[9px] font-black text-zinc-900 uppercase truncate max-w-[120px]">{q.productName}</span>
                                            </div>
                                        </div>
                                        <button
                                            className="w-10 h-10 flex items-center justify-center bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all active:scale-95 border border-red-100"
                                            onClick={() => deleteQuestion(q.id)}
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                                <div className="p-6">
                                    <p className="text-sm font-bold text-zinc-800 leading-relaxed italic mb-4">
                                        {q.question}
                                    </p>

                                    {q.answers.length > 0 ? (
                                        <div className="space-y-4">
                                            {q.answers.map(ans => (
                                                <div key={ans.id} className="bg-zinc-950 text-white p-6 rounded-[2rem] relative overflow-hidden shadow-premium transition-all hover:scale-[1.01]">
                                                    <p className="text-sm font-medium text-zinc-200 leading-relaxed">{ans.answer}</p>
                                                </div>
                                            ))}
                                        </div>
                                    ) : (
                                        <button
                                            className="w-full h-14 bg-zinc-900 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-premium hover:shadow-premium-lg hover:bg-zinc-800 transition-all active:scale-95 flex items-center justify-center gap-3"
                                            onClick={() => setSelectedQuestion(q)}
                                        >
                                            <MessageSquare className="w-4 h-4" />
                                            Responder Pergunta
                                        </button>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Pagination Controls */}
                {totalPages > 1 && (
                    <div className="flex items-center justify-center gap-4 pt-8">
                        <button
                            onClick={() => setPage(prev => Math.max(0, prev - 1))}
                            disabled={page === 0}
                            className="w-12 h-12 flex items-center justify-center bg-white rounded-2xl border border-zinc-100 text-zinc-900 shadow-premium-sm disabled:opacity-50 hover:bg-zinc-50 transition-all active:scale-95"
                        >
                            <ArrowLeft className="w-5 h-5" />
                        </button>
                        <div className="flex items-center justify-center px-4">
                            <span className="text-[11px] font-black uppercase tracking-widest text-zinc-500">
                                Página <span className="text-zinc-900">{page + 1}</span> de <span className="text-zinc-900">{totalPages}</span>
                            </span>
                        </div>
                        <button
                            onClick={() => setPage(prev => Math.min(totalPages - 1, prev + 1))}
                            disabled={page === totalPages - 1}
                            className="w-12 h-12 flex items-center justify-center bg-white rounded-2xl border border-zinc-100 text-zinc-900 shadow-premium-sm disabled:opacity-50 hover:bg-zinc-50 transition-all active:scale-95"
                        >
                            <ArrowLeft className="w-5 h-5 rotate-180" />
                        </button>
                    </div>
                )}
            </div>

            {/* Answer Modal */}
            <Dialog open={!!selectedQuestion} onOpenChange={() => setSelectedQuestion(null)}>
                <DialogContent className="sm:max-w-lg rounded-[2.5rem] border-zinc-100 shadow-premium p-0 overflow-hidden">
                    <DialogHeader className="p-8 pb-0">
                        <DialogTitle className="text-xl font-black text-zinc-900 tracking-tight flex items-center gap-3 uppercase">
                            <MessageSquare className="w-6 h-6 text-zinc-400" />
                            Responder Pergunta
                        </DialogTitle>
                        <DialogDescription className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest mt-2">
                            {selectedQuestion?.customerName} • {selectedQuestion?.productName}
                        </DialogDescription>
                    </DialogHeader>

                    <div className="p-8 space-y-6">
                        <div className="bg-zinc-50 p-6 rounded-3xl border border-zinc-100 relative overflow-hidden group">
                            <span className="absolute -left-1 -top-1 text-zinc-200/50 text-6xl font-black italic select-none">"</span>
                            <p className="text-sm font-bold text-zinc-700 italic relative z-10 leading-relaxed">
                                {selectedQuestion?.question}
                            </p>
                        </div>

                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest ml-1">Sua Resposta Especialista</label>
                            <textarea
                                value={answer}
                                onChange={(e) => setAnswer(e.target.value)}
                                placeholder="Dê uma resposta detalhada e persuasiva..."
                                className="w-full h-40 px-5 py-5 bg-zinc-50 border border-zinc-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-zinc-900/5 focus:bg-white focus:border-zinc-900 transition-all resize-none shadow-inner"
                            />
                        </div>

                        <div className="flex gap-4 pt-2">
                            <button
                                onClick={() => setSelectedQuestion(null)}
                                className="flex-1 h-14 bg-zinc-50 text-zinc-500 rounded-2xl text-[11px] font-black uppercase tracking-widest border border-zinc-100 hover:bg-zinc-100 transition-all active:scale-95"
                            >
                                Cancelar
                            </button>
                            <button
                                onClick={handleSendAnswer}
                                disabled={isSubmitting || !answer.trim()}
                                className="flex-[1.5] h-14 bg-zinc-900 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-premium hover:bg-zinc-800 transition-all active:scale-95 disabled:opacity-50 disabled:scale-100"
                            >
                                {isSubmitting ? 'Enviando...' : 'Publicar Resposta'}
                            </button>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from 'react';
