import { useState, useEffect } from 'react';
import {
    ArrowLeft,
    Mail,
    Phone,
    Calendar,
    Package,
    ShoppingCart,
    CreditCard,
    MapPin,
    ExternalLink,
    MessageSquare
} from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from '@/components/ui/table';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { mapOrderFromDB, mapProductFromDB } from '@/lib/mappers';
import type { Order, CartItem, Address } from '@/types';
import { toast } from 'sonner';

interface AdminUserDetailViewProps {
    userId: string;
    onBack: () => void;
    onNavigate: (view: any, id?: string) => void;
}

export function AdminUserDetailView({ userId, onBack, onNavigate }: AdminUserDetailViewProps) {
    const [loading, setLoading] = useState(true);
    const [profile, setProfile] = useState<any>(null);
    const [orders, setOrders] = useState<Order[]>([]);
    const [cartItems, setCartItems] = useState<CartItem[]>([]);
    const [addresses, setAddresses] = useState<Address[]>([]);

    useEffect(() => {
        fetchUserData();
    }, [userId]);

    const fetchUserData = async () => {
        setLoading(true);
        try {
            // 1. Fetch Profile
            const { data: profileData, error: profileError } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single();

            if (profileError) throw profileError;
            setProfile(profileData);

            // 2. Fetch Orders
            const { data: ordersData, error: ordersError } = await supabase
                .from('marketplace_orders')
                .select(`*, items:marketplace_order_items(*)`)
                .eq('user_id', userId)
                .order('created_at', { ascending: false });

            if (ordersError) throw ordersError;
            setOrders(ordersData?.map(mapOrderFromDB) || []);

            // 3. Fetch Cart Items
            const { data: cartData, error: cartError } = await supabase
                .from('cart_items')
                .select('*')
                .eq('user_id', userId);

            if (cartError) throw cartError;

            if (cartData && cartData.length > 0) {
                const productIds = cartData.map(item => item.product_id);
                const { data: products, error: prodError } = await supabase
                    .from('produtos')
                    .select('*')
                    .in('id', productIds);

                if (prodError) throw prodError;

                const reconstructedCart: CartItem[] = cartData.map(dbItem => {
                    const product = products.find(p => p.id === dbItem.product_id);
                    return {
                        product: mapProductFromDB(product as any),
                        quantity: dbItem.quantity,
                        variantId: dbItem.variant_id || undefined
                    };
                }).filter(item => item.product);

                setCartItems(reconstructedCart);
            }

            // 4. Fetch Addresses
            const { data: addData, error: addError } = await supabase
                .from('user_addresses')
                .select('*')
                .eq('user_id', userId);

            if (!addError) setAddresses(addData || []);

        } catch (err: any) {
            console.error('[AdminUserDetail] Error fetching data:', err);
            toast.error('Erro ao carregar dados do usuário');
        } finally {
            setLoading(false);
        }
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'new': return <Badge variant="secondary" className="bg-blue-100 text-blue-800 border-blue-200">Novo</Badge>;
            case 'processing': return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800 border-yellow-200">Processando</Badge>;
            case 'shipping': return <Badge variant="secondary" className="bg-blue-100 text-blue-800 border-blue-200">Enviado</Badge>;
            case 'delivered': return <Badge variant="secondary" className="bg-green-100 text-green-800 border-green-200">Entregue</Badge>;
            case 'cancelled': return <Badge variant="destructive">Cancelado</Badge>;
            default: return <Badge variant="outline">{status}</Badge>;
        }
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[400px] space-y-4">
                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <p className="text-muted-foreground animate-pulse">Carregando detalhes do cliente...</p>
            </div>
        );
    }

    const totalSpent = orders
        .filter(o => o.status !== 'cancelled')
        .reduce((sum, o) => sum + o.total, 0);

    return (
        <div className="space-y-6 pb-20 max-w-7xl mx-auto">
            {/* Header / Actions */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={onBack} className="rounded-full">
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight">Detalhes do Cliente</h1>
                        <p className="text-sm text-muted-foreground">ID: {userId}</p>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <Button
                        className="flex-1 md:flex-none gap-2"
                        onClick={() => window.open(`https://wa.me/${profile?.whatsapp?.replace(/\D/g, '')}`, '_blank')}
                    >
                        <MessageSquare className="h-4 w-4" />
                        WhatsApp
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left Column: Profile Card */}
                <Card className="lg:col-span-1 h-fit border-none shadow-sm bg-gradient-to-br from-white to-slate-50/50">
                    <CardHeader className="flex flex-col items-center pb-2">
                        <Avatar className="h-24 w-24 border-4 border-white shadow-lg">
                            <AvatarImage src={profile?.avatar_url} />
                            <AvatarFallback className="text-2xl bg-primary/10 text-primary">
                                {profile?.full_name?.substring(0, 2).toUpperCase() || '??'}
                            </AvatarFallback>
                        </Avatar>
                        <CardTitle className="mt-4 text-xl">{profile?.full_name || 'N/A'}</CardTitle>
                        <Badge variant="outline" className="mt-1 capitalize">
                            {profile?.role || 'customer'}
                        </Badge>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-4">
                        <div className="space-y-3">
                            <div className="flex items-center gap-3 text-sm">
                                <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center text-blue-600">
                                    <Mail className="h-4 w-4" />
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-xs text-muted-foreground uppercase font-semibold tracking-wider">Email</span>
                                    <span>{profile?.email || 'Sem email'}</span>
                                </div>
                            </div>

                            <div className="flex items-center gap-3 text-sm">
                                <div className="w-8 h-8 rounded-lg bg-green-50 flex items-center justify-center text-green-600">
                                    <Phone className="h-4 w-4" />
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-xs text-muted-foreground uppercase font-semibold tracking-wider">WhatsApp</span>
                                    <span>{profile?.whatsapp || 'N/A'}</span>
                                </div>
                            </div>

                            <div className="flex items-center gap-3 text-sm">
                                <div className="w-8 h-8 rounded-lg bg-orange-50 flex items-center justify-center text-orange-600">
                                    <Calendar className="h-4 w-4" />
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-xs text-muted-foreground uppercase font-semibold tracking-wider">Membro Desde</span>
                                    <span>{profile?.created_at ? format(new Date(profile.created_at), "dd 'de' MMMM, yyyy", { locale: ptBR }) : 'N/A'}</span>
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 border-t space-y-3">
                            <h3 className="text-sm font-semibold flex items-center gap-2">
                                <MapPin className="h-4 w-4 text-primary" /> Endereços
                            </h3>
                            {addresses.length === 0 ? (
                                <p className="text-xs text-muted-foreground text-center py-2 italic">Nenhum endereço cadastrado</p>
                            ) : (
                                <div className="space-y-2">
                                    {addresses.map(addr => (
                                        <div key={addr.id} className="text-xs p-2 rounded-md bg-white border shadow-sm">
                                            <div className="font-semibold flex items-center justify-between mb-1">
                                                {addr.name}
                                                {addr.is_default && <Badge className="text-[10px] h-4 px-1">Padrão</Badge>}
                                            </div>
                                            <p className="text-muted-foreground">
                                                {addr.street}, {addr.number}{addr.complement ? ` - ${addr.complement}` : ''}
                                            </p>
                                            <p className="text-muted-foreground">{addr.neighborhood}, {addr.city}-{addr.state}</p>
                                            <p className="mt-1 font-mono text-[10px]">{addr.cep}</p>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Right Column: Content Tabs */}
                <div className="lg:col-span-2 space-y-6">
                    {/* Quick Stats Banner */}
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                        <Card className="bg-primary/5 border-primary/10 overflow-hidden relative">
                            <div className="absolute right-[-10px] top-[-10px] opacity-10">
                                <CreditCard className="h-24 w-24" />
                            </div>
                            <CardContent className="p-4">
                                <p className="text-xs font-semibold text-primary/70 uppercase tracking-wider">Total Gasto</p>
                                <p className="text-2xl font-bold mt-1">
                                    {totalSpent.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                                </p>
                            </CardContent>
                        </Card>

                        <Card className="border-none shadow-sm bg-white overflow-hidden relative">
                            <div className="absolute right-[-10px] top-[-10px] opacity-10">
                                <Package className="h-24 w-24 text-blue-600" />
                            </div>
                            <CardContent className="p-4">
                                <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Pedidos</p>
                                <p className="text-2xl font-bold mt-1">{orders.length}</p>
                            </CardContent>
                        </Card>

                        <Card className="border-none shadow-sm bg-white overflow-hidden relative">
                            <div className="absolute right-[-10px] top-[-10px] opacity-10">
                                <ShoppingCart className="h-24 w-24 text-green-600" />
                            </div>
                            <CardContent className="p-4">
                                <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">No Carrinho</p>
                                <p className="text-2xl font-bold mt-1 text-green-600">{cartItems.reduce((s, i) => s + i.quantity, 0)} itens</p>
                            </CardContent>
                        </Card>
                    </div>

                    <Tabs defaultValue="orders" className="w-full">
                        <TabsList className="grid w-full grid-cols-2 bg-slate-100 p-1">
                            <TabsTrigger value="orders" className="flex items-center gap-2">
                                <Package className="h-4 w-4" /> Histórico
                            </TabsTrigger>
                            <TabsTrigger value="cart" className="flex items-center gap-2">
                                <ShoppingCart className="h-4 w-4" /> Carrinho Atual
                            </TabsTrigger>
                        </TabsList>

                        <TabsContent value="orders" className="mt-4">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Últimos Pedidos</CardTitle>
                                </CardHeader>
                                <CardContent className="p-0 sm:p-6">
                                    {orders.length === 0 ? (
                                        <div className="text-center py-10 text-muted-foreground">
                                            Nenhum pedido realizado ainda.
                                        </div>
                                    ) : (
                                        <div className="overflow-x-auto">
                                            <Table>
                                                <TableHeader>
                                                    <TableRow>
                                                        <TableHead>Pedido</TableHead>
                                                        <TableHead>Data</TableHead>
                                                        <TableHead>Status</TableHead>
                                                        <TableHead className="text-right">Total</TableHead>
                                                        <TableHead></TableHead>
                                                    </TableRow>
                                                </TableHeader>
                                                <TableBody>
                                                    {orders.map((order) => (
                                                        <TableRow key={order.id} className="cursor-pointer hover:bg-slate-50" onClick={() => onNavigate('order-details', order.id)}>
                                                            <TableCell className="font-medium font-mono text-xs">
                                                                #{order.id.substring(0, 8).toUpperCase()}
                                                            </TableCell>
                                                            <TableCell className="text-xs">
                                                                {format(new Date(order.createdAt), 'dd/MM/yy HH:mm')}
                                                            </TableCell>
                                                            <TableCell>{getStatusBadge(order.status)}</TableCell>
                                                            <TableCell className="text-right font-semibold">
                                                                {order.total.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                                                            </TableCell>
                                                            <TableCell>
                                                                <ExternalLink className="h-4 w-4 text-muted-foreground" />
                                                            </TableCell>
                                                        </TableRow>
                                                    ))}
                                                </TableBody>
                                            </Table>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        </TabsContent>

                        <TabsContent value="cart" className="mt-4">
                            <Card className="border-green-100">
                                <CardHeader className="bg-green-50/30">
                                    <div className="flex items-center justify-between">
                                        <div>
                                            <CardTitle className="text-green-800">Carrinho em Tempo Real</CardTitle>
                                            <CardDescription>O que este cliente adicionou e ainda não finalizou.</CardDescription>
                                        </div>
                                        {cartItems.length > 0 && <Badge className="bg-green-600">{cartItems.length} Itens</Badge>}
                                    </div>
                                </CardHeader>
                                <CardContent className="p-0 sm:p-6">
                                    {cartItems.length === 0 ? (
                                        <div className="text-center py-12">
                                            <div className="inline-flex h-16 w-16 items-center justify-center rounded-full bg-slate-50 mb-4">
                                                <ShoppingCart className="h-8 w-8 text-slate-300" />
                                            </div>
                                            <p className="text-muted-foreground">O carrinho está vazio no momento.</p>
                                        </div>
                                    ) : (
                                        <div className="overflow-x-auto">
                                            <Table>
                                                <TableHeader>
                                                    <TableRow>
                                                        <TableHead>Produto</TableHead>
                                                        <TableHead className="text-center">Qtd</TableHead>
                                                        <TableHead>Preço Un.</TableHead>
                                                        <TableHead className="text-right">Total</TableHead>
                                                    </TableRow>
                                                </TableHeader>
                                                <TableBody>
                                                    {cartItems.map((item, idx) => {
                                                        const variant = item.variantId ? item.product.variants?.find(v => v.id === item.variantId) : null;
                                                        const unitPrice = variant?.priceOverride || item.product.price;

                                                        return (
                                                            <TableRow key={idx}>
                                                                <TableCell>
                                                                    <div className="flex items-center gap-3">
                                                                        <Avatar className="h-10 w-10 rounded-md">
                                                                            <AvatarImage src={item.product.images[0]} className="object-cover" />
                                                                            <AvatarFallback>P</AvatarFallback>
                                                                        </Avatar>
                                                                        <div className="flex flex-col">
                                                                            <span className="font-medium text-sm line-clamp-1">{item.product.name}</span>
                                                                            {variant && <span className="text-[10px] text-muted-foreground italic">{variant.name}: {variant.value}</span>}
                                                                        </div>
                                                                    </div>
                                                                </TableCell>
                                                                <TableCell className="text-center">{item.quantity}x</TableCell>
                                                                <TableCell className="text-sm">
                                                                    {unitPrice.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                                                                </TableCell>
                                                                <TableCell className="text-right font-semibold text-primary">
                                                                    {(unitPrice * item.quantity).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                                                                </TableCell>
                                                            </TableRow>
                                                        );
                                                    })}
                                                    <TableRow className="bg-slate-50/50 hover:bg-slate-50/50">
                                                        <TableCell colSpan={3} className="text-right font-semibold uppercase tracking-wider text-xs">Valor Estimado do Carrinho:</TableCell>
                                                        <TableCell className="text-right font-bold text-lg text-green-600">
                                                            {cartItems.reduce((acc, item) => {
                                                                const variant = item.variantId ? item.product.variants?.find(v => v.id === item.variantId) : null;
                                                                return acc + (variant?.priceOverride || item.product.price) * item.quantity;
                                                            }, 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                                                        </TableCell>
                                                    </TableRow>
                                                </TableBody>
                                            </Table>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        </TabsContent>
                    </Tabs>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
    User,
    Mail,
    ChevronLeft,
    Loader2,
    Shield,
    Phone,
    KeyRound,
    AlertTriangle,
    CheckCircle2
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { toast } from 'sonner';
import type { View } from '@/types';

interface AccountSettingsViewProps {
    onNavigate: (view: View) => void;
}

export function AccountSettingsView({ onNavigate }: AccountSettingsViewProps) {
    const { user } = useAuth();
    const [loading, setLoading] = useState(false);
    const [updatingPassword, setUpdatingPassword] = useState(false);

    const [profileData, setProfileData] = useState({
        name: '',
        phone: '',
        email: ''
    });

    const [passwordData, setPasswordData] = useState({
        newPassword: '',
        confirmPassword: ''
    });

    useEffect(() => {
        if (user) {
            const fetchProfile = async () => {
                const { data, error } = await supabase
                    .from('profiles')
                    .select('full_name, whatsapp')
                    .eq('id', user.id)
                    .single();

                if (data && !error) {
                    setProfileData({
                        name: data.full_name || '',
                        phone: data.whatsapp || '',
                        email: user.email || ''
                    });
                }
            };
            fetchProfile();
        }
    }, [user]);

    const handleUpdateProfile = async () => {
        if (!user) return;
        setLoading(true);
        try {
            const { error } = await supabase
                .from('profiles')
                .update({
                    full_name: profileData.name,
                    whatsapp: profileData.phone
                })
                .eq('id', user.id);

            if (error) throw error;
            toast.success('Perfil atualizado com sucesso');
        } catch (error) {
            console.error('Update error:', error);
            toast.error('Erro ao atualizar perfil');
        } finally {
            setLoading(false);
        }
    };

    const handleChangePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (passwordData.newPassword !== passwordData.confirmPassword) {
            toast.error('As senhas não coincidem');
            return;
        }

        if (passwordData.newPassword.length < 6) {
            toast.error('A senha deve ter pelo menos 6 caracteres');
            return;
        }

        setUpdatingPassword(true);
        try {
            const { error } = await supabase.auth.updateUser({
                password: passwordData.newPassword
            });

            if (error) throw error;

            toast.success('Senha alterada com sucesso!');
            setPasswordData({ newPassword: '', confirmPassword: '' });
        } catch (error: any) {
            console.error('Password update error:', error);
            toast.error('Erro ao alterar senha: ' + (error.message || 'Erro inesperado'));
        } finally {
            setUpdatingPassword(false);
        }
    };

    if (!user) return null;

    return (
        <div className="min-h-screen bg-white">
            {/* Header Sticky */}
            <div className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-zinc-100 px-6 py-4 flex items-center justify-between">
                <button
                    onClick={() => onNavigate('profile')}
                    className="p-2 -ml-2 hover:bg-zinc-50 rounded-full transition-colors"
                >
                    <ChevronLeft className="w-6 h-6 text-zinc-900" />
                </button>
                <h1 className="text-sm font-black uppercase tracking-[0.2em] text-zinc-900">Configurações</h1>
                <div className="w-10" /> {/* Spacer */}
            </div>

            <div className="max-w-md mx-auto px-6 py-8 space-y-10">
                {/* Profile Section */}
                <section className="space-y-6">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-zinc-900 rounded-2xl flex items-center justify-center shadow-lg shadow-zinc-200">
                            <User className="w-5 h-5 text-white" />
                        </div>
                        <div>
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">Perfil</h2>
                            <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Informações públicas</p>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">Nome Completo</label>
                            <Input
                                value={profileData.name}
                                onChange={e => setProfileData(p => ({ ...p, name: e.target.value }))}
                                className="h-14 bg-zinc-50 border-none rounded-2xl font-bold px-6 focus-visible:ring-2 focus-visible:ring-zinc-200"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">WhatsApp</label>
                            <div className="relative">
                                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                                <Input
                                    value={profileData.phone}
                                    onChange={e => setProfileData(p => ({ ...p, phone: e.target.value }))}
                                    className="h-14 bg-zinc-50 border-none rounded-2xl font-bold pl-12 pr-6 focus-visible:ring-2 focus-visible:ring-zinc-200"
                                    placeholder="(00) 00000-0000"
                                />
                            </div>
                        </div>
                        <Button
                            onClick={handleUpdateProfile}
                            disabled={loading}
                            className="w-full h-14 bg-zinc-900 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-zinc-100"
                        >
                            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Salvar Alterações'}
                        </Button>
                    </div>
                </section>

                <div className="h-px bg-zinc-100" />

                {/* Security Section */}
                <section className="space-y-6">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-amber-500 rounded-2xl flex items-center justify-center shadow-lg shadow-amber-200">
                            <Shield className="w-5 h-5 text-white" />
                        </div>
                        <div>
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">Segurança</h2>
                            <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Proteção da conta</p>
                        </div>
                    </div>

                    {/* Password compromised warning if applicable */}
                    <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex gap-4">
                        <AlertTriangle className="w-5 h-5 text-red-500 shrink-0" />
                        <div className="space-y-1">
                            <p className="text-[10px] font-black uppercase tracking-widest text-red-600">Alerta de Senha</p>
                            <p className="text-[10px] font-bold text-red-400 leading-relaxed uppercase tracking-tighter">
                                Use uma senha forte e exclusiva. Evite reutilizar senhas de outros sites.
                            </p>
                        </div>
                    </div>

                    <form onSubmit={handleChangePassword} className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">E-mail (Login)</label>
                            <div className="relative">
                                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                                <Input
                                    value={profileData.email}
                                    disabled
                                    className="h-14 bg-zinc-50/50 border-none rounded-2xl font-bold pl-12 pr-6 opacity-60 italic"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">Nova Chave de Acesso</label>
                            <div className="relative">
                                <KeyRound className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                                <Input
                                    type="password"
                                    value={passwordData.newPassword}
                                    onChange={e => setPasswordData(d => ({ ...d, newPassword: e.target.value }))}
                                    className="h-14 bg-zinc-50 border-none rounded-2xl font-bold pl-12 pr-6 focus-visible:ring-2 focus-visible:ring-zinc-200"
                                    placeholder="No mínimo 6 caracteres"
                                    required
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">Confirmar Nova Chave</label>
                            <div className="relative">
                                <KeyRound className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                                <Input
                                    type="password"
                                    value={passwordData.confirmPassword}
                                    onChange={e => setPasswordData(d => ({ ...d, confirmPassword: e.target.value }))}
                                    className="h-14 bg-zinc-50 border-none rounded-2xl font-bold pl-12 pr-6 focus-visible:ring-2 focus-visible:ring-zinc-200"
                                    placeholder="Repita a nova senha"
                                    required
                                />
                            </div>
                        </div>

                        <Button
                            type="submit"
                            disabled={updatingPassword}
                            className="w-full h-16 bg-zinc-900 text-white rounded-[1.5rem] font-black uppercase tracking-widest text-[11px] shadow-2xl shadow-zinc-200 hover:bg-black transition-all active:scale-[0.98]"
                        >
                            {updatingPassword ? <Loader2 className="w-4 h-4 animate-spin" /> : (
                                <div className="flex items-center gap-2">
                                    <Shield className="w-4 h-4" />
                                    Atualizar Senha Agora
                                </div>
                            )}
                        </Button>
                    </form>
                </section>

                {/* Footer simple info */}
                <div className="text-center pt-6">
                    <div className="inline-flex items-center gap-2 px-3 py-1 bg-zinc-50 rounded-full">
                        <CheckCircle2 className="w-3 h-3 text-emerald-500" />
                        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-400">Proteção Supabase Auth Ativa</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { ArrowLeft, CreditCard, Banknote, Smartphone, Check, MapPin, User, Phone, FileText, Tag, Plus, AlertCircle, Star } from 'lucide-react';
import confetti from 'canvas-confetti';
import type { CartItem, PaymentMethod, View, Customer, Address } from '@/types';
import { useStore } from '@/contexts/StoreContext';
import { useOrders } from '@/hooks/useOrders';
import { useCoupons } from '@/hooks/useCoupons';
import { useAuth } from '@/contexts/AuthContext';
import { useAddresses } from '@/hooks/useAddresses';
import { useLoyalty } from '@/hooks/useLoyalty';
import { haptic } from '@/utils/haptic';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { CouponInput } from '@/components/ui/custom/CouponInput';
import { AddressList } from '@/components/ui/custom/AddressList';
import { AddressForm } from '@/components/ui/custom/AddressForm';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

interface CheckoutViewProps {
  cart: CartItem[];
  subtotal: number;
  shipping: number;
  total: number;
  onClearCart: () => void;
  onNavigate: (view: View, productId?: string) => void;
}

export function CheckoutView({ cart, subtotal, shipping, total, onClearCart, onNavigate }: CheckoutViewProps) {
  const { config } = useStore();
  const { createOrder } = useOrders();
  const { validateCoupon, applyCoupon } = useCoupons();
  const { user } = useAuth();
  const { addresses, fetchAddresses, addAddress, loading: addressesLoading } = useAddresses();
  const { points: currentPoints, tier: currentTier, nextTierPoints } = useLoyalty();

  const [customer, setCustomer] = useState<Partial<Customer>>({
    name: user?.user_metadata?.name || '',
    whatsapp: user?.user_metadata?.whatsapp || '',
    address: '',
    number: '',
    neighborhood: '',
    reference: ''
  });
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('pix');
  const [notes, setNotes] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [orderId, setOrderId] = useState('');

  // Coupon state
  const [appliedCoupon, setAppliedCoupon] = useState<{ code: string; discount: number } | null>(null);
  const [couponError, setCouponError] = useState<string>('');

  // Address selection state
  const [selectedAddressId, setSelectedAddressId] = useState<string | null>(null);
  const [isAddressModalOpen, setIsAddressModalOpen] = useState(false);

  useEffect(() => {
    if (user) {
      fetchAddresses();
    }
  }, [user, fetchAddresses]);

  const handleSelectAddress = useCallback((address: Address) => {
    setSelectedAddressId(address.id);
    setCustomer(prev => ({
      ...prev,
      address: address.street,
      number: address.number,
      neighborhood: address.neighborhood,
      reference: address.reference
    }));
  }, []);

  // Set default address when addresses are loaded
  useEffect(() => {
    if (addresses.length > 0 && !selectedAddressId) {
      const defaultAddr = addresses.find(a => a.is_default) || addresses[0];
      handleSelectAddress(defaultAddr);
    }
  }, [addresses, selectedAddressId, handleSelectAddress]);

  // Values are now passed from props to ensure consistency
  const discount = appliedCoupon?.discount || 0;
  const finalTotal = total - discount;

  const isValid =
    customer.name?.trim() &&
    (customer.whatsapp?.replace(/\D/g, '').length || 0) >= 10 &&
    customer.address?.trim() &&
    customer.number?.trim() &&
    customer.neighborhood?.trim();

  const formatWhatsApp = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 2) return numbers;
    if (numbers.length <= 7) return `(${numbers.slice(0, 2)}) ${numbers.slice(2)}`;
    if (numbers.length <= 11) return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 7)}-${numbers.slice(7)}`;
    return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 7)}-${numbers.slice(7, 11)}`;
  };

  const handleRemoveCoupon = () => {
    setAppliedCoupon(null);
    setCouponError('');
  };

  const handleApplyCoupon = async (code: string) => {
    setCouponError('');
    try {
      const result = await validateCoupon(code, subtotal);

      if (result.valid) {
        setAppliedCoupon({ code, discount: result.discount });
        await applyCoupon(code);
      } else {
        setCouponError(result.message || 'Cupom inválido');
      }
    } catch (error) {
      console.error('Error applying coupon:', error);
      setCouponError('Erro ao validar cupom');
    }
  };


  const handleNewAddressSubmit = async (data: Omit<Address, 'id' | 'user_id'>) => {
    const newAddress = await addAddress(data);
    if (newAddress) {
      setIsAddressModalOpen(false);
      handleSelectAddress(newAddress);
    }
    return !!newAddress;
  };

  const handleSubmit = async () => {
    if (!isValid) return;

    setIsSubmitting(true);

    const orderData = {
      customer: customer as Customer,
      items: cart.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        price: item.product.price,
        quantity: item.quantity,
        image: item.product.images?.[0] || 'https://placehold.co/600x400?text=Sem+Imagem'
      })),
      subtotal,
      shipping,
      discount,
      total: finalTotal,
      paymentMethod,
      notes: notes || undefined,
      couponCode: appliedCoupon?.code,
      status: 'new' as const
    };

    try {
      const order = await createOrder(orderData);
      setOrderId(order.id);

      // Send WhatsApp message
      const message = `*Novo Pedido - IKCOUS*\n\n` +
        `*Pedido:* #${order.id.slice(-6)}\n` +
        `*Cliente:* ${customer.name}\n` +
        `*WhatsApp:* ${customer.whatsapp}\n\n` +
        `*Itens:*\n${cart.map(item =>
          `- ${item.product.name} (${item.quantity}x) - R$ ${(item.product.price * item.quantity).toFixed(2).replace('.', ',')}`
        ).join('\n')}\n\n` +
        `*Subtotal:* R$ ${subtotal.toFixed(2).replace('.', ',')}\n` +
        `${discount > 0 ? `*Desconto:* -R$ ${discount.toFixed(2).replace('.', ',')}\n` : ''}` +
        `*Frete:* ${shipping === 0 ? 'Grátis' : `R$ ${shipping.toFixed(2).replace('.', ',')}`}\n` +
        `*Total:* R$ ${finalTotal.toFixed(2).replace('.', ',')}\n\n` +
        `*Pagamento:* ${paymentMethod === 'pix' ? 'Pix' : paymentMethod === 'card' ? 'Cartão' : 'Dinheiro'}\n` +
        `*Endereço:* ${customer.address}, ${customer.number} - ${customer.neighborhood}${customer.reference ? ` (${customer.reference})` : ''}`;

      const whatsappUrl = `https://wa.me/55${config.whatsappNumber}?text=${encodeURIComponent(message)}`;
      window.open(whatsappUrl, '_blank');

      onClearCart();
      setShowSuccess(true);

      // Trigger confetti celebration
      confetti({
        particleCount: 150,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#000000', '#ffffff', '#10b981', '#fbbf24']
      });
    } catch (error: any) {
      console.error('Error creating order:', error);
      const errorMessage = error.message || 'Ocorreu um erro ao processar seu pedido.';
      toast.error(`Falha no Pedido: ${errorMessage}`);
      // Fallback alert if toast fails or for critical notice
      if (!error.message) alert('Ocorreu um erro ao criar o pedido. Por favor, tente novamente.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (showSuccess) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center px-6 pb-32 bg-white text-center">
        <div className="relative mb-12 group">
          <div className="absolute inset-0 bg-emerald-100 rounded-2xl scale-[2.5] blur-3xl opacity-30 group-hover:opacity-50 transition-opacity duration-1000" />
          <div className="relative w-32 h-32 bg-emerald-50 rounded-2xl flex items-center justify-center border-4 border-white shadow-2xl group-hover:scale-110 transition-transform duration-700">
            <Check className="w-14 h-14 text-emerald-500" />
          </div>
          {/* Decorative Sparks */}
          <div className="absolute -top-4 -right-4 w-8 h-8 bg-amber-400 rounded-full blur-xl animate-pulse" />
          <div className="absolute -bottom-2 -left-2 w-6 h-6 bg-primary/30 rounded-full blur-lg animate-pulse delay-500" />
        </div>

        <h2 className="text-4xl font-black text-zinc-900 mb-4 tracking-tighter leading-tight animate-in slide-in-from-bottom-4 duration-700">
          Pedido Celebreado!
        </h2>

        <div className="space-y-4 mb-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
          <p className="text-sm font-black uppercase tracking-[0.2em] text-zinc-400">
            Identificador: <span className="text-zinc-900">#{orderId.slice(-6).toUpperCase()}</span>
          </p>
          <div className="max-w-[300px] mx-auto">
            <p className="text-sm text-zinc-500 font-medium leading-relaxed">
              Sua escolha premium foi registrada. Agora, nossa equipe cuidará de cada detalhe da logística.
            </p>
          </div>
          {appliedCoupon && (
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-600 text-[10px] font-black uppercase tracking-widest rounded-lg border border-emerald-100/50">
              Privilégio Ativo: R$ {discount.toFixed(2).replace('.', ',')} OFF
            </div>
          )}
        </div>

        <div className="flex flex-col gap-4 w-full max-w-xs animate-in slide-in-from-bottom-12 duration-1000">
          <button
            onClick={() => onNavigate('home')}
            className="h-16 bg-zinc-900 text-white text-[11px] font-black uppercase tracking-[0.3em] rounded-2xl hover:bg-black transition-all shadow-3xl shadow-zinc-200 active:scale-95 flex items-center justify-center gap-3"
          >
            Retornar à Vitrine
            <ArrowLeft className="w-5 h-5 rotate-180" />
          </button>
          <button
            onClick={() => onNavigate('profile')}
            className="h-16 bg-white text-zinc-900 text-[11px] font-black uppercase tracking-[0.3em] rounded-2xl border-2 border-zinc-100 hover:border-zinc-900 transition-all active:scale-95 flex items-center justify-center gap-3"
          >
            Ver Meus Pedidos
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-40 bg-gray-50/10 pt-4">

      <div className="px-6 space-y-8">

        {/* Customer Info */}
        <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
          <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
              <User className="w-5 h-5 text-zinc-900" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Dados de Identificação</span>
          </div>
          <div className="p-8 space-y-6">
            <div>
              <label htmlFor="checkout-name" className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                Nome do Cliente
              </label>
              <input
                id="checkout-name"
                type="text"
                autoComplete="name"
                value={customer.name || ''}
                onChange={(e) => setCustomer(prev => ({ ...prev, name: e.target.value }))}
                placeholder="Seu nome completo"
                className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
              />
            </div>
            <div>
              <label htmlFor="checkout-tel" className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                WhatsApp Direct
              </label>
              <div className="relative">
                <Phone className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-zinc-300" aria-hidden="true" />
                <input
                  id="checkout-tel"
                  type="tel"
                  autoComplete="tel"
                  value={customer.whatsapp || ''}
                  onChange={(e) => setCustomer(prev => ({ ...prev, whatsapp: formatWhatsApp(e.target.value) }))}
                  placeholder="(34) 99999-9999"
                  maxLength={15}
                  className="w-full pl-14 pr-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Saved Addresses (Logged In Only) */}
        {user && (
          <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
            <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
                  <MapPin className="w-5 h-5 text-zinc-900" />
                </div>
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Seus Endereços</span>
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setIsAddressModalOpen(true)}
                className="h-10 px-4 text-[10px] font-black uppercase tracking-widest rounded-2xl bg-zinc-900 text-white hover:bg-black transition-all"
              >
                <Plus className="w-3.5 h-3.5 mr-2" /> Novo
              </Button>
            </div>
            <div className="p-6">
              {addressesLoading ? (
                <div className="py-12 flex flex-col items-center justify-center">
                  <div className="w-8 h-8 border-4 border-zinc-100 border-t-zinc-900 rounded-full animate-spin mb-4" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Sincronizando endereços...</p>
                </div>
              ) : (
                <AddressList
                  addresses={addresses}
                  selectable
                  selectedId={selectedAddressId || undefined}
                  onSelect={handleSelectAddress}
                  onEdit={() => { }}
                  onDelete={() => { }}
                />
              )}
            </div>
          </div>
        )}

        {/* Address Manually */}
        <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
          <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
              <MapPin className="w-5 h-5 text-zinc-900" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Destino de Entrega</span>
          </div>
          <div className="p-8 space-y-6">
            <div>
              <label className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                Logradouro
              </label>
              <input
                type="text"
                value={customer.address || ''}
                onChange={(e) => setCustomer(prev => ({ ...prev, address: e.target.value }))}
                placeholder="Rua, Avenida, etc"
                className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                  Número
                </label>
                <input
                  type="text"
                  value={customer.number || ''}
                  onChange={(e) => setCustomer(prev => ({ ...prev, number: e.target.value }))}
                  placeholder="123"
                  className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                  Bairro
                </label>
                <input
                  type="text"
                  value={customer.neighborhood || ''}
                  onChange={(e) => setCustomer(prev => ({ ...prev, neighborhood: e.target.value }))}
                  placeholder="Seu bairro"
                  className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-black uppercase tracking-[0.15em] text-zinc-400 mb-3 ml-1">
                Referência Especial
              </label>
              <input
                type="text"
                value={customer.reference || ''}
                onChange={(e) => setCustomer(prev => ({ ...prev, reference: e.target.value }))}
                placeholder="Ex: Próximo ao mercado principal"
                className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none"
              />
            </div>
          </div>
        </div>

        {/* Coupon */}
        <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
          <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
              <Tag className="w-5 h-5 text-zinc-900" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Vantagem Exclusiva</span>
          </div>
          <div className="p-8">
            <CouponInput
              onApply={handleApplyCoupon}
              onRemove={handleRemoveCoupon}
              appliedCoupon={appliedCoupon}
              error={couponError}
            />
          </div>
        </div>

        {/* Payment Method */}
        <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
          <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
              <CreditCard className="w-5 h-5 text-zinc-900" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Meio de Pagamento</span>
          </div>
          <div className="p-8 grid grid-cols-1 gap-4">
            {[
              { value: 'pix' as PaymentMethod, label: 'Pix Instantâneo', icon: Smartphone, color: 'text-emerald-500 bg-emerald-50' },
              { value: 'card' as PaymentMethod, label: 'Cartão de Crédito', icon: CreditCard, color: 'text-blue-500 bg-blue-50' },
              { value: 'cash' as PaymentMethod, label: 'Dinheiro em Mãos', icon: Banknote, color: 'text-amber-500 bg-amber-50' },
            ].map((option) => {
              const Icon = option.icon;
              return (
                <button
                  key={option.value}
                  onClick={() => setPaymentMethod(option.value)}
                  className={`w-full flex items-center gap-5 p-6 rounded-[2rem] border-2 transition-all duration-500 active:scale-[0.97] shadow-sm ${paymentMethod === option.value
                    ? 'border-zinc-900 bg-white shadow-2xl shadow-zinc-200 z-10'
                    : 'border-zinc-50 bg-zinc-50 hover:border-zinc-100 hover:bg-white'
                    }`}
                >
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${option.color} transition-all duration-500 ${paymentMethod === option.value ? 'scale-110 rotate-3' : ''}`}>
                    <Icon className="w-6 h-6" />
                  </div>
                  <span className={`text-sm font-black uppercase tracking-widest ${paymentMethod === option.value ? 'text-zinc-900' : 'text-zinc-400'}`}>
                    {option.label}
                  </span>
                  <div className={`ml-auto w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all duration-500 ${paymentMethod === option.value ? 'bg-zinc-900 border-zinc-900 scale-110' : 'border-zinc-200'}`}>
                    {paymentMethod === option.value && <Check className="w-4 h-4 text-white" />}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Notes */}
        <div className="bg-white rounded-[2.5rem] border border-zinc-100 overflow-hidden premium-shadow">
          <div className="px-6 py-5 bg-zinc-50/50 border-b border-zinc-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-white flex items-center justify-center shadow-sm">
              <FileText className="w-5 h-5 text-zinc-900" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Notas Adicionais (Opcional)</span>
          </div>
          <div className="p-8">
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Ex: Deixar na portaria, campainha estragada, etc..."
              rows={4}
              className="w-full px-6 py-5 bg-zinc-50 rounded-3xl text-sm font-black border-2 border-transparent focus:border-zinc-900 focus:bg-white focus:shadow-3xl focus:shadow-zinc-100 transition-all outline-none resize-none"
            />
          </div>
        </div>

        {/* Location Notice */}
        <div className="bg-zinc-900 text-white p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 group-hover:rotate-0 transition-transform duration-1000">
            <MapPin className="w-24 h-24" />
          </div>
          <div className="relative z-10 flex items-start gap-4">
            <div className="mt-1">
              <AlertCircle className="w-6 h-6 text-zinc-400" />
            </div>
            <div>
              <h4 className="text-sm font-black uppercase tracking-[0.2em] mb-2">Aviso de Região</h4>
              <p className="text-xs font-medium text-zinc-400 leading-relaxed uppercase tracking-tighter">
                Nossos serviços de entrega premium estão ativos exclusivamente em <span className="text-white font-black">Monte Carmelo, MG</span>.
              </p>
            </div>
          </div>
        </div>

        {/* Loyalty Reward Preview */}
        {user && (
          <div className={cn(
            "bg-gradient-to-br p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group mt-8 text-white",
            currentTier === 'Black' ? "from-zinc-900 via-zinc-800 to-black ring-1 ring-white/10" : "from-zinc-900 to-black"
          )}>
            <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 group-hover:rotate-0 transition-transform duration-1000">
              <Star className="w-24 h-24" />
            </div>
            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 rounded-2xl bg-white/10 flex items-center justify-center border border-white/10">
                  <Star className={cn(
                    "w-5 h-5",
                    currentTier === 'Black' ? "text-zinc-100 fill-zinc-100" : "text-amber-400 fill-amber-400"
                  )} />
                </div>
                <div>
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500">Ikcous Loyalty Program</h4>
                  <p className="text-sm font-black">Ganhe +{Math.floor(finalTotal)} pontos</p>
                </div>
              </div>

              <div className="space-y-4 pt-4 border-t border-white/10">
                <div className="flex justify-between items-end text-[9px] font-black uppercase tracking-widest">
                  <span className="text-zinc-500">Status atual: <span className="text-white italic">{currentTier}</span></span>
                  <span className="text-white">{currentPoints + Math.floor(finalTotal)} / {nextTierPoints > 0 ? nextTierPoints + currentPoints : 'MAX'}</span>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div
                    className={cn(
                      "h-full transition-all duration-1000 bg-white",
                      currentTier === 'Black' && "bg-gradient-to-r from-zinc-300 to-white"
                    )}
                    style={{ width: `${nextTierPoints > 0 ? Math.min(((currentPoints + Math.floor(finalTotal)) / (nextTierPoints + currentPoints)) * 100, 100) : 100}%` }}
                  />
                </div>
                <p className="text-[9px] font-medium text-zinc-400 leading-relaxed italic uppercase tracking-tighter">
                  {nextTierPoints > 0
                    ? `Faltam ${nextTierPoints - Math.floor(finalTotal)} pontos para elevar seu privil\u00e9gio.`
                    : 'Voc\u00ea atingiu a n\u00edvel Black. Exclusividade absoluta.'}
                </p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Order Summary */}
      <div className="sticky bottom-0 left-0 right-0 bg-white/90 backdrop-blur-2xl border-t border-zinc-100 p-4 pb-8 md:pb-12 z-40 shadow-[0_-20px_50px_rgba(0,0,0,0.1)] rounded-t-[2.5rem] mt-12">
        <div className="max-w-screen-md mx-auto">
          <div className="flex items-center justify-between mb-4 px-1">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400 leading-none mb-1">Total a Pagar</span>
              <span className="text-2xl font-black tracking-tighter text-zinc-900 leading-none">
                R$ {finalTotal.toFixed(2).replace('.', ',')}
              </span>
            </div>
            {discount > 0 && (
              <div className="px-3 py-1 bg-red-500 text-white text-[10px] font-black rounded-full uppercase tracking-wider">
                -R$ {discount.toFixed(2).replace('.', ',')} OFF
              </div>
            )}
          </div>

          <button
            onClick={() => {
              haptic.medium();
              handleSubmit();
            }}
            disabled={!isValid || isSubmitting}
            className={cn(
              "w-full h-14 transition-all duration-500 active:scale-[0.98] shadow-2xl flex items-center justify-center gap-2 rounded-3xl uppercase tracking-[0.2em] font-black text-xs",
              (!isValid || isSubmitting)
                ? "bg-zinc-200 text-zinc-500 cursor-not-allowed border border-zinc-300 shadow-none opacity-100"
                : "bg-zinc-900 text-white hover:bg-black shadow-zinc-200"
            )}
          >
            {isSubmitting ? (
              <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" />
            ) : (
              <>
                Finalizar Pedido
                <ArrowLeft className="w-5 h-5 rotate-180" />
              </>
            )}
          </button>
        </div>
      </div>

      {/* Address Modal */}
      <Dialog open={isAddressModalOpen} onOpenChange={setIsAddressModalOpen}>
        <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Novo Endereço</DialogTitle>
            <DialogDescription>
              Cadastre um novo endereço para suas entregas.
            </DialogDescription>
          </DialogHeader>
          <AddressForm
            onSubmit={handleNewAddressSubmit}
            onCancel={() => setIsAddressModalOpen(false)}
          />
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { MapPin, CreditCard, Package, Truck, CheckCircle, Clock, XCircle, ShoppingBag } from 'lucide-react';
import { useOrders } from '@/hooks/useOrders';
import type { Order, OrderStatus, View } from '@/types';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';
import { useCart } from '@/hooks/useCart';

interface OrderDetailsViewProps {
    orderId: string;
    onBack: () => void;
    onNavigate: (view: View) => void;
}

const statusConfig: Record<OrderStatus, { label: string; icon: any; color: string; bg: string }> = {
    new: { label: 'Novo', icon: Package, color: 'text-blue-600', bg: 'bg-blue-50' },
    processing: { label: 'Em Separação', icon: Clock, color: 'text-yellow-600', bg: 'bg-yellow-50' },
    shipping: { label: 'Em Trânsito', icon: Truck, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    delivered: { label: 'Entregue', icon: CheckCircle, color: 'text-green-600', bg: 'bg-green-50' },
    cancelled: { label: 'Cancelado', icon: XCircle, color: 'text-red-600', bg: 'bg-red-50' }
};

export function OrderDetailsView({ orderId, onBack, onNavigate }: OrderDetailsViewProps) {
    const { orders, fetchUserOrders } = useOrders(true, `order-details-${orderId}`);
    const { addToCart } = useCart();
    const [order, setOrder] = useState<Order | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const load = async () => {
            let currentOrders = orders;
            if (orders.length === 0) {
                currentOrders = await fetchUserOrders();
            }
            const found = currentOrders.find(o => o.id === orderId);
            setOrder(found || null);
            setLoading(false);
        };
        load();
    }, [orderId, fetchUserOrders]); // Remove 'orders' from dep to avoid loop if orders changes ref

    const handleBuyAgain = () => {
        if (!order) return;
        order.items.forEach(item => {
            // Reconstruct product object minimal needed for cart
            addToCart({
                id: item.productId,
                name: item.name,
                price: item.price,
                images: [item.image],
                category: '', // Missing in order item, acceptable
                stock: 99, // Unknown, assume available or check later
                isActive: true, // Assume active
                description: '',
                sold: 0,
                freeShipping: false,
                createdAt: '',
                isBestseller: false
            }, item.quantity);
        });
        onNavigate('cart');
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center py-12">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
        );
    }

    if (!order) {
        return (
            <div className="p-4 text-center">
                <h2 className="text-xl font-bold mb-2">Pedido não encontrado</h2>
                <Button onClick={onBack}>Voltar</Button>
            </div>
        );
    }

    const StatusIcon = statusConfig[order.status].icon;

    return (
        <div className="pb-24 animate-in fade-in duration-300 bg-gray-50/30 min-h-screen">

            <div className="p-4 space-y-4 max-w-2xl mx-auto">
                {/* Status Card */}
                <Card className="border-none shadow-sm bg-gray-50/50">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-gray-500">Status do Pedido</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className={`flex items-center gap-3 p-3 rounded-lg ${statusConfig[order.status].bg}`}>
                            <StatusIcon className={`w-5 h-5 ${statusConfig[order.status].color}`} />
                            <span className={`font-semibold ${statusConfig[order.status].color}`}>
                                {statusConfig[order.status].label}
                            </span>
                        </div>
                        <p className="text-xs text-gray-400 mt-2 pl-1">
                            Realizado em {order?.createdAt ? new Date(order.createdAt).toLocaleString('pt-BR') : 'Data Indisponível'}
                        </p>
                    </CardContent>
                </Card>

                {/* Items */}
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-base">Itens do Pedido</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        {order.items.map((item, idx) => (
                            <div key={idx} className="flex gap-3">
                                <div className="h-16 w-16 bg-gray-100 rounded-md overflow-hidden flex-shrink-0">
                                    <img src={item.image} alt={item.name} className="h-full w-full object-cover" />
                                </div>
                                <div className="flex-1">
                                    <p className="font-medium text-sm line-clamp-2">{item.name}</p>
                                    <p className="text-sm text-gray-500 mt-1">
                                        {item.quantity}x <span className="text-black font-semibold">R$ {item.price.toFixed(2)}</span>
                                    </p>
                                </div>
                            </div>
                        ))}
                    </CardContent>
                </Card>

                {/* Values */}
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-base">Resumo Financeiro</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-2 text-sm">
                        <div className="flex justify-between">
                            <span className="text-gray-500">Subtotal</span>
                            <span>R$ {order.subtotal.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                            <span className="text-gray-500">Frete</span>
                            <span>{order.shipping > 0 ? `R$ ${order.shipping.toFixed(2)}` : 'Grátis'}</span>
                        </div>
                        {order.discount > 0 && (
                            <div className="flex justify-between text-green-600">
                                <span>Desconto</span>
                                <span>- R$ {order.discount.toFixed(2)}</span>
                            </div>
                        )}
                        <Separator className="my-2" />
                        <div className="flex justify-between font-bold text-base">
                            <span>Total</span>
                            <span>R$ {order.total.toFixed(2)}</span>
                        </div>
                    </CardContent>
                </Card>

                {/* Delivery & Payment */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="text-sm font-medium flex items-center gap-2">
                                <MapPin className="w-4 h-4" /> Entrega
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="text-sm text-gray-600">
                            <p className="font-medium text-black">{order.customer.name}</p>
                            <p>{order.customer.address}, {order.customer.number}</p>
                            <p>{order.customer.neighborhood}</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="text-sm font-medium flex items-center gap-2">
                                <CreditCard className="w-4 h-4" /> Pagamento
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="text-sm text-gray-600">
                            <p className="capitalize">Método: {order.paymentMethod === 'card' ? 'Cartão de Crédito' : order.paymentMethod}</p>
                            {order.paymentMethod === 'pix' && <p className="text-xs text-yellow-600 mt-1">Aguardando confirmação</p>}
                        </CardContent>
                    </Card>
                </div>

                <Button className="w-full gap-2" size="lg" onClick={handleBuyAgain}>
                    <ShoppingBag className="w-4 h-4" />
                    Comprar Novamente
                </Button>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
  Heart, Share2, MessageCircle, Truck, ShieldCheck, Flame,
  ChevronLeft, ChevronRight, Check, Star, ShoppingCart
} from 'lucide-react';
import type { Product } from '@/types';
import { QuantitySelector } from '@/components/ui/custom/QuantitySelector';
import { StarRating } from '@/components/ui/custom/StarRating';
import { ReviewCard } from '@/components/ui/custom/ReviewCard';
import { ReviewForm } from '@/components/ui/custom/ReviewForm';
import { ProductQA } from '@/components/ui/custom/ProductQA';
import { useReviews } from '@/hooks/useReviews';
import { Helmet } from 'react-helmet-async';
import { Button } from '@/components/ui/button';
import { useAuth } from '@/contexts/AuthContext';
import { useProducts } from '@/hooks/useProducts';
import { useFavorites } from '@/hooks/useFavorites';
import { useStore } from '@/contexts/StoreContext';
import { ProductCard } from '@/components/ui/custom/ProductCard';
import { ProductCardSkeleton } from '@/components/ui/custom/ProductCardSkeleton';
import { MarkdownRenderer } from '@/components/ui/custom/MarkdownRenderer';

interface ProductViewProps {
  product: Product;
  isFavorite: boolean;
  onToggleFavorite: () => void;
  onAddToCart: (quantity: number, variantId?: string) => void;
  onBack: () => void;
  onProductClick?: (productId: string) => void;
  scrollProgress?: number;
}

export function ProductView({
  product,
  isFavorite,
  onToggleFavorite,
  onAddToCart,
  onBack,
  onProductClick,
  scrollProgress = 0
}: ProductViewProps) {
  const [quantity, setQuantity] = useState(1);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [showAddedToast, setShowAddedToast] = useState(false);
  const [activeTab, setActiveTab] = useState<'description' | 'reviews' | 'questions'>('description');
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [selectedVariants, setSelectedVariants] = useState<Record<string, string>>({});

  const { config } = useStore();
  const { reviews, loading: loadingReviews, getReviewsByProduct, markHelpful } = useReviews();
  const { trackRecommendationClick, fetchRecommendations } = useProducts({ autoFetch: false });
  const { isFavorite: checkFavorite, toggleFavorite } = useFavorites();
  const { user } = useAuth();

  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [loadingRecs, setLoadingRecs] = useState(true);

  const scrolled = scrollProgress > 400;

  useEffect(() => {
    getReviewsByProduct(product.id);
  }, [product.id, getReviewsByProduct]);

  useEffect(() => {
    const loadRecs = async () => {
      setLoadingRecs(true);
      const recs = await fetchRecommendations(product.id);
      setRecommendations(recs);
      setLoadingRecs(false);
    };
    loadRecs();
  }, [product.id, fetchRecommendations]);

  // Calculate average rating and count on the fly based on fetched reviews
  const reviewCount = reviews.length;
  const averageRating = reviewCount > 0
    ? reviews.reduce((acc, r) => acc + r.rating, 0) / reviewCount
    : 0;

  // Group variants by name
  const variantGroups = product.variants?.reduce((acc, v) => {
    if (!v.active) return acc;
    if (!acc[v.name]) acc[v.name] = [];
    acc[v.name].push(v);
    return acc;
  }, {} as Record<string, typeof product.variants>) || {};

  // Calculate current price and stock
  const selectedVariantObjects = Object.entries(selectedVariants).map(([name, value]) =>
    product.variants?.find(v => v.name === name && v.value === value)
  ).filter(Boolean);

  const currentPrice = selectedVariantObjects.reduce((acc, v) => v?.priceOverride || acc, product.price);
  const currentStock = product.stock + selectedVariantObjects.reduce((acc, v) => acc + (v?.stockIncrement || 0), 0);

  const isLowStock = currentStock <= 3;
  const isOutOfStock = currentStock === 0;
  const discount = product.originalPrice
    ? Math.round(((product.originalPrice - currentPrice) / product.originalPrice) * 100)
    : 0;

  const handleAddToCart = () => {
    onAddToCart(quantity, selectedVariantObjects[0]?.id);
    setShowAddedToast(true);
    setTimeout(() => setShowAddedToast(false), 2000);
  };

  const handleShare = async () => {
    const shareData = {
      title: product.name,
      text: `${config.shareText} ${product.name} por R$${product.price.toFixed(2)}`,
      url: window.location.href
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Share cancelled');
      }
    } else {
      navigator.clipboard.writeText(`${shareData.text} - ${shareData.url}`);
      alert('Link copiado para a área de transferência!');
    }
  };

  const handleWhatsApp = () => {
    const variantInfo = Object.entries(selectedVariants).map(([n, v]) => `${n}: ${v}`).join(', ');
    const message = `Olá! Tenho interesse no produto: ${product.name}${variantInfo ? ` (${variantInfo})` : ''} - R$ ${currentPrice.toFixed(2).replace('.', ',')}`;
    const url = `https://wa.me/55${config.whatsappNumber}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % product.images.length);
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + product.images.length) % product.images.length);
  };

  // Schema.org JSON-LD
  const structuredData = {
    "@context": "https://schema.org/",
    "@type": "Product",
    "name": product.name,
    "image": product.images,
    "description": product.description,
    "sku": product.id,
    "offers": {
      "@type": "Offer",
      "url": window.location.href,
      "priceCurrency": "BRL",
      "price": product.price,
      "availability": isOutOfStock ? "https://schema.org/OutOfStock" : "https://schema.org/InStock",
      "itemCondition": "https://schema.org/NewCondition"
    },
    ...(reviewCount > 0 && {
      "aggregateRating": {
        "@type": "AggregateRating",
        "ratingValue": averageRating.toFixed(1),
        "reviewCount": reviewCount
      }
    })
  };

  return (
    <div className="min-h-screen pb-64">
      <Helmet>
        <title>{product.metaTitle || `${product.name} | Loja`}</title>
        <meta name="description" content={product.metaDescription || product.description.substring(0, 150)} />
        <meta property="og:title" content={product.metaTitle || product.name} />
        <meta property="og:description" content={product.metaDescription || product.description.substring(0, 150)} />
        <meta property="og:image" content={product.images[0]} />
        <meta property="og:type" content="product" />
        <script type="application/ld+json">
          {JSON.stringify(structuredData)}
        </script>
      </Helmet>

      {/* Image Gallery */}
      <div className="relative aspect-square bg-[#F8F9FA] group">
        <div className="flex justify-center items-center w-full h-full lg:h-[70vh] overflow-hidden">
          <img
            src={product.images[currentImageIndex]}
            alt={product.name}
            className="w-auto h-full max-w-full object-contain transition-opacity duration-500"
            loading="eager"
            fetchPriority="high"
            decoding="async"
          />
        </div>

        {/* Navigation Arrows */}
        {product.images.length > 1 && (
          <div className="absolute inset-0 flex items-center justify-between px-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none">
            <button
              onClick={prevImage}
              className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-premium hover:bg-white transition-all pointer-events-auto active:scale-95"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <button
              onClick={nextImage}
              className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-premium hover:bg-white transition-all pointer-events-auto active:scale-95"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
        )}

        {/* Image Indicators - Glass Pill */}
        {product.images.length > 1 && (
          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-1.5 px-4 py-2 bg-white/10 backdrop-blur-xl rounded-full border border-white/20 shadow-2xl">
            {product.images.map((_, index) => (
              <button
                key={index}
                onClick={() => setCurrentImageIndex(index)}
                className={`h-1 rounded-full transition-all duration-500 ${index === currentImageIndex ? 'bg-white w-8' : 'bg-white/30 hover:bg-white/50 w-2'
                  }`}
              />
            ))}
          </div>
        )}


        {/* Action Buttons */}
        <div className="absolute top-4 right-4 flex gap-2 z-10">
          <button
            onClick={onToggleFavorite}
            className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-premium hover:bg-white transition-all active:scale-95"
          >
            <Heart className={`w-5 h-5 transition-colors ${isFavorite ? 'fill-red-500 text-red-500' : 'text-zinc-600'}`} />
          </button>
          <button
            onClick={handleShare}
            className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-premium hover:bg-white transition-all active:scale-95"
          >
            <Share2 className="w-5 h-5 text-zinc-600" />
          </button>
        </div>
      </div>

      {/* Sticky Top Bar on Scroll */}
      <div className={`fixed top-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-b border-zinc-100/30 p-4 z-50 transition-all duration-500 transform ${scrolled ? 'translate-y-0 opacity-100 shadow-2xl shadow-black/5' : '-translate-y-full opacity-0'}`}>
        <div className="max-w-screen-md mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="relative">
              <img src={product.images[0]} className="w-10 h-10 rounded-xl object-cover shadow-sm ring-1 ring-black/5" alt={product.name} />
              {discount > 0 && <span className="absolute -top-1.5 -right-1.5 bg-red-500 text-white text-[7px] font-black px-1 rounded-full">{discount}%</span>}
            </div>
            <div className="flex flex-col">
              <h2 className="text-[10px] font-black uppercase tracking-widest text-zinc-400 line-clamp-1 max-w-[150px]">{product.name}</h2>
              <span className="text-sm font-black text-zinc-900 tracking-tighter">R$ {currentPrice.toFixed(2).replace('.', ',')}</span>
            </div>
          </div>
          <button
            onClick={handleAddToCart}
            className="bg-zinc-900 text-white px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all shadow-xl shadow-zinc-200 hover:bg-black"
          >
            Adicionar à Sacola
          </button>
        </div>
      </div>

      {/* Product Info */}
      <div className="px-6 py-8">
        {/* Breadcrumbs */}
        <nav className="flex items-center gap-2 mb-6 overflow-x-auto whitespace-nowrap scrollbar-hide text-[10px] font-black uppercase tracking-widest text-zinc-400">
          <button onClick={onBack} className="hover:text-zinc-900 transition-colors">Início</button>
          <ChevronRight className="w-3 h-3" />
          <button className="hover:text-zinc-900 transition-colors">{product.category}</button>
          <ChevronRight className="w-3 h-3" />
          <span className="text-zinc-900 line-clamp-1">{product.name}</span>
        </nav>

        {/* Badges */}
        <div className="flex flex-wrap gap-2 mb-4">
          {discount > 0 && (
            <span className="px-3 py-1 bg-red-500 text-white text-[10px] font-black tracking-wider rounded-full shadow-sm shadow-red-200 uppercase">
              {discount}% OFF
            </span>
          )}
          {product.isBestseller && (
            <span className="px-3 py-1 bg-amber-100 text-amber-800 text-[10px] font-black tracking-wider rounded-full flex items-center gap-1 uppercase border border-amber-200">
              <Flame className="w-3 h-3 text-orange-500" />
              Hit de Vendas
            </span>
          )}
          {product.freeShipping && (
            <span className="px-3 py-1 bg-zinc-100 text-zinc-800 text-[10px] font-black tracking-wider rounded-full flex items-center gap-1 border border-zinc-200 uppercase">
              <Truck className="w-3 h-3" />
              Frete Grátis
            </span>
          )}
        </div>

        {/* Name */}
        <h1 className="text-2xl font-black text-zinc-900 mb-2 leading-tight tracking-tight">
          {product.name}
        </h1>

        {/* Rating */}
        {reviewCount > 0 && (
          <div className="flex items-center gap-2 mb-3">
            <StarRating rating={averageRating} size={16} />
            <span className="text-sm text-gray-600">
              {averageRating.toFixed(1)} ({reviewCount} avaliações)
            </span>
          </div>
        )}

        {/* Price */}
        <div className="flex items-baseline gap-3 mb-6">
          <span className="text-3xl font-black text-zinc-900 tracking-tighter">
            R$ {currentPrice.toFixed(2).replace('.', ',')}
          </span>
          {product.originalPrice && (
            <span className="text-lg text-zinc-400 line-through font-medium">
              R$ {product.originalPrice.toFixed(2).replace('.', ',')}
            </span>
          )}
        </div>

        {/* Variant Selectors - Jewelry Style */}
        {Object.entries(variantGroups).length > 0 && (
          <div className="space-y-6 mb-10">
            {Object.entries(variantGroups).map(([name, values]) => (
              <div key={name}>
                <label className="block text-[10px] font-black text-zinc-400 uppercase tracking-[0.3em] mb-4 ml-1">
                  Selecione {name}
                </label>
                <div className="flex flex-wrap gap-3">
                  {values!.map((v) => (
                    <button
                      key={v.id}
                      onClick={() => setSelectedVariants(prev => ({ ...prev, [name]: v.value }))}
                      className={`min-w-[64px] px-6 py-4 text-xs font-black rounded-3xl border-2 transition-all duration-500 active:scale-90 ${selectedVariants[name] === v.value
                        ? 'border-zinc-900 bg-zinc-900 text-white shadow-2xl shadow-zinc-200 scale-105'
                        : 'border-zinc-100 bg-zinc-50/50 text-zinc-400 hover:border-zinc-200 hover:bg-white hover:text-zinc-900'
                        }`}
                    >
                      {v.value}
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Stock Info */}
        <div className={`flex items-center gap-1.5 sm:gap-2 mb-3 sm:mb-4 p-2.5 sm:p-3 rounded-lg ${isLowStock ? 'bg-red-50 text-red-700' : 'bg-green-50 text-green-700'
          }`}>
          {isLowStock ? (
            <>
              <Flame className="w-4 h-4 sm:w-5 sm:h-5" />
              <span className="text-xs sm:text-sm font-medium">
                Corre, estão acabando! Apenas {currentStock} unidades
              </span>
            </>
          ) : (
            <>
              <Check className="w-4 h-4 sm:w-5 sm:h-5" />
              <span className="text-xs sm:text-sm font-medium">
                Em estoque: {currentStock} {currentStock === 1 ? 'unidade' : 'unidades'}
              </span>
            </>
          )}
        </div>

        {/* Luxury Segmented Tabs - iOS Style */}
        <div className="bg-zinc-100/50 p-1.5 rounded-[2rem] flex items-center gap-1 mb-8 border border-zinc-100 max-w-sm mx-auto">
          {[
            { id: 'description', label: 'Detalhes' },
            { id: 'reviews', label: `Reviews (${reviewCount})` },
            { id: 'questions', label: 'Chat' }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 py-3 px-4 rounded-[1.6rem] text-[10px] font-black uppercase tracking-widest transition-all duration-500 ${activeTab === tab.id
                ? 'bg-white text-zinc-900 shadow-xl shadow-black/5 ring-1 ring-black/5 scale-[1.02]'
                : 'text-zinc-400 hover:text-zinc-600'
                }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Content */}
        {activeTab === 'description' && (
          <div className="mb-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <MarkdownRenderer content={product.description} />

            {/* Benefits */}
            <div className="space-y-3 mt-6">
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center">
                  <ShieldCheck className="w-4 h-4" />
                </div>
                <span>Troca garantida em até 24h após entrega</span>
              </div>
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center">
                  <Truck className="w-4 h-4" />
                </div>
                <span>Entrega em Monte Carmelo, MG</span>
              </div>
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center">
                  <ShoppingCart className="w-4 h-4" />
                </div>
                <span>Produto em estoque - Envio rápido</span>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'reviews' && (
          <div className="mb-6 space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
            {!showReviewForm ? (
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-semibold text-lg">Opiniões dos consumidores</h3>
                {user && (
                  <Button variant="outline" size="sm" onClick={() => setShowReviewForm(true)}>
                    Avaliar produto
                  </Button>
                )}
              </div>
            ) : (
              <div className="mb-6">
                <div className="flex justify-between items-center mb-2">
                  <h3 className="font-semibold">Escreva sua avaliação</h3>
                  <Button variant="ghost" size="sm" onClick={() => setShowReviewForm(false)}>Cancelar</Button>
                </div>
                <ReviewForm
                  productId={product.id}
                  onSuccess={() => setShowReviewForm(false)}
                />
              </div>
            )}

            {loadingReviews ? (
              <div className="text-center py-12">
                <div className="w-10 h-10 border-4 border-zinc-100 border-t-zinc-900 rounded-full animate-spin mx-auto mb-4" />
                <p className="text-zinc-400 text-sm font-black uppercase tracking-widest">Carregando Reviews</p>
              </div>
            ) : reviews.length === 0 ? (
              <div className="text-center py-16 bg-zinc-50 rounded-[2.5rem] border border-zinc-100">
                <Star className="w-12 h-12 text-zinc-200 mx-auto mb-4" />
                <p className="text-zinc-900 font-black text-lg tracking-tighter">Nenhuma avaliação ainda</p>
                <p className="text-zinc-400 text-xs mt-1">Seja o primeiro a compartilhar sua experiência!</p>
              </div>
            ) : (
              <>
                {/* Rating Distribution Chart */}
                <div className="bg-zinc-950 rounded-[3rem] p-10 mb-8 text-white shadow-3xl shadow-zinc-200/50 relative overflow-hidden group border border-white/5">
                  <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 rounded-full -translate-y-1/2 translate-x-1/2 blur-[80px] group-hover:bg-primary/30 transition-colors duration-1000" />
                  <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/5 rounded-full translate-y-1/2 -translate-x-1/2 blur-[40px]" />

                  <div className="relative z-10 flex flex-col sm:flex-row items-center gap-10">
                    <div className="text-center sm:text-left">
                      <p className="text-6xl font-black tracking-tighter mb-2 bg-gradient-to-br from-white to-zinc-500 bg-clip-text text-transparent">{averageRating.toFixed(1)}</p>
                      <StarRating rating={averageRating} size={20} />
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500 mt-6 antialiased">Baseado em {reviewCount} experiências</p>
                    </div>

                    <div className="flex-1 w-full space-y-3">
                      {[5, 4, 3, 2, 1].map((star) => {
                        const count = reviews.filter(r => r.rating === star).length;
                        const percentage = reviewCount > 0 ? (count / reviewCount) * 100 : 0;
                        return (
                          <div key={star} className="flex items-center gap-4 group/row">
                            <span className="text-[10px] font-black w-4 text-zinc-400 group-hover/row:text-white transition-colors">{star}</span>
                            <div className="flex-1 h-2 bg-white/5 rounded-full overflow-hidden p-[1px]">
                              <div
                                className="h-full bg-gradient-to-r from-zinc-400 to-white rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(255,255,255,0.3)]"
                                style={{ width: `${percentage}%` }}
                              />
                            </div>
                            <span className="text-[10px] font-black text-zinc-500 w-8 text-right group-hover/row:text-zinc-300 transition-colors">{count}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
                <div className="space-y-4">
                  {reviews.map((review) => (
                    <ReviewCard
                      key={review.id}
                      review={review}
                      onHelpful={markHelpful}
                    />
                  ))}
                </div>
              </>
            )}
          </div>
        )}

        {activeTab === 'questions' && (
          <div className="mb-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <ProductQA productId={product.id} />
          </div>
        )}

        {/* Recommendations - Magazine Style */}
        <div className="mt-20 pt-10 border-t border-zinc-100">
          <div className="flex flex-col items-center text-center mb-10">
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 mb-3">Curadoria Especial</span>
            <h3 className="text-3xl font-black tracking-tighter text-zinc-900 leading-none">Você também pode gostar</h3>
          </div>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 -mx-4 px-2">
            {loadingRecs ? (
              Array(4).fill(0).map((_, i) => <ProductCardSkeleton key={i} />)
            ) : (
              recommendations.map(p => (
                <ProductCard
                  key={p.id}
                  product={p}
                  isFavorite={checkFavorite(p.id)}
                  onToggleFavorite={(e) => {
                    e.stopPropagation();
                    toggleFavorite(p);
                  }}
                  onAddToCart={(e) => {
                    e.stopPropagation();
                    onAddToCart(1, undefined);
                  }}
                  onClick={() => {
                    trackRecommendationClick(p.id, 'product_view');
                    if (onProductClick) {
                      onProductClick(p.id);
                    } else {
                      window.location.href = `?product=${p.id}`;
                    }
                  }}
                />
              ))
            )}
          </div>
        </div>
      </div>

      {/* Bottom Actions */}
      <div className="fixed bottom-16 md:bottom-20 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-zinc-100 p-4 z-40 shadow-2xl rounded-t-[2.5rem]">
        <div className="max-w-screen-md mx-auto">
          {/* Quantity Selector */}
          {!isOutOfStock && (
            <div className="flex items-center justify-between mb-4 px-1">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400">Quantidade</span>
              <QuantitySelector
                quantity={quantity}
                maxQuantity={currentStock}
                onChange={setQuantity}
              />
            </div>
          )}

          {/* Buttons */}
          <div className="flex gap-3">
            <button
              onClick={handleWhatsApp}
              className="flex-shrink-0 w-14 h-14 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center hover:bg-emerald-500 hover:text-white transition-all duration-500 active:scale-90 border border-emerald-100"
            >
              <MessageCircle className="w-6 h-6" />
            </button>

            <button
              onClick={handleAddToCart}
              disabled={isOutOfStock}
              className="flex-1 h-14 bg-zinc-900 text-white text-xs font-black uppercase tracking-[0.2em] rounded-3xl hover:bg-black disabled:bg-zinc-100 disabled:text-zinc-300 disabled:cursor-not-allowed transition-all duration-500 active:scale-[0.98] shadow-2xl shadow-zinc-200 flex items-center justify-center gap-2"
            >
              {isOutOfStock ? (
                'Esgotado'
              ) : (
                <>
                  <ShoppingCart className="w-5 h-5" />
                  Adicionar ao Carrinho
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Added to Cart Toast */}
      {showAddedToast && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-black text-white px-6 py-3 rounded-xl shadow-lg z-50 animate-in fade-in zoom-in duration-200">
          <div className="flex items-center gap-2">
            <Check className="w-5 h-5 text-green-400" />
            <span className="font-medium">Adicionado ao carrinho!</span>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { ArrowLeft, Search as SearchIcon, SlidersHorizontal, Sparkles, PackageSearch } from 'lucide-react';
import { useSearch } from '@/hooks/useSearch';
import { useProducts } from '@/hooks/useProducts';
import { useFavorites } from '@/hooks/useFavorites';
import { ProductCard } from '@/components/ui/custom/ProductCard';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import type { View } from '@/types';

interface SearchViewProps {
    onNavigate: (view: View, productId?: string) => void;
    initialQuery?: string;
    onBack: () => void;
}

export function SearchView({ onNavigate, initialQuery = '', onBack }: SearchViewProps) {
    const { products: allProducts } = useProducts();
    const {
        query, setQuery,
        category, setCategory,
        minPrice, setMinPrice,
        maxPrice, setMaxPrice,
        sort, setSort,
        filteredProducts,
        totalResults
    } = useSearch(allProducts);

    const { isFavorite, toggleFavorite } = useFavorites();
    const [isFilterOpen, setIsFilterOpen] = useState(false);

    // Get trending products for empty state
    const trendingProducts = allProducts.slice(0, 4);

    // Extract unique categories
    const categoriesSet = ['Todas', ...Array.from(new Set(allProducts.map(p => p.category)))];

    const handleClearFilters = useCallback(() => {
        setCategory('Todas');
        setMinPrice('');
        setMaxPrice('');
        setSort('newest');
    }, [setCategory, setMinPrice, setMaxPrice, setSort]);

    // Initialize query from props if needed
    useEffect(() => {
        if (initialQuery !== undefined) {
            setQuery(initialQuery);
            if (!initialQuery) {
                handleClearFilters();
            }
        }
    }, [initialQuery, setQuery, handleClearFilters]);

    const activeFiltersCount =
        (category !== 'Todas' ? 1 : 0) +
        (minPrice !== '' ? 1 : 0) +
        (maxPrice !== '' ? 1 : 0);

    return (
        <div className="min-h-screen bg-white pb-32 selection:bg-black selection:text-white">
            {/* Premium Sticky Search Header */}
            <div className="bg-white/90 backdrop-blur-2xl sticky top-0 z-50 border-b border-zinc-100">
                <div className="px-4 py-4 max-w-7xl mx-auto space-y-4">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={onBack}
                            className="w-10 h-10 flex items-center justify-center bg-zinc-50 rounded-2xl border border-zinc-100 hover:bg-zinc-100 transition-all active:scale-90"
                        >
                            <ArrowLeft className="w-5 h-5 text-zinc-900" />
                        </button>
                        <div className="flex-1 relative group">
                            <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400 group-focus-within:text-zinc-900 transition-colors" />
                            <Input
                                value={query}
                                onChange={(e) => setQuery(e.target.value)}
                                placeholder="O que você deseja hoje?"
                                className="h-12 bg-zinc-50 border-zinc-100 rounded-2xl pl-11 pr-4 text-sm focus:ring-black/5 focus:border-zinc-200 transition-all placeholder:text-zinc-400"
                            />
                        </div>
                    </div>

                    {/* Quick Filters - Pill Style */}
                    <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                        <Sheet open={isFilterOpen} onOpenChange={setIsFilterOpen}>
                            <SheetTrigger asChild>
                                <button className="flex items-center gap-2 px-4 py-2 bg-zinc-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest whitespace-nowrap shadow-xl shadow-black/10 active:scale-95 transition-all">
                                    <SlidersHorizontal className="w-3 h-3" />
                                    Filtros {activeFiltersCount > 0 && `(${activeFiltersCount})`}
                                </button>
                            </SheetTrigger>
                            <SheetContent side="bottom" className="rounded-t-[3rem] p-8 max-h-[90vh] overflow-y-auto">
                                <SheetHeader className="mb-8">
                                    <div className="flex items-center justify-between">
                                        <SheetTitle className="text-2xl font-black tracking-tighter">Refinar Busca</SheetTitle>
                                        {activeFiltersCount > 0 && (
                                            <button
                                                onClick={handleClearFilters}
                                                className="text-[10px] font-black text-red-500 uppercase tracking-widest"
                                            >
                                                Limpar Tudo
                                            </button>
                                        )}
                                    </div>
                                </SheetHeader>

                                <div className="space-y-8 pb-10">
                                    <div>
                                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-4">Categorias</p>
                                        <div className="flex flex-wrap gap-2">
                                            {categoriesSet.map((catName) => (
                                                <button
                                                    key={catName}
                                                    onClick={() => setCategory(catName)}
                                                    className={`px-5 py-2.5 rounded-2xl text-[11px] font-bold transition-all border ${category === catName
                                                        ? 'bg-zinc-950 text-white border-zinc-950 scale-105 shadow-lg shadow-black/10'
                                                        : 'bg-zinc-50 text-zinc-600 border-zinc-100 hover:border-zinc-300'
                                                        }`}
                                                >
                                                    {catName}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    <div>
                                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-4">Ordenação</p>
                                        <div className="grid grid-cols-2 gap-3">
                                            {[
                                                { label: 'Menor Preço', value: 'price_asc' },
                                                { label: 'Maior Preço', value: 'price_desc' },
                                                { label: 'Mais Novos', value: 'newest' },
                                                { label: 'Alfabetica', value: 'name_asc' }
                                            ].map((option) => (
                                                <button
                                                    key={option.value}
                                                    onClick={() => setSort(option.value as any)}
                                                    className={`px-4 py-3 rounded-2xl border text-[11px] font-bold transition-all ${sort === option.value
                                                        ? 'bg-zinc-950 text-white border-zinc-950'
                                                        : 'bg-zinc-50 text-zinc-600 border-zinc-100 hover:border-zinc-300'
                                                        }`}
                                                >
                                                    {option.label}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    <Button
                                        onClick={() => setIsFilterOpen(false)}
                                        className="w-full h-14 rounded-2xl bg-zinc-950 text-white font-black uppercase tracking-widest text-xs hover:bg-zinc-900 transition-all shadow-2xl shadow-black/20"
                                    >
                                        Aplicar Filtros
                                    </Button>
                                </div>
                            </SheetContent>
                        </Sheet>

                        <div className="w-[1px] h-4 bg-zinc-100 mx-2" />

                        {categoriesSet.slice(0, 6).map(catName => (
                            <button
                                key={catName}
                                onClick={() => setCategory(catName)}
                                className={`px-4 py-2 rounded-full border text-[10px] font-bold uppercase tracking-widest whitespace-nowrap transition-all ${category === catName
                                    ? 'bg-zinc-950 text-white border-zinc-950'
                                    : 'bg-zinc-50 text-zinc-500 border-zinc-100 hover:border-zinc-900 hover:text-zinc-900'
                                    }`}
                            >
                                {catName}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Content Area */}
            <div className="px-4 py-8 max-w-7xl mx-auto">
                {filteredProducts.length > 0 ? (
                    <div className="space-y-8">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-2">
                                <Sparkles className="w-4 h-4 text-zinc-900" />
                                <h2 className="text-xl font-black tracking-tighter">Encontramos {totalResults} resultados</h2>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
                            {filteredProducts.map((product) => (
                                <ProductCard
                                    key={product.id}
                                    product={product}
                                    isFavorite={isFavorite(product.id)}
                                    onToggleFavorite={(e) => {
                                        e.stopPropagation();
                                        toggleFavorite(product);
                                    }}
                                    onClick={() => onNavigate('product', product.id)}
                                />
                            ))}
                        </div>
                    </div>
                ) : (
                    /* Smart Empty State */
                    <div className="py-20 animate-in fade-in slide-in-from-bottom-8 duration-700">
                        <div className="text-center max-w-sm mx-auto mb-20">
                            <div className="w-20 h-20 bg-zinc-50 rounded-[2.5rem] flex items-center justify-center border border-zinc-100 mx-auto mb-6">
                                <PackageSearch className="w-8 h-8 text-zinc-300" />
                            </div>
                            <h2 className="text-2xl font-black tracking-tighter text-zinc-900">Ué, nenhum resultado?</h2>
                            <p className="text-zinc-400 text-xs mt-2 leading-relaxed font-medium">
                                Não encontramos o que você buscou com esses filtros. <br />
                                <span className="text-zinc-900 font-black">Que tal dar uma olhada no que é tendência?</span>
                            </p>
                            <Button
                                variant="outline"
                                onClick={handleClearFilters}
                                className="mt-8 rounded-2xl border-zinc-200 text-zinc-900 font-black text-[10px] uppercase tracking-widest h-12 px-8"
                            >
                                Limpar Tudo
                            </Button>
                        </div>

                        {/* Trending Recommendations */}
                        <div className="pt-10 border-t border-zinc-100">
                            <div className="flex flex-col items-center text-center mb-10">
                                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 mb-2">Editor's Choice</span>
                                <h3 className="text-2xl font-black tracking-tighter text-zinc-900">Trending na IKCOUS</h3>
                            </div>
                            <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
                                {trendingProducts.map((product) => (
                                    <ProductCard
                                        key={product.id}
                                        product={product}
                                        isFavorite={isFavorite(product.id)}
                                        onToggleFavorite={(e) => {
                                            e.stopPropagation();
                                            toggleFavorite(product);
                                        }}
                                        onClick={() => onNavigate('product', product.id)}
                                    />
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}
